# ═══════════════════════════════════════════════════════════════
# FAST JSON (orjson > json)
# ═══════════════════════════════════════════════════════════════

def fast_json_dumps(obj: Any, indent: int = None) -> str:
    """Fast JSON serialization with orjson fallback."""
    if ORJSON_AVAILABLE:
        try:
            option = orjson.OPT_INDENT_2 if indent else 0
            return orjson.dumps(obj, option=option).decode()
        except Exception:
            pass
    return json.dumps(obj, indent=indent, ensure_ascii=False, default=str)

def fast_json_loads(data: str) -> Any:
    """Fast JSON deserialization."""
    if ORJSON_AVAILABLE:
        try:
            return orjson.loads(data.encode() if isinstance(data, str) else data)
        except Exception:
            pass
    return json.loads(data)

