@dataclass(slots=True)
class ZombieConfig:
    """
    🧟 CENTRALIZED CONFIGURATION — All settings in one place.
    
    Validates all config values on initialization.
    Used by ALL modules for consistent behavior.
    """
    
    # ═══ Target Settings ═══
    target_domain: str = ""
    target_url: str = ""
    scope_domains: List[str] = field(default_factory=list)
    out_of_scope: List[str] = field(default_factory=list)
    
    # ═══ Stealth Settings ═══
    fingerprint: str = "chrome"
    pool_size: int = 7
    region: str = "us"
    rotation_interval: int = 40
    base_delay: float = 0.3
    jitter_max: float = 0.5
    enable_camouflage: bool = False
    enable_tls_rotation: bool = True
    enable_mimicry: bool = False
    
    # ═══ Scan Settings ═══
    workers: int = 30
    timeout: int = 15
    max_retries: int = 3
    max_depth: int = 5
    max_pages: int = 1000
    max_findings: int = 10000
    
    # ═══ Rate Limiting ═══
    rate_limit: float = 2.0
    burst_size: int = 20
    enable_circuit_breaker: bool = True
    failure_threshold: int = 5
    recovery_timeout: float = 60.0
    
    # ═══ Module Toggles ═══
    enable_recon: bool = True
    enable_dorking: bool = True
    enable_crawler: bool = True
    enable_takeover: bool = True
    enable_waf_bypass: bool = True
    enable_cloud_metadata: bool = True
    enable_oauth_scan: bool = True
    enable_jwt_scan: bool = True
    enable_fuzzer: bool = True
    enable_deep_verify: bool = True
    enable_apocalypse_reaper: bool = False
    
    # ═══ Output Settings ═══
    output_dir: str = "./zombie_output"
    db_path: str = "./zombie_output/zombie.db"
    log_file: str = "./zombie_output/zombie.log"
    log_level: str = "INFO"
    log_max_bytes: int = 50_000_000
    log_backup_count: int = 10
    
    # ═══ Report Settings ═══
    report_formats: List[str] = field(default_factory=lambda: ["html", "json", "txt", "md"])
    report_dir: str = "./zombie_output/reports"
    
    # ═══ Advanced Settings ═══
    verify_ssl: bool = False
    proxy: Optional[str] = None
    proxy_auth: Optional[Tuple[str, str]] = None
    dns_timeout: int = 5
    wildcard_threshold: int = 10
    
    def __post_init__(self):
        """Validate and fix configuration values."""
        # Validate pool_size
        if not (5 <= self.pool_size <= 20):
            self.pool_size = max(5, min(self.pool_size, 20))
        
        # Validate workers
        if not (1 <= self.workers <= 200):
            self.workers = max(1, min(self.workers, 200))
        
        # Validate rate_limit
        if self.rate_limit < 0.1:
            self.rate_limit = 0.1
        
        # Ensure directories exist
        Path(self.output_dir).mkdir(parents=True, exist_ok=True)
        Path(self.report_dir).mkdir(parents=True, exist_ok=True)
    
    def to_dict(self) -> Dict:
        """Convert config to dictionary."""
        return asdict(self)
    
    @classmethod
    def from_dict(cls, data: Dict) -> 'ZombieConfig':
        """Create config from dictionary."""
        valid_keys = {f.name for f in fields(cls)}
        filtered = {k: v for k, v in data.items() if k in valid_keys}
        return cls(**filtered)
    
    @classmethod
    def from_args(cls, args: argparse.Namespace) -> 'ZombieConfig':
        """Create config from CLI arguments."""
        config_dict = {}
        
        # Map CLI args to config fields
        arg_mapping = {
            'target': 'target_domain',
            'url': 'target_url',
            'output': 'output_dir',
            'workers': 'workers',
            'stealth': 'fingerprint',
            'region': 'region',
        }
        
        for arg_name, config_name in arg_mapping.items():
            if hasattr(args, arg_name):
                value = getattr(args, arg_name)
                if value is not None:
                    config_dict[config_name] = value
        
        return cls(**config_dict)


