class SensitiveDataFilter(logging.Filter):
    """
    🛡️ AUTO-REDACT SENSITIVE DATA FROM LOGS — 50+ Patterns
    """
    
    PATTERNS: ClassVar[List[Tuple[str, str]]] = [
        # Authorization Headers
        (r'(?i)Authorization:\s*(?:Bearer|Basic|Digest|HOBA|Mutual|Negotiate|OAuth|SCRAM|vapid)\s+[^\s,;]+',
         'Authorization: [REDACTED]'),
        (r'(?i)X-API-Key:\s*[^\s,;]+', 'X-API-Key: [REDACTED]'),
        (r'(?i)X-Auth-Token:\s*[^\s,;]+', 'X-Auth-Token: [REDACTED]'),
        
        # JWT Tokens
        (r'eyJ[a-zA-Z0-9_-]+\.eyJ[a-zA-Z0-9_-]+\.[a-zA-Z0-9_-]+', '[JWT_REDACTED]'),
        (r'(?i)Bearer\s+[A-Za-z0-9\-._~+/]+=*', 'Bearer [REDACTED]'),
        (r'(?i)access_token\s*[:=]\s*[^\s,;]+', 'access_token=[REDACTED]'),
        (r'(?i)refresh_token\s*[:=]\s*[^\s,;]+', 'refresh_token=[REDACTED]'),
        
        # Database Connection Strings
        (r'(?i)(?:mongodb|postgres(?:ql)?|mysql|mssql|redis|sqlite|cassandra|couchbase|neo4j|oracle|mariadb|influxdb)(?:\+[^:]+)?://[^:]+:[^@]+@[^\s]+',
         '[DB_CREDENTIALS_REDACTED]'),
        
        # AWS Credentials
        (r'AKIA[0-9A-Z]{16}', '[AWS_ACCESS_KEY_REDACTED]'),
        (r'ASIA[0-9A-Z]{16}', '[AWS_SESSION_TOKEN_REDACTED]'),
        
        # GCP Credentials
        (r'AIza[0-9A-Za-z\-_]{35}', '[GCP_API_KEY_REDACTED]'),
        
        # SSH Private Keys
        (r'-----BEGIN (?:RSA|DSA|EC|OPENSSH|PGP) PRIVATE KEY-----[\s\S]*?-----END (?:RSA|DSA|EC|OPENSSH|PGP) PRIVATE KEY-----',
         '[PRIVATE_KEY_REDACTED]'),
        
        # Passwords & Secrets
        (r'(?i)(?:password|passwd|pwd|secret|private[_-]?key)\s*[:=]\s*[^\s,;"]+', '\\1=[REDACTED]'),
        (r'(?i)api[_-]?(?:key|secret|token)\s*[:=]\s*[A-Za-z0-9\-_]{20,}', '\\1=[REDACTED]'),
        
        # Credit Cards
        (r'\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14}|3[47][0-9]{13}|3(?:0[0-5]|[68][0-9])[0-9]{11}|6(?:011|5[0-9]{2})[0-9]{12}|(?:2131|1800|35\d{3})\d{11})\b',
         '[CREDIT_CARD_REDACTED]'),
        
        # Webhook URLs
        (r'https://hooks\.slack\.com/services/[A-Z0-9]+/[A-Z0-9]+/[A-Za-z0-9]+', '[SLACK_WEBHOOK_REDACTED]'),
        (r'https://discord\.com/api/webhooks/\d+/[A-Za-z0-9\-_]+', '[DISCORD_WEBHOOK_REDACTED]'),
        
        # Stripe Keys
        (r'(?:sk|pk)_(?:live|test)_[a-zA-Z0-9]{24,}', '[STRIPE_KEY_REDACTED]'),
        
        # GitHub Tokens
        (r'(?:ghp|gho|ghu|ghs|ghr)_[A-Za-z0-9_]{36,}', '[GITHUB_TOKEN_REDACTED]'),
        (r'github_pat_[A-Za-z0-9_]{22,}', '[GITHUB_PAT_REDACTED]'),
        
        # GitLab Tokens
        (r'glpat-[A-Za-z0-9\-_]{20,}', '[GITLAB_TOKEN_REDACTED]'),
        
        # Tokens in URLs
        (r'(?i)access_token=[^&\s]+', 'access_token=[REDACTED]'),
        (r'(?i)api_key=[^&\s]+', 'api_key=[REDACTED]'),
        
        # Social Security Numbers
        (r'\b\d{3}-\d{2}-\d{4}\b', '[SSN_REDACTED]'),
    ]
    
    def filter(self, record: logging.LogRecord) -> bool:
        """Filter and redact sensitive data from log records."""
        if isinstance(record.msg, str):
            for pattern, replacement in self.PATTERNS:
                try:
                    record.msg = re.sub(pattern, replacement, record.msg,
                                       flags=re.IGNORECASE | re.DOTALL)
                except re.error:
                    continue
        
        if record.args and isinstance(record.args, dict):
            filtered_args = {}
            for key, value in record.args.items():
                if isinstance(value, str):
                    for pattern, replacement in self.PATTERNS:
                        try:
                            value = re.sub(pattern, replacement, value,
                                          flags=re.IGNORECASE | re.DOTALL)
                        except re.error:
                            continue
                filtered_args[key] = value
            record.args = filtered_args
        
        return True


def setup_logging(config: ZombieConfig = None) -> logging.Logger:
    """
    Setup advanced logging with rotation and sensitive data filtering.
    
    Args:
        config: ZombieConfig instance
        
    Returns:
        Configured logger instance
    """
    if config is None:
        config = ZombieConfig()
    
    # Ensure log directory exists
    log_path = Path(config.log_file)
    log_path.parent.mkdir(parents=True, exist_ok=True)
    
    # Create logger
    logger = logging.getLogger('zombie')
    logger.setLevel(getattr(logging, config.log_level.upper(), logging.INFO))
    
    # Clear existing handlers
    logger.handlers.clear()
    
    # Formatter
    formatter = logging.Formatter(
        '%(asctime)s [%(levelname)s] %(name)s - %(message)s',
        datefmt='%Y-%m-%d %H:%M:%S'
    )
    
    # File handler with rotation
    file_handler = RotatingFileHandler(
        config.log_file,
        maxBytes=config.log_max_bytes,
        backupCount=config.log_backup_count,
        encoding='utf-8'
    )
    file_handler.setFormatter(formatter)
    file_handler.addFilter(SensitiveDataFilter())
    
    # Console handler
    console_handler = logging.StreamHandler(sys.stdout)
    console_handler.setFormatter(formatter)
    console_handler.addFilter(SensitiveDataFilter())
    
    # Add handlers
    logger.addHandler(file_handler)
    logger.addHandler(console_handler)
    
    # Suppress noisy third-party loggers
    for noisy_logger in ['aiohttp', 'chardet', 'urllib3']:
        logging.getLogger(noisy_logger).setLevel(logging.WARNING)
    
    return logger


