class C:
    """🎨 ANSI Color Constants — 256-color support"""
    
    # Basic Colors
    RED       = '\033[91m'
    GREEN     = '\033[92m'
    YELLOW    = '\033[93m'
    BLUE      = '\033[94m'
    MAGENTA   = '\033[95m'
    CYAN      = '\033[96m'
    WHITE     = '\033[97m'
    BLACK     = '\033[30m'
    
    # Bright Colors
    BRIGHT_RED     = '\033[91m\033[1m'
    BRIGHT_GREEN   = '\033[92m\033[1m'
    BRIGHT_YELLOW  = '\033[93m\033[1m'
    BRIGHT_BLUE    = '\033[94m\033[1m'
    BRIGHT_MAGENTA = '\033[95m\033[1m'
    BRIGHT_CYAN    = '\033[96m\033[1m'
    
    # Background Colors
    BG_RED    = '\033[41m'
    BG_GREEN  = '\033[42m'
    BG_YELLOW = '\033[43m'
    BG_BLUE   = '\033[44m'
    BG_CYAN   = '\033[46m'
    BG_WHITE  = '\033[47m'
    
    # Text Styles
    BOLD      = '\033[1m'
    DIM       = '\033[2m'
    ITALIC    = '\033[3m'
    UNDERLINE = '\033[4m'
    BLINK     = '\033[5m'
    REVERSE   = '\033[7m'
    STRIKE    = '\033[9m'
    
    # Reset
    RST = '\033[0m'
    
    # Severity Colors
    CRITICAL = '\033[91m\033[1m\033[5m'  # Red + Bold + Blink
    HIGH     = '\033[93m\033[1m'         # Bright Yellow
    MEDIUM   = '\033[94m\033[1m'         # Bright Blue
    LOW      = '\033[92m'                # Green
    INFO     = '\033[97m'                # White
    
    # Status Colors
    SUCCESS = '\033[92m\033[1m'  # Bright Green
    FAIL    = '\033[91m\033[1m'  # Bright Red
    WARN    = '\033[93m'         # Yellow
    HIGHLIGHT = '\033[95m\033[1m'  # Bright Magenta
    
    # Aliases
    R, G, Y, B, M, CY, W = RED, GREEN, YELLOW, BLUE, MAGENTA, CYAN, WHITE
    
    @classmethod
    def gradient(cls, text: str, colors: List[str] = None) -> str:
        """Create gradient-colored text."""
        if colors is None:
            colors = [cls.RED, cls.YELLOW, cls.GREEN, cls.CYAN, cls.BLUE, cls.MAGENTA]
        
        result = []
        for i, char in enumerate(text):
            color = colors[i % len(colors)]
            result.append(f"{color}{char}")
        result.append(cls.RST)
        return ''.join(result)
    
    @classmethod
    def rainbow(cls, text: str) -> str:
        """Create rainbow-colored text."""
        return cls.gradient(text, [cls.RED, cls.YELLOW, cls.GREEN, cls.CYAN, cls.BLUE, cls.MAGENTA])


