# PRINT HELPERS — Rich + ANSI Dual Support
# ═══════════════════════════════════════════════════════════════

from rich.console import Console as RichConsole

class Console:
    def __init__(self, use_rich: bool = True):
        self.use_rich = use_rich and RICH_AVAILABLE
        if self.use_rich:
            self._rich_console = RichConsole()  # <-- PAKE RichConsole, bukan Console
    
    def print_success(self, msg: str) -> None:
        """Print success message."""
        print(f"{C.G}{I.CHECK} {msg}{C.RST}")
    
    def print_error(self, msg: str) -> None:
        """Print error message."""
        print(f"{C.R}{I.CROSS} {msg}{C.RST}")
    
    def print_warning(self, msg: str) -> None:
        """Print warning message."""
        print(f"{C.Y}{I.WARN} {msg}{C.RST}")
    
    def print_info(self, msg: str) -> None:
        """Print info message."""
        print(f"{C.CY}{I.INFO} {msg}{C.RST}")
    
    def print_process(self, msg: str) -> None:
        """Print process message."""
        print(f"{C.CY}  {msg}{C.RST}")
    
    def print_critical(self, msg: str) -> None:
        """Print critical message."""
        print(f"{C.CRITICAL}{I.SKULL} {msg}{C.RST}")
    
    def print_finding(self, severity: str, url: str, details: str = "") -> None:
        """Print vulnerability finding."""
        sev_color = {
            "CRITICAL": C.CRITICAL, "HIGH": C.HIGH,
            "MEDIUM": C.MEDIUM, "LOW": C.LOW, "INFO": C.INFO,
        }.get(severity.upper(), C.WHITE)
        
        icon = I.severity_icon(severity)
        
        print(f"  {sev_color}{icon} [{severity:8s}] {url[:70]}{C.RST}")
        if details:
            print(f"       {C.DIM}{details[:80]}{C.RST}")
    
    def print_section(self, title: str, color: str = C.CYAN) -> None:
        """Print section header."""
        print(f"\n{color}{'═'*70}{C.RST}")
        print(f"{color}{C.BOLD}  {title}{C.RST}")
        print(f"{color}{'═'*70}{C.RST}")
    
    def print_stat(self, label: str, value: Any, color: str = C.YELLOW) -> None:
        """Print statistic line."""
        print(f"  {C.WHITE}{label}: {color}{value}{C.RST}")
    
    def print_banner_line(self, text: str, color: str = C.RED) -> None:
        """Print banner line."""
        print(f"{color}{text}{C.RST}")


