@dataclass(frozen=True, slots=True)
class VulnerabilitySignature:
    """Immutable vulnerability identifier."""
    target_url: str
    param: str
    vuln_type: str
    payload_hash: str
    
    def __str__(self):
        return f"{self.vuln_type}:{self.param}@{self.target_url[:50]}"
    
    @property
    def unique_key(self) -> str:
        return f"{self.target_url}|{self.param}|{self.vuln_type}"


@dataclass(slots=True)
class ScanResult:
    """Comprehensive scan result with all evidence."""
    signature: VulnerabilitySignature
    severity: Severity = Severity.INFO
    confidence: Confidence = Confidence.LOW
    title: str = ""
    description: str = ""
    evidence: str = ""
    request_raw: str = ""
    response_raw: str = ""
    reproduction: str = ""
    remediation: str = ""
    waf_detected: Optional[str] = None
