class ScanSession:
    """Scan session tracking."""
    session_id: str = field(default_factory=lambda: uuid.uuid4().hex[:12])
    targets: List[str] = field(default_factory=list)
    scope_domains: List[str] = field(default_factory=list)
    out_of_scope: List[str] = field(default_factory=list)
    findings: List[Dict] = field(default_factory=list)
    visited_urls: Set[str] = field(default_factory=set)
    waf_detected: Optional[str] = None
    start_time: Optional[datetime] = None
    end_time: Optional[datetime] = None
    scan_type: str = "full"
    config: Optional[ZombieConfig] = None
    
    @property
    def duration(self) -> float:
        if self.start_time and self.end_time:
            return (self.end_time - self.start_time).total_seconds()
        return 0.0
    
    @property
    def valid_findings(self) -> List[Dict]:
        return [f for f in self.findings if f.get("confidence", 0) >= 60]
    
    @property
    def critical_findings(self) -> List[Dict]:
        return [f for f in self.findings if f.get("severity") == "CRITICAL"]
    
    def add_finding(self, finding: Dict) -> None:
        """Add a finding with deduplication."""
        key = f"{finding.get('url', '')}|{finding.get('param', '')}|{finding.get('vuln_type', '')}"
        if not any(f.get('unique_key') == key for f in self.findings):
            finding['unique_key'] = key
            self.findings.append(finding)


