def detect_waf(response: Dict) -> Optional[str]:
    """
    🛡️ Enhanced WAF Detection from HTTP response.
    
    Args:
        response: HTTP response dictionary with 'headers', 'text', 'status'
        
    Returns:
        WAF name if detected, None otherwise
    """
    if not response:
        return None
    
    text = (response.get('text', '') or '').lower()
    headers = {
        k.lower(): str(v).lower()
        for k, v in response.get('headers', {}).items()
    }
    status = response.get('status', 0)
    
    # Check all WAF signatures
    best_match = None
    best_score = 0.0
    
    for waf_name, sigs in WAF_SIGNATURES.items():
        score = 0.0
        
        # Check headers
        header_sigs = sigs.get('headers', [])
        if header_sigs:
            header_matches = 0
            for sig in header_sigs:
                sig_lower = sig.lower()
                if any(sig_lower in v for v in headers.values()):
                    header_matches += 1
                elif any(sig_lower in k for k in headers.keys()):
                    header_matches += 1
            score += (header_matches / len(header_sigs)) * 0.6
        
        # Check cookies
        cookie_sigs = sigs.get('cookies', [])
        if cookie_sigs:
            cookie_matches = sum(
                1 for sig in cookie_sigs
                if sig.lower() in text or sig.lower() in str(headers.get('set-cookie', ''))
            )
            if cookie_sigs:
                score += (cookie_matches / len(cookie_sigs)) * 0.3
        
        # Check body
        body_sigs = sigs.get('body', [])
        if body_sigs:
            body_matches = sum(1 for sig in body_sigs if sig.lower() in text)
            if body_sigs:
                score += (body_matches / len(body_sigs)) * 0.1
        
        # Check status code match
        if status in sigs.get('status', []):
            score += 0.05
        
        # Apply confidence multiplier
        score *= sigs.get('confidence', 0.7)
        
        if score > best_score:
            best_score = score
            best_match = waf_name
    
    if best_match and best_score >= 0.3:
        return best_match
    
    return None


