    # ═══ Class Methods ═══
    
    @classmethod
    def is_high_value(cls, param_name: str) -> bool:
        """
        Check if parameter is high-value for vulnerability testing.
        
        Args:
            param_name: Parameter name to check
            
        Returns:
            True if parameter is valuable for testing
        """
        p = param_name.lower().strip()
        
        # Immune params first
        if p in cls.IMMUNE_PARAMS:
            return False
        
        # Direct match
        if p in cls.HIGH_VALUE_PARAMS:
            return True
        
        # Pattern match
        for pattern in cls.HIGH_VALUE_PATTERNS:
            if pattern.match(p):
                return True
        
        return False
    
    @classmethod
    def extract_params(cls, url: str) -> List[str]:
        """
        Extract high-value parameters from URL.
        
        Args:
            url: URL to extract from
            
        Returns:
            List of high-value parameter names
        """
        parsed = urlparse(url)
        params = list(parse_qs(parsed.query).keys())
        return [p for p in params if cls.is_high_value(p)]
    
    @classmethod
    def extract_all_params(cls, url: str) -> List[str]:
        """
        Extract all parameters from URL (including non-high-value).
        
        Args:
            url: URL to extract from
            
        Returns:
            List of all parameter names
        """
        parsed = urlparse(url)
        return list(parse_qs(parsed.query).keys())
    
    @classmethod
    def get_all_params(cls) -> List[str]:
        """
        Return all high-value parameters as sorted list.
        
        Returns:
            Sorted list of all parameter names
        """
        return sorted(list(cls.HIGH_VALUE_PARAMS))
    
    @classmethod
    def get_param_count(cls) -> int:
        """Return total count of high-value parameters."""
        return len(cls.HIGH_VALUE_PARAMS)
    
    @classmethod
    def get_immune_count(cls) -> int:
        """Return total count of immune parameters."""
        return len(cls.IMMUNE_PARAMS)


