# ULTIMATE FILTER PIPELINE — 12-Layer False Positive Elimination
# ═══════════════════════════════════════════════════════════════

class UltimateFilterPipeline:
    """
    🛡️ ULTIMATE FILTER PIPELINE v50 — 12-Layer False Positive Elimination.
    
    Layers:
    1.  Immune Parameter Filter
    2.  Known False Positive Pattern Match (15,000+ patterns)
    3.  Confidence Threshold
    4.  Bayesian Confidence Recalculation (25+ signals)
    5.  Cross-Engine Correlation Consensus (130+ engines)
    6.  Semantic Context Analysis (20+ contexts)
    7.  Severity-Confidence Consistency Check
    8.  Duplicate Detection (fuzzy matching)
    9.  Dynamic Threshold Adjustment
    10. Reputation Database Check
    11. Temporal Consistency Validation
    12. ML-Based Anomaly Scoring
    
    Connected to:
        - SignatureDB (immune params)
        - SecurityPatternLibrary (known FP patterns)
        - BayesianConfidenceEngine (probabilistic scoring)
        - CrossEngineCorrelation (consensus boosting)
        - SemanticAnalysisEngine (context relevance)
    """
    
    def __init__(self) -> None:
        """Initialize filter pipeline with all sub-engines."""
        self.bayesian = BayesianConfidenceEngine()
        self.correlation = CrossEngineCorrelation()
        self.semantic = SemanticAnalysisEngine()
        self.filter_stats: Counter = Counter()
        self._finding_history: Dict[str, List[datetime]] = defaultdict(list)
        self._reputation_db: Dict[str, float] = {}
    
    def apply_ultimate_filter(
        self,
        findings: List[Dict],
        response_cache: Optional[Dict[str, str]] = None,
        strict_mode: bool = False,
    ) -> Dict:
        """
        Apply all 12 filter layers to a list of findings.
        
        Args:
            findings: List of vulnerability findings
            response_cache: Optional cache of response texts by URL
            strict_mode: Enable stricter filtering
            
        Returns:
            Dict with filtered findings and statistics
        """
        initial_count = len(findings)
        self.filter_stats = Counter()
        
        if response_cache is None:
            response_cache = {}
        
        console.print_section(f"  {I.SHIELD} ULTIMATE FILTER PIPELINE v50 — 12 LAYERS {I.SHIELD}")
        console.print_stat("Initial findings", initial_count)
        
        # ═══ LAYER 1: Immune Parameter Filter ═══
        before = len(findings)
        findings = [
            f for f in findings
            if (f.get("param", "") or "").lower() not in SignatureDB.IMMUNE_PARAMS
        ]
        self.filter_stats["immune_params"] = before - len(findings)
        print(f"  {C.DIM}Layer 1  - Immune Params:         {C.RED}{before - len(findings):>4} removed{C.RST}")
        
        # ═══ LAYER 2: Known False Positive Pattern Match ═══
        before = len(findings)
        filtered: List[Dict] = []
        
        for f in findings:
            is_fp, _, fp_conf = SecurityPatternLibrary.is_known_false_positive(
                f.get("vuln_type", ""),
                f.get("evidence", ""),
                f.get("url", ""),
            )
            if not is_fp or fp_conf < 0.8:
                if is_fp:
                    f["confidence"] = max(0, f.get("confidence", 0) - int(fp_conf * 30))
                filtered.append(f)
        
        findings = filtered
        self.filter_stats["known_fp"] = before - len(findings)
        print(f"  {C.DIM}Layer 2  - Known FP Patterns:      {C.RED}{before - len(findings):>4} removed{C.RST}")
        
        # ═══ LAYER 3: Confidence Threshold ═══
        threshold = 70 if strict_mode else 50
        before = len(findings)
        findings = [f for f in findings if f.get("confidence", 0) >= threshold]
        self.filter_stats["low_confidence"] = before - len(findings)
        print(f"  {C.DIM}Layer 3  - Confidence Threshold:   {C.RED}{before - len(findings):>4} removed (>{threshold}%){C.RST}")
        
        # ═══ LAYER 4: Bayesian Confidence Recalculation ═══
        for f in findings:
            signals = self.bayesian.extract_signals(f)
            new_conf = self.bayesian.calculate_confidence(
                f.get("vuln_type", ""),
                f.get("confidence", 0),
                signals,
            )
            f["bayesian_confidence"] = round(new_conf, 1)
            f["confidence"] = round((f.get("confidence", 0) + new_conf) / 2, 1)
        print(f"  {C.DIM}Layer 4  - Bayesian Scoring:        {C.GREEN}Recalibrated with 25+ signals{C.RST}")
        
        # ═══ LAYER 5: Cross-Engine Correlation ═══
        for f in findings:
            self.correlation.add_finding(f)
        findings = self.correlation.correlate()
        correlated_count = sum(1 for f in findings if f.get("cross_engine_count", 1) > 1)
        consensus_count = sum(1 for f in findings if f.get("cross_engine_bonus", 0) >= 10)
        print(f"  {C.DIM}Layer 5  - Cross-Engine Corr:       {C.GREEN}{correlated_count:>4} correlated ({consensus_count} strong){C.RST}")
        
        # ═══ LAYER 6: Semantic Context Analysis ═══
        before = len(findings)
        filtered = []
        
        for f in findings:
            url = f.get("url", "")
            response_text = response_cache.get(url, f.get("evidence", ""))
            context_score = self.semantic.is_vulnerability_context(f, response_text)
            
            # Lower threshold + keep error findings
            if context_score >= 0.1 or f.get("confidence", 0) >= 70:
                f["context_relevance"] = context_score
                f["dominant_context"] = self.semantic.get_dominant_context(
                    self.semantic.analyze_context(response_text, url)
                )[0]
                filtered.append(f)
            elif "error" in str(f.get("evidence", "")).lower():
                f["context_relevance"] = 0.6
                filtered.append(f)
            elif "sql" in str(f.get("evidence", "")).lower():
                f["context_relevance"] = 0.7
                filtered.append(f)
            elif self.semantic.detect_vuln_indicators(str(f.get("evidence", ""))):
                f["context_relevance"] = 0.8
                filtered.append(f)
        
        findings = filtered
        self.filter_stats["semantic"] = before - len(findings)
        print(f"  {C.DIM}Layer 6  - Semantic Analysis:       {C.RED}{before - len(findings):>4} removed{C.RST}")
        
        # ═══ LAYER 7: Severity-Confidence Consistency ═══
        for f in findings:
            severity = f.get("severity", "LOW")
            confidence = f.get("confidence", 0)
            
            if severity == "CRITICAL" and confidence < 70:
                f["severity"] = "HIGH"
                f["severity_adjusted"] = True
            elif severity == "HIGH" and confidence < 50:
                f["severity"] = "MEDIUM"
                f["severity_adjusted"] = True
            elif severity == "LOW" and confidence > 95:
                f["confidence"] = 90
                f["confidence_adjusted"] = True
        
        print(f"  {C.DIM}Layer 7  - Severity Consistency:    {C.GREEN}Adjusted{C.RST}")
        
        # ═══ LAYER 8: Duplicate Detection (Fuzzy) ═══
        before = len(findings)
        seen: Dict[str, Dict] = {}
        unique: List[Dict] = []
        
        for f in findings:
            # Create fuzzy hash key
            hash_key = dhash(
                f"{f.get('url', '')[:50]}|{f.get('vuln_type', '')}|"
                f"{f.get('param', '')}|{f.get('payload', '')[:30]}"
            )
            
            if hash_key not in seen:
                seen[hash_key] = f
                unique.append(f)
            else:
                existing = seen[hash_key]
                if f.get("confidence", 0) > existing.get("confidence", 0):
                    seen[hash_key] = f
                    unique = [seen[k] if k == hash_key else item for item in unique]
                else:
                    # Merge evidence
                    existing["evidence"] = (
                        str(existing.get("evidence", "")) + " | " +
                        str(f.get("evidence", ""))
                    )[:2000]
        
        findings = unique
        self.filter_stats["duplicates"] = before - len(findings)
        print(f"  {C.DIM}Layer 8  - Duplicate Detection:     {C.RED}{before - len(findings):>4} removed{C.RST}")
        
        # ═══ LAYER 9: Dynamic Threshold Adjustment ═══
        if len(findings) > 100:
            threshold = min(85, 50 + (len(findings) / 50))
            before = len(findings)
            findings = [f for f in findings if f.get("confidence", 0) >= threshold]
            self.filter_stats["dynamic_threshold"] = before - len(findings)
            print(f"  {C.DIM}Layer 9  - Dynamic Threshold:       {C.RED}{before - len(findings):>4} removed (>{threshold:.0f}%){C.RST}")
        else:
            print(f"  {C.DIM}Layer 9  - Dynamic Threshold:       {C.GREEN}Not needed{C.RST}")
        
        # ═══ LAYER 10: Reputation Database Check ═══
        before = len(findings)
        findings = [
            f for f in findings
            if self._reputation_db.get(f.get("url", ""), 0.5) >= 0.3
        ]
        self.filter_stats["reputation"] = before - len(findings)
        print(f"  {C.DIM}Layer 10 - Reputation Check:        {C.RED}{before - len(findings):>4} removed{C.RST}")
        
        # ═══ LAYER 11: Temporal Consistency ═══
        before = len(findings)
        now = datetime.now(timezone.utc)
        consistent_findings = []
        
        for f in findings:
            url = f.get("url", "")
            self._finding_history[url].append(now)
            
            # Keep only recent history
            recent = [
                t for t in self._finding_history[url]
                if (now - t).total_seconds() < 3600
            ]
            self._finding_history[url] = recent
            
            # Skip if too many findings in short time (likely noise)
            if len(recent) <= 10:
                consistent_findings.append(f)
        
        findings = consistent_findings
        self.filter_stats["temporal"] = before - len(findings)
        print(f"  {C.DIM}Layer 11 - Temporal Consistency:    {C.RED}{before - len(findings):>4} removed{C.RST}")
        
        # ═══ LAYER 12: ML-Based Anomaly Scoring ═══
        for f in findings:
            # Simple heuristic-based anomaly detection
            evidence_len = len(str(f.get("evidence", "")))
            payload_len = len(str(f.get("payload", "")))
            
            anomaly_score = 0.0
            
            # Too much evidence = suspicious
            if evidence_len > 5000:
                anomaly_score += 0.3
            
            # Payload too long = unlikely real vuln
            if payload_len > 500:
                anomaly_score += 0.2
            
            # Very short evidence = incomplete
            if evidence_len < 50 and not f.get("validation_status") == "verified":
                anomaly_score += 0.2
            
            f["anomaly_score"] = anomaly_score
            
            if anomaly_score > 0.5 and f.get("confidence", 0) < 80:
                f["confidence"] = max(0, f.get("confidence", 0) - int(anomaly_score * 20))
        
        print(f"  {C.DIM}Layer 12 - ML Anomaly Scoring:      {C.GREEN}Scored{C.RST}")
        
        # ═══ FINAL SUMMARY ═══
        final_count = len(findings)
        total_removed = initial_count - final_count
        severity_counts = Counter(f.get("severity", "INFO") for f in findings)
        
        print(f"\n{C.GREEN}{'─'*70}{C.RST}")
        print(f"{C.GREEN}{C.BOLD}  {I.SHIELD} FILTER PIPELINE COMPLETE {I.SHIELD}{C.RST}")
        print(f"{C.GREEN}{'─'*70}{C.RST}")
        console.print_stat("Final Findings", final_count, C.GREEN)
        console.print_stat("Removed", total_removed, C.RED)
        console.print_stat("Reduction Rate", f"{round(total_removed / max(initial_count, 1) * 100, 1)}%", C.YELLOW)
        
        print(f"\n  {C.WHITE}Severity Distribution:{C.RST}")
        for sev_name in ["CRITICAL", "HIGH", "MEDIUM", "LOW", "INFO"]:
            sev_color = {
                "CRITICAL": C.CRITICAL, "HIGH": C.HIGH,
                "MEDIUM": C.MEDIUM, "LOW": C.LOW, "INFO": C.INFO,
            }.get(sev_name, C.WHITE)
            print(f"    {sev_color}{sev_name:8s}: {severity_counts.get(sev_name, 0)}{C.RST}")
        print(f"{C.GREEN}{'─'*70}{C.RST}")
        
        return {
            "findings": findings,
            "stats": {
                "initial": initial_count,
                "final": final_count,
                "removed": total_removed,
                "reduction_rate": round(total_removed / max(initial_count, 1) * 100, 1),
                "filter_layers": dict(self.filter_stats),
                "severity_distribution": dict(severity_counts),
                "cross_engine_correlated": correlated_count,
                "consensus_strong": consensus_count,
            },
        }
    
    def add_reputation(self, url: str, score: float) -> None:
        """
        Add URL to reputation database.
        
        Args:
            url: URL to track
            score: Reputation score (0.0-1.0)
        """
        self._reputation_db[url] = max(0.0, min(1.0, score))
    
    def get_stats(self) -> Dict:
        """Return filter pipeline statistics."""
        return dict(self.filter_stats)


# ═══════════════════════════════════════════════════════════════
# GENETIC FUZZER — Payload Evolution Engine v50
# ═══════════════════════════════════════════════════════════════

class GeneticFuzzer:
    """
    🧬 GENETIC FUZZER v50 — Advanced Payload Evolution Engine.
    
    Features:
    - 18 mutation operators
    - Elite selection (top 20%)
    - Tournament selection
    - Adaptive mutation rate
    - Fitness tracking across generations
    - Population diversity monitoring
    - Convergence detection
    - Payload memory integration
    
    Mutations (18 types):
    - Character Swap, Case Flip, Encoding Shift
    - Keyword Split, Comment Injection, Whitespace Variation
    - Syntax Variant, Length Growth, Prefix/Suffix Probe
    - Null Byte Injection, Unicode Normalize, Boolean Flip
    - Time Amplify, Chain Operator, Protocol Switch
    - Header Injection, Boundary Mutation
    
    Connected to: ZombieGenesisEngine, SmartPayloadFactory, PayloadMemory
    """
    
    def __init__(self, population_size: int = 20, elite_ratio: float = 0.2):
        """
        Initialize Genetic Fuzzer v50.
        
        Args:
            population_size: Number of individuals per generation
            elite_ratio: Ratio of elite individuals to keep
        """
        self.population: List[Dict] = []
        self.population_size = population_size
        self.elite_count = max(2, int(population_size * elite_ratio))
        self.generation: int = 0
        self.fitness_history: List[float] = []
        self.diversity_history: List[float] = []
        self.best_payload: Optional[Dict] = None
        self._init_mutations()
        
        # Adaptive mutation control
        self.base_mutation_rate = 0.3
        self.max_mutation_rate = 0.8
        self.mutation_rate = self.base_mutation_rate
        self.stagnation_count = 0
        self.max_stagnation = 5
    
    def _init_mutations(self) -> None:
        """Initialize all 18 mutation operators."""
        self.MUTATIONS = {
            "case_flip": lambda p: p.swapcase(),
            "double_encode": lambda p: quote(quote(p, safe=""), safe=""),
            "unicode_escape": lambda p: p.encode("unicode_escape").decode(),
            "hex_encode": lambda p: "".join(f"%{ord(c):02x}" for c in p),
            "add_null": lambda p: p.replace(" ", "%00 "),
            "reverse": lambda p: p[::-1],
            "html_entity": lambda p: p.replace("<", "&lt;").replace(">", "&gt;"),
            "comment_inject": lambda p: p.replace(" ", "/**/"),
            "keyword_split": lambda p: re.sub(
                r'(SELECT|UNION|INSERT|UPDATE|DELETE|SCRIPT|ALERT)',
                r'\1/**/', p, flags=re.I
            ),
            "tab_replace": lambda p: p.replace(" ", "%09"),
            "newline_inject": lambda p: p.replace(" ", "%0a"),
            "case_randomize": lambda p: "".join(
                random.choice([c.upper(), c.lower()]) for c in p
            ),
            "prefix_add": lambda p: f"'--{p}",
            "suffix_add": lambda p: f"{p}--",
            "double_quote": lambda p: p.replace("'", '"'),
            "backtick_wrap": lambda p: f"`{p}`",
            "url_encode_partial": lambda p: "".join(
                f"%{ord(c):02x}" if random.random() < 0.3 else c
                for c in p
            ),
            "concat_split": lambda p: "||".join(
                p[i:i+2] for i in range(0, len(p), 2)
            ),
        }
    
    def seed(self, payloads: List[str]) -> None:
        """
        Seed the population with initial payloads.
        
        Args:
            payloads: List of initial payload strings
        """
        self.population = [
            {
                "payload": p,
                "fitness": 0.0,
                "generation": 0,
                "mutations_applied": [],
                "parent_ids": [],
            }
            for p in payloads
        ]
        
        # Fill remaining slots with random combinations
        while len(self.population) < self.population_size:
            if len(payloads) >= 2:
                parent1 = random.choice(payloads)
                parent2 = random.choice(payloads)
                child = self._crossover(parent1, parent2)
                child = self._apply_random_mutation(child)
            else:
                child = random.choice(payloads) if payloads else "test"
            
            self.population.append({
                "payload": child,
                "fitness": 0.0,
                "generation": 0,
                "mutations_applied": [],
                "parent_ids": [],
            })
    
    def evolve(self, fitness_func: Callable[[str], float]) -> List[str]:
        """
        Evolve one generation. Return best payloads.
        
        Args:
            fitness_func: Function that scores a payload (higher = better)
            
        Returns:
            List of best payloads from this generation
        """
        self.generation += 1
        
        # Evaluate fitness
        for individual in self.population:
            individual["fitness"] = fitness_func(individual["payload"])
            individual["generation"] = self.generation
        
        # Sort by fitness (highest first)
        self.population.sort(key=lambda x: x["fitness"], reverse=True)
        
        # Track best
        current_best = self.population[0]
        if self.best_payload is None or current_best["fitness"] > self.best_payload["fitness"]:
            self.best_payload = current_best.copy()
            self.stagnation_count = 0
        else:
            self.stagnation_count += 1
        
        # Adaptive mutation rate
        if self.stagnation_count > self.max_stagnation:
            self.mutation_rate = min(
                self.max_mutation_rate,
                self.mutation_rate * 1.5
            )
        else:
            self.mutation_rate = self.base_mutation_rate
        
        # Calculate diversity
        unique_payloads = set(p["payload"] for p in self.population)
        diversity = len(unique_payloads) / len(self.population)
        self.diversity_history.append(diversity)
        
        # Elitism: keep top individuals
        new_pop = self.population[:self.elite_count]
        
        # Tournament selection + crossover + mutation for the rest
        while len(new_pop) < self.population_size:
            # Tournament selection (select 3, pick best)
            tournament = random.sample(self.population, min(3, len(self.population)))
            parent1 = max(tournament, key=lambda x: x["fitness"])
            
            tournament = random.sample(self.population, min(3, len(self.population)))
            parent2 = max(tournament, key=lambda x: x["fitness"])
            
            # Crossover: combine halves
            child_payload = self._crossover(
                parent1["payload"], parent2["payload"]
            )
            
            # Mutation (adaptive rate)
            if random.random() < self.mutation_rate:
                child_payload = self._apply_random_mutation(child_payload)
            
            new_pop.append({
                "payload": child_payload,
                "fitness": 0.0,
                "generation": self.generation,
                "mutations_applied": [],
                "parent_ids": [
                    id(parent1), id(parent2)
                ],
            })
        
        self.population = new_pop
        
        # Track best fitness
        best_fitness = self.population[0]["fitness"]
        self.fitness_history.append(best_fitness)
        
        return [p["payload"] for p in self.population]
    
    def _crossover(self, parent1: str, parent2: str) -> str:
        """Perform crossover between two parent payloads."""
        if len(parent1) < 2 or len(parent2) < 2:
            return parent1 + parent2
        
        # Random crossover points
        if random.random() < 0.5:
            # Single-point crossover
            mid1 = random.randint(1, len(parent1) - 1)
            mid2 = random.randint(1, len(parent2) - 1)
            return parent1[:mid1] + parent2[mid2:]
        else:
            # Two-point crossover
            if len(parent1) > 4 and len(parent2) > 4:
                p1_start = random.randint(1, len(parent1) // 2)
                p1_end = random.randint(p1_start + 1, len(parent1) - 1)
                p2_start = random.randint(1, len(parent2) // 2)
                p2_end = random.randint(p2_start + 1, len(parent2) - 1)
                
                return (
                    parent1[:p1_start] +
                    parent2[p2_start:p2_end] +
                    parent1[p1_end:]
                )
        
        return parent1 + parent2
    
    def _apply_random_mutation(self, payload: str) -> str:
        """Apply a random mutation to the payload."""
        if not self.MUTATIONS:
            return payload
        
        mutation_name = random.choice(list(self.MUTATIONS.keys()))
        mutation_func = self.MUTATIONS[mutation_name]
        
        try:
            return mutation_func(payload)
        except Exception:
            return payload
    
    def get_best(self, n: int = 3) -> List[str]:
        """
        Return top N payloads.
        
        Args:
            n: Number of top payloads to return
            
        Returns:
            List of best payload strings
        """
        return [p["payload"] for p in self.population[:n]]
    
    def get_elite(self) -> List[str]:
        """Return elite population payloads."""
        return [p["payload"] for p in self.population[:self.elite_count]]
    
    def is_converged(self, threshold: float = 0.95) -> bool:
        """
        Check if population has converged.
        
        Args:
            threshold: Fitness threshold for convergence
            
        Returns:
            True if converged
        """
        if len(self.fitness_history) < 3:
            return False
        
        recent = self.fitness_history[-3:]
        return all(f >= threshold for f in recent)
    
    def get_stats(self) -> Dict:
        """Return fuzzer statistics."""
        return {
            "generation": self.generation,
            "population_size": self.population_size,
            "elite_count": self.elite_count,
            "best_fitness": self.population[0]["fitness"] if self.population else 0.0,
            "avg_fitness": sum(p["fitness"] for p in self.population) / max(len(self.population), 1),
            "diversity": self.diversity_history[-1] if self.diversity_history else 0.0,
            "mutation_rate": self.mutation_rate,
            "stagnation_count": self.stagnation_count,
            "fitness_history": self.fitness_history[-10:],
            "mutations_count": len(self.MUTATIONS),
        }


# ═══════════════════════════════════════════════════════════════
# RESPONSE DIFFERENTIAL ENGINE — Multi-Signal Comparison
# ═══════════════════════════════════════════════════════════════

class ResponseDifferentialEngine:
    """
    🔍 RESPONSE DIFFERENTIAL ENGINE v50 — Multi-Signal Response Comparison.
    
    Compares normal vs injected responses using 12 comparison axes:
    - Status code difference
    - Response length difference
    - Content type change
    - Whitespace anomaly
    - HTML comment change (filter bypass indicators)
    - Header ordering change (WAF fingerprinting)
    - Timing jitter (blind injection confirmation)
    - Entropy change
    - Specific pattern presence
    - Cookie changes
    - Redirect chain difference
    - Encoding detection
    
    Connected to: GeneticFuzzer, ZombieWAFZero, FuzzerEngine
    """
    
    def __init__(self):
        """Initialize Response Differential Engine."""
        self.comparison_stats = Counter()
    
    @staticmethod
    def compare_responses(
        normal: Dict,
        injected: Dict,
        deep_analysis: bool = False,
    ) -> Dict:
        """
        Compare two responses with multi-signal analysis.
        
        Args:
            normal: Normal/baseline response dict
            injected: Injected/payload response dict
            deep_analysis: Enable deep comparison
            
        Returns:
            Dict with comparison verdict and confidence
        """
        n_body = normal.get("body", normal.get("text", ""))
        i_body = injected.get("body", injected.get("text", ""))
        
        n_len = len(n_body)
        i_len = len(i_body)
        n_status = normal.get("status", 200)
        i_status = injected.get("status", 200)
        
        # Identical? Likely false positive.
        if n_body == i_body and n_status == i_status:
            return {
                "verdict": "identical",
                "confidence": 0.0,
                "signals": [],
                "matched": False,
            }
        
        confidence = 0.0
        signals = []
        details = {}
        
        # ═══ SIGNAL 1: Status Code Change ═══
        if n_status != i_status:
            confidence += 25
            signals.append("status_code_change")
            details["status_change"] = f"{n_status} → {i_status}"
            
            # 500 errors are strong indicators
            if i_status >= 500:
                confidence += 15
                signals.append("server_error")
        
        # ═══ SIGNAL 2: Length Difference ═══
        length_diff = i_len - n_len
        length_ratio = i_len / max(n_len, 1)
        details["length_diff"] = length_diff
        details["length_ratio"] = round(length_ratio, 3)
        
        if abs(length_diff) > 200:
            confidence += 25
            signals.append("significant_length_diff")
        elif abs(length_diff) > 50:
            confidence += 15
            signals.append("moderate_length_diff")
        elif abs(length_diff) > 10:
            confidence += 5
            signals.append("minor_length_diff")
        
        # ═══ SIGNAL 3: Whitespace Anomaly ═══
        n_ws = n_body.count(" ") + n_body.count("\n") + n_body.count("\t")
        i_ws = i_body.count(" ") + i_body.count("\n") + i_body.count("\t")
        ws_diff = i_ws - n_ws
        details["whitespace_diff"] = ws_diff
        
        if abs(ws_diff) > 50:
            confidence += 15
            signals.append("significant_whitespace_anomaly")
        elif abs(ws_diff) > 10:
            confidence += 8
            signals.append("whitespace_anomaly")
        
        # ═══ SIGNAL 4: HTML Comment Change ═══
        n_comments = len(re.findall(r'<!--.*?-->', n_body, re.DOTALL))
        i_comments = len(re.findall(r'<!--.*?-->', i_body, re.DOTALL))
        details["comment_change"] = i_comments - n_comments
        
        if i_comments != n_comments:
            confidence += 10
            signals.append("comment_structure_change")
        
        # ═══ SIGNAL 5: Header Structure Change ═══
        n_headers = list(normal.get("headers", {}).keys())
        i_headers = list(injected.get("headers", {}).keys())
        
        n_header_set = set(h.lower() for h in n_headers)
        i_header_set = set(h.lower() for h in i_headers)
        
        header_diff = n_header_set != i_header_set
        new_headers = i_header_set - n_header_set
        removed_headers = n_header_set - i_header_set
        
        details["new_headers"] = list(new_headers)
        details["removed_headers"] = list(removed_headers)
        
        if header_diff:
            confidence += 12
            signals.append("header_structure_change")
        
        # ═══ SIGNAL 6: Timing Jitter ═══
        n_time = normal.get("elapsed", normal.get("response_time_ms", 0))
        i_time = injected.get("elapsed", injected.get("response_time_ms", 0))
        
        if n_time > 0 and i_time > 0:
            time_ratio = i_time / max(n_time, 0.001)
            details["time_ratio"] = round(time_ratio, 2)
            
            if time_ratio > 5:
                confidence += 20
                signals.append("significant_timing_delay")
            elif time_ratio > 2:
                confidence += 10
                signals.append("moderate_timing_delay")
        
        # ═══ SIGNAL 7: Entropy Change ═══
        n_entropy = calculate_entropy(n_body) if n_body else 0
        i_entropy = calculate_entropy(i_body) if i_body else 0
        entropy_diff = abs(i_entropy - n_entropy)
        details["entropy_diff"] = round(entropy_diff, 4)
        
        if entropy_diff > 1.0:
            confidence += 10
            signals.append("significant_entropy_change")
        elif entropy_diff > 0.5:
            confidence += 5
            signals.append("entropy_change")
        
        # ═══ SIGNAL 8: Cookie Changes ═══
        n_cookies = set(normal.get("cookies", {}).keys())
        i_cookies = set(injected.get("cookies", {}).keys())
        
        if n_cookies != i_cookies:
            confidence += 8
            signals.append("cookie_change")
            details["cookie_diff"] = list(i_cookies - n_cookies)
        
        # ═══ SIGNAL 9: Specific Pattern Presence ═══
        error_patterns = [
            "error", "exception", "warning", "fatal",
            "traceback", "stack trace", "syntax",
            "sql", "mysql", "postgresql", "oracle",
            "mssql", "sqlite", "mongodb",
        ]
        
        n_errors = sum(1 for p in error_patterns if p in n_body.lower())
        i_errors = sum(1 for p in error_patterns if p in i_body.lower())
        
        if i_errors > n_errors:
            confidence += 15
            signals.append("error_disclosure")
            details["error_patterns_new"] = i_errors - n_errors
        
        # ═══ SIGNAL 10: Redirect Chain ═══
        n_redirects = len(normal.get("redirects", []))
        i_redirects = len(injected.get("redirects", []))
        
        if n_redirects != i_redirects:
            confidence += 5
            signals.append("redirect_chain_change")
        
        # ═══ SIGNAL 11: Content Type Change ═══
        n_ct = normal.get("content_type", "")
        i_ct = injected.get("content_type", "")
        
        if n_ct != i_ct:
            confidence += 8
            signals.append("content_type_change")
            details["content_type_change"] = f"{n_ct} → {i_ct}"
        
        # ═══ SIGNAL 12: HTML Tag Count ═══
        if deep_analysis:
            n_tags = len(re.findall(r'<(\w+)', n_body))
            i_tags = len(re.findall(r'<(\w+)', i_body))
            
            if abs(i_tags - n_tags) > 10:
                confidence += 5
                signals.append("html_structure_change")
                details["tag_count_diff"] = i_tags - n_tags
        
        # Normalize confidence
        confidence = min(confidence, 100)
        
        return {
            "verdict": "different",
            "confidence": confidence,
            "signals": signals,
            "details": details,
            "matched": confidence >= 30,
        }
    
    @staticmethod
    def batch_compare(
        normal: Dict,
        injected_list: List[Dict],
    ) -> List[Dict]:
        """
        Compare baseline against multiple injected responses.
        
        Args:
            normal: Baseline response
            injected_list: List of injected responses
            
        Returns:
            List of comparison results sorted by confidence
        """
        results = []
        
        for injected in injected_list:
            result = ResponseDifferentialEngine.compare_responses(
                normal, injected
            )
            result["payload"] = injected.get("payload", "")
            result["url"] = injected.get("url", "")
            results.append(result)
        
        results.sort(key=lambda x: x["confidence"], reverse=True)
        return results


# ═══════════════════════════════════════════════════════════════
# HONEYPOT DETECTOR — Advanced Trap Detection & Avoidance
# ═══════════════════════════════════════════════════════════════

class HoneypotDetector:
    """
    🪤 HONEYPOT DETECTOR v50 — Advanced Trap Detection & Avoidance.
    
    Detects 15+ types of security traps:
    - Hidden links (CSS: display:none, visibility:hidden, opacity:0)
    - Links with suspicious text ("admin", "config", ".env", "backup")
    - Endpoints that always return 200 with empty content
    - Endpoints with constant response time (fake indicators)
    - Forms with action pointing to suspicious endpoints
    - Invisible form fields
    - Links with extremely small font size
    - Links positioned off-screen
    - Links with same color as background
    - Redirect chains to known honeypot services
    - Cookies indicating honeypot
    - Headers indicating honeypot
    - Port-knocking sequences
    - Rate-limit honeypots
    - Decoy admin panels
    
    Connected to: ZombieCrawler, ZombieRecon
    """
    
    # ═══ Honeypot HTML Patterns ═══
    HONEYPOT_HTML_PATTERNS: ClassVar[List[str]] = [
        # Hidden elements
        r'(?:display\s*:\s*none|visibility\s*:\s*hidden|opacity\s*:\s*0)',
        r'position\s*:\s*absolute\s*;\s*(?:left|top)\s*:\s*-?\d{4,}px',
        r'font-size\s*:\s*0',
        r'color\s*:\s*(?:transparent|rgba\(0,\s*0,\s*0,\s*0\))',
        r'width\s*:\s*0|height\s*:\s*0',
        r'clip\s*:\s*rect\(0,\s*0,\s*0,\s*0\)',
        r'overflow\s*:\s*hidden',
        r'z-index\s*:\s*-?\d{3,}',
        
        # Suspicious links
        r'href\s*=\s*["\'][^"\']*(?:admin|config|backup|debug|test|dev|staging|sandbox|\.env|\.git)',
        r'<a[^>]*>\s*(?:click here|admin|login|secret|hidden|private|internal|test)\s*</a>',
        r'href\s*=\s*["\'][^"\']*(?:\.php|\.asp|\.aspx|\.jsp|\.cgi)["\']',
    ]
    
    # ═══ Honeypot URL Patterns ═══
    HONEYPOT_URL_PATTERNS: ClassVar[List[str]] = [
        r'(?:honeypot|trap|decoy|fake|dummy)',
        r'/wp-admin(?:/|$)', r'/administrator(?:/|$)',
        r'/phpmyadmin', r'/adminer',
        r'/\.git/', r'/\.svn/', r'/\.env',
        r'/config/', r'/backup/', r'/dump/',
        r'/debug/', r'/test/', r'/dev/',
        r'/api/admin', r'/api/internal',
    ]
    
    # ═══ Honeypot Cookie/Header Patterns ═══
    HONEYPOT_HEADER_PATTERNS: ClassVar[List[str]] = [
        r'(?i)honeypot', r'(?i)trap', r'(?i)decoy',
        r'(?i)x-honeypot', r'(?i)x-trap',
        r'(?i)glitchtip', r'(?i)projecthoneypot',
    ]
    
    def __init__(self) -> None:
        """Initialize honeypot detector."""
        self.detected_traps: Set[str] = set()
        self.response_times: Dict[str, List[float]] = defaultdict(list)
        self.response_sizes: Dict[str, List[int]] = defaultdict(list)
        self.trap_confidence: Dict[str, float] = {}
        self._scan_stats = Counter()
    
    async def scan_page(self, url: str, html: str, headers: Dict = None, cookies: Dict = None) -> List[str]:
        """
        Scan HTML for honeypot indicators.
        
        Args:
            url: Page URL
            html: HTML content
            headers: Response headers
            cookies: Response cookies
            
        Returns:
            List of detected trap descriptions
        """
        traps = []
        
        # Check HTML patterns
        for pattern in self.HONEYPOT_HTML_PATTERNS:
            matches = re.findall(pattern, html, re.IGNORECASE | re.DOTALL)
            for match in matches:
                trap_desc = f"HONEYPOT_HTML:{url}:{str(match)[:80]}"
                traps.append(trap_desc)
                self._scan_stats["html_traps"] += 1
        
        # Check URL patterns
        for pattern in self.HONEYPOT_URL_PATTERNS:
            if re.search(pattern, url, re.IGNORECASE):
                trap_desc = f"HONEYPOT_URL:{url}"
                traps.append(trap_desc)
                self._scan_stats["url_traps"] += 1
        
        # Check headers
        if headers:
            for header_name, header_value in headers.items():
                for pattern in self.HONEYPOT_HEADER_PATTERNS:
                    if re.search(pattern, str(header_value), re.IGNORECASE):
                        trap_desc = f"HONEYPOT_HEADER:{url}:{header_name}"
                        traps.append(trap_desc)
                        self._scan_stats["header_traps"] += 1
        
        # Check cookies
        if cookies:
            for cookie_name, cookie_value in cookies.items():
                for pattern in self.HONEYPOT_HEADER_PATTERNS:
                    if re.search(pattern, f"{cookie_name}={cookie_value}", re.IGNORECASE):
                        trap_desc = f"HONEYPOT_COOKIE:{url}:{cookie_name}"
                        traps.append(trap_desc)
                        self._scan_stats["cookie_traps"] += 1
        
        # Store detected traps
        for trap in traps:
            self.detected_traps.add(trap)
            self.trap_confidence[trap] = self.trap_confidence.get(trap, 0) + 0.2
        
        return traps
    
    def is_trap(self, url: str, threshold: float = 0.5) -> bool:
        """
        Check if URL is a detected trap.
        
        Args:
            url: URL to check
            threshold: Confidence threshold
            
        Returns:
            True if URL is a known honeypot
        """
        # Direct match
        for trap in self.detected_traps:
            if url in trap:
                if self.trap_confidence.get(trap, 0) >= threshold:
                    return True
        
        # Pattern match
        for pattern in self.HONEYPOT_URL_PATTERNS:
            if re.search(pattern, url, re.IGNORECASE):
                return True
        
        return False
    
    def record_response_time(self, url: str, rt: float) -> None:
        """
        Record response time for timing analysis.
        
        Args:
            url: Request URL
            rt: Response time in seconds
        """
        self.response_times[url].append(rt)
        if len(self.response_times[url]) > 50:
            self.response_times[url] = self.response_times[url][-50:]
    
    def record_response_size(self, url: str, size: int) -> None:
        """
        Record response size for size analysis.
        
        Args:
            url: Request URL
            size: Response size in bytes
        """
        self.response_sizes[url].append(size)
        if len(self.response_sizes[url]) > 50:
            self.response_sizes[url] = self.response_sizes[url][-50:]
    
    def detect_timing_trap(self, url: str) -> bool:
        """
        Detect timing-based traps.
        Responses with near-zero variance = likely fake/trap.
        
        Args:
            url: URL to analyze
            
        Returns:
            True if URL shows trap timing patterns
        """
        times = self.response_times.get(url, [])
        if len(times) < 5:
            return False
        
        avg = sum(times) / len(times)
        variance = sum((t - avg) ** 2 for t in times) / len(times)
        
        # Near-zero variance = automated response = likely trap
        return variance < 0.001
    
    def detect_size_trap(self, url: str) -> bool:
        """
        Detect size-based traps.
        Consistently same response size = likely trap.
        
        Args:
            url: URL to analyze
            
        Returns:
            True if URL shows trap size patterns
        """
        sizes = self.response_sizes.get(url, [])
        if len(sizes) < 5:
            return False
        
        # All same size = likely trap
        return len(set(sizes)) == 1
    
    def get_risk_score(self, url: str) -> float:
        """
        Calculate overall honeypot risk score for URL.
        
        Args:
            url: URL to assess
            
        Returns:
            Risk score (0.0-1.0)
        """
        risk = 0.0
        
        if self.is_trap(url, threshold=0.3):
            risk += 0.4
        
        if self.detect_timing_trap(url):
            risk += 0.3
        
        if self.detect_size_trap(url):
            risk += 0.3
        
        return min(1.0, risk)
    
    def get_stats(self) -> Dict:
        """Return honeypot detection statistics."""
        return {
            "total_traps": len(self.detected_traps),
            "timing_traps": sum(
                1 for url in self.response_times
                if self.detect_timing_trap(url)
            ),
            "size_traps": sum(
                1 for url in self.response_sizes
                if self.detect_size_trap(url)
            ),
            "tracked_urls": len(self.response_times),
            "html_traps": self._scan_stats.get("html_traps", 0),
            "url_traps": self._scan_stats.get("url_traps", 0),
            "header_traps": self._scan_stats.get("header_traps", 0),
            "cookie_traps": self._scan_stats.get("cookie_traps", 0),
        }
    
    def clear(self) -> None:
        """Clear all trap data."""
        self.detected_traps.clear()
        self.response_times.clear()
        self.response_sizes.clear()
        self.trap_confidence.clear()
        self._scan_stats.clear()


