    def __init__(self, target_profile: Optional[TargetProfile] = None) -> None:
        """
        Initialize Smart Payload Factory v50.
        
        Args:
            target_profile: TargetProfile with detected technologies
        """
        self.profile = target_profile or TargetProfile(url="")
        self.generated_payloads: Dict[str, Set[str]] = defaultdict(set)
        self.successful_payloads: Dict[str, List[Dict]] = defaultdict(list)
        self.payload_scores: Dict[str, float] = {}
        self.total_generated = 0
    
    def get_sqli_payloads(self, max_payloads: int = 300) -> List[Dict]:
        """
        Generate SQLi payloads smartly based on target profile.
        
        Args:
            max_payloads: Maximum payloads to return
            
        Returns:
            List of payload dictionaries
        """
        payloads = []
        seen = set()
        
        # Auth bypass (always included)
        for p in self.SQLI_PAYLOADS.get("auth_bypass", []):
            key = dhash(p["payload"])
            if key not in seen:
                seen.add(key)
                payloads.append({**p, "priority": 10})
        
        # Database-specific payloads
        db_type = self._detect_db_type()
        if db_type:
            for category in ["boolean_based", "union_based", "time_based", "error_based"]:
                for p in self.SQLI_PAYLOADS.get(category, []):
                    key = dhash(p["payload"])
                    if key not in seen:
                        seen.add(key)
                        payloads.append({**p, "priority": 20, "db_target": db_type})
        
        # WAF bypass if detected
        if self.profile.waf_type:
            for p in self.SQLI_PAYLOADS.get("waf_bypass_sqli", []):
                key = dhash(p["payload"])
                if key not in seen:
                    seen.add(key)
                    payloads.append({**p, "priority": 15, "waf_bypass": True})
        
        # Fallback to Payloads class
        if len(payloads) < 10:
            try:
                from_payloads_class = random.sample(Payloads.SQLI, min(50, len(Payloads.SQLI)))
                for pl in from_payloads_class:
                    key = dhash(pl)
                    if key not in seen:
                        seen.add(key)
                        payloads.append({"payload": pl, "priority": 5, "source": "fallback"})
            except Exception:
                pass
        
        payloads.sort(key=lambda x: x.get("priority", 0), reverse=True)
        return payloads[:max_payloads]
    
