    # ═══ Detection Helpers ═══
    
    def _detect_db_type(self) -> Optional[str]:
        """Detect database type from tech stack."""
        tech = f"{self.profile.database} {self.profile.server} {self.profile.framework}".lower()
        
        if any(x in tech for x in ["mysql", "mariadb"]): return "mysql"
        if any(x in tech for x in ["postgresql", "postgres", "pgsql"]): return "postgresql"
        if any(x in tech for x in ["mssql", "sql server", "microsoft"]): return "mssql"
        if "oracle" in tech: return "oracle"
        if "sqlite" in tech: return "sqlite"
        if "mongodb" in tech: return "mongodb"
        
        return None
    
    def _detect_xss_contexts(self) -> List[str]:
        """Detect XSS reflection contexts."""
        contexts = []
        
        for point in self.profile.reflection_points:
            surrounding = point.get("surrounding", "")
            
            if "<script>" in surrounding or "</script>" in surrounding:
                contexts.append("javascript_context")
            elif "href" in surrounding or "src" in surrounding:
                contexts.append("attribute_xss")
            elif "<" in surrounding and ">" in surrounding:
                contexts.append("reflected_xss")
        
        if not contexts:
            contexts.append("reflected_xss")
        
        return list(set(contexts))
    
    def _detect_cloud_provider(self) -> Optional[str]:
        """Detect cloud provider."""
        tech = f"{self.profile.server} {self.profile.framework}".lower()
        
        if any(x in tech for x in ["aws", "amazon", "ec2", "cloudfront"]): return "aws"
        if any(x in tech for x in ["gcp", "google cloud", "appspot"]): return "gcp"
        if any(x in tech for x in ["azure", "microsoft"]): return "azure"
        if "digitalocean" in tech: return "digitalocean"
        
        return None
    
    def _detect_template_engine(self) -> Optional[str]:
        """Detect template engine."""
        tech = f"{self.profile.language} {self.profile.framework}".lower()
        
        if any(x in tech for x in ["flask", "jinja", "django"]): return "jinja2_python"
        if any(x in tech for x in ["twig", "symfony", "laravel"]): return "twig_php"
        if any(x in tech for x in ["freemarker", "spring"]): return "freemarker_java"
        if any(x in tech for x in ["velocity", "struts"]): return "velocity_java"
        if any(x in tech for x in ["smarty", "codeigniter"]): return "smarty_php"
        if any(x in tech for x in ["handlebars", "express"]): return "handlebars_node"
        
        return None
    
    def record_success(self, vuln_type: str, payload: Dict) -> None:
        """
        Record a successful payload for future amplification.
        
        Args:
            vuln_type: Vulnerability type
            payload: Successful payload dictionary
        """
        self.profile.successful_payloads.append({
            **payload,
            "success_time": datetime.now(timezone.utc).isoformat(),
        })
        self.successful_payloads[vuln_type].append(payload)
    
    def get_total_payloads_available(self) -> Dict[str, int]:
        """Return count of available payloads per vulnerability type."""
        return {
            "sqli": sum(len(v) for v in self.SQLI_PAYLOADS.values()),
            "xss": sum(len(v) for v in self.XSS_PAYLOADS.values()),
            "ssrf": sum(len(v) for v in self.SSRF_PAYLOADS.values()),
            "ssti": sum(len(v) for v in self.SSTI_PAYLOADS.values()),
        }


