    # ═══ UTILITY METHODS ═══
    
    @staticmethod
    def sample(lst: List[str], n: int) -> List[str]:
        """Get random sample from payload list."""
        if not lst:
            return []
        return random.sample(lst, min(n, len(lst)))
    
    @classmethod
    def get_all_payloads(cls) -> Dict[str, List[str]]:
        """Return all payloads grouped by vulnerability type."""
        return {
            "xss": cls.XSS,
            "sqli": cls.SQLI,
            "lfi": cls.LFI,
            "ssti": cls.SSTI,
            "ssrf": cls.SSRF,
            "xxe": cls.XXE,
            "nosql": cls.NOSQL,
            "cmdi": cls.CMDI,
        }
    
    @classmethod
    def get_total_count(cls) -> int:
        """Return total number of payloads across all categories."""
        return (
            len(cls.XSS) + len(cls.SQLI) + len(cls.LFI) +
            len(cls.SSTI) + len(cls.SSRF) + len(cls.XXE) +
            len(cls.NOSQL) + len(cls.CMDI)
        )
    
    @classmethod
    def get_payloads_by_type(cls, vuln_type: str, max_count: int = 100) -> List[str]:
        """
        Get payloads for a specific vulnerability type.
        
        Args:
            vuln_type: Vulnerability type
            max_count: Maximum payloads to return
            
        Returns:
            List of payload strings
        """
        type_map = {
            "xss": cls.XSS,
            "sqli": cls.SQLI,
            "lfi": cls.LFI,
            "ssti": cls.SSTI,
            "ssrf": cls.SSRF,
            "xxe": cls.XXE,
            "nosql": cls.NOSQL,
            "cmdi": cls.CMDI,
        }
        
        payloads = type_map.get(vuln_type.lower(), [])
        return cls.sample(payloads, max_count)


