    async def _query_dnsdumpster(self, session) -> List[str]:
        """Query DNSDumpster."""
        results = []
        try:
            # DNSDumpster requires CSRF token
            url = "https://dnsdumpster.com/"
            headers = self._zombie.get_headers(url, domain=self.domain)
            async with session.get(url, headers=headers, timeout=aiohttp.ClientTimeout(total=30), ssl=False) as resp:
                text = await resp.text()
                csrf_match = re.search(r'name="csrfmiddlewaretoken" value="([^"]+)"', text)
                if csrf_match:
                    csrf_token = csrf_match.group(1)
                    
                    data = {
                        "csrfmiddlewaretoken": csrf_token,
                        "targetip": self.domain,
                        "user": "free",
                    }
                    headers["Referer"] = url
                    headers["Content-Type"] = "application/x-www-form-urlencoded"
                    
                    async with session.post(
                        url, headers=headers, data=data,
                        timeout=aiohttp.ClientTimeout(total=30), ssl=False,
                    ) as resp2:
                        resp_text = await resp2.text()
                        # Extract subdomains from response
                        subs = re.findall(r'<td[^>]*>\s*([a-zA-Z0-9.-]+\.' + re.escape(self.domain) + r')\s*</td>', resp_text)
                        results.extend([s.strip().lower() for s in subs])
            self.stats["dnsdumpster"] = len(results)
        except Exception:
            pass
        return results
    
