    async def _query_github(self, session) -> List[str]:
        """Search GitHub for domain references."""
        results = []
        try:
            url = f"https://api.github.com/search/code?q={self.domain}+in:file&per_page=100"
            headers = {
                "Accept": "application/vnd.github.v3+json",
            }
            token = self.api_keys.get("github", "")
            if token:
                headers["Authorization"] = f"token {token}"
            headers.update(self._zombie.get_headers(url, domain=self.domain))
            
            async with session.get(url, headers=headers, timeout=aiohttp.ClientTimeout(total=30), ssl=False) as resp:
                if resp.status == 200:
                    data = await resp.json()
                    for item in data.get("items", []):
                        html_url = item.get("html_url", "")
                        if html_url:
                            results.append(html_url)
            self.stats["github"] = len(results)
        except Exception:
            pass
        return results
    
    async def _scan_cloud_buckets(self) -> None:
        """Scan for cloud storage buckets."""
        bucket_patterns = [
            self.domain.replace(".", ""),
            self.domain.replace(".", "-"),
            self.domain.split(".")[0],
            f"{self.domain.split('.')[0]}-prod",
            f"{self.domain.split('.')[0]}-dev",
            f"{self.domain.split('.')[0]}-staging",
        ]
        
        async with aiohttp.ClientSession() as session:
            for pattern in bucket_patterns[:5]:
                for provider, url_template in [
                    ("aws", f"https://{pattern}.s3.amazonaws.com"),
                    ("aws-regional", f"https://{pattern}.s3-us-west-2.amazonaws.com"),
                    ("gcp", f"https://{pattern}.storage.googleapis.com"),
                    ("azure", f"https://{pattern}.blob.core.windows.net"),
                    ("digitalocean", f"https://{pattern}.nyc3.digitaloceanspaces.com"),
                ]:
                    try:
                        headers = self._zombie.get_headers(url_template, domain=self.domain)
                        async with session.get(
                            url_template, headers=headers,
                            timeout=aiohttp.ClientTimeout(total=5), ssl=False,
                        ) as resp:
                            if resp.status in [200, 403]:
                                self.cloud_buckets.append({
                                    "provider": provider,
                                    "name": pattern,
                                    "url": url_template,
                                    "status": resp.status,
                                    "accessible": resp.status == 200,
                                })
                    except Exception:
                        continue
    
    # ═══ Full Recon Execution ═══
    
    async def recon(self) -> Dict:
        """
        Execute full recon pipeline with 100+ sources.
        
        Returns:
            Complete recon report
        """
        self.start_time = time.time()
        
        print(f"\n{C.CYAN}{'═'*70}{C.RST}")
        print(f"{C.CYAN}{C.BOLD}  {I.SEARCH} ZOMBIE RECON v50 — {self.domain} {I.SEARCH}{C.RST}")
        print(f"{C.CYAN}{'═'*70}{C.RST}")
        print(f"  {C.WHITE}Session: {C.YELLOW}{self.session_id}{C.RST}")
        print(f"  {C.WHITE}Sources: {C.YELLOW}100+{C.RST} | Workers: {C.YELLOW}{self.max_workers}{C.RST}")
        print(f"  {C.WHITE}Zombie:  {C.YELLOW}{self._zombie.pool_size} identities | {self._zombie.fingerprint} | {self._zombie.region}{C.RST}")
        
        connector = aiohttp.TCPConnector(limit=self.max_workers, ssl=False)
        timeout = aiohttp.ClientTimeout(total=30)
        
        async with aiohttp.ClientSession(connector=connector, timeout=timeout) as session:
            # Phase 1: Certificate Transparency
            print(f"\n  {C.MAGENTA}[PHASE 1] Certificate Transparency Sources{C.RST}")
            ct_tasks = [
                self._query_crtsh(session),
                self._query_certspotter(session),
            ]
            ct_results = await asyncio.gather(*ct_tasks, return_exceptions=True)
            for result in ct_results:
                if isinstance(result, list):
                    self.subdomains.update(result)
            print(f"  {C.GREEN}├─ Subdomains: {len(self.subdomains)}{C.RST}")
            
            # Phase 2: Passive DNS
            print(f"\n  {C.MAGENTA}[PHASE 2] Passive DNS Sources{C.RST}")
            dns_tasks = [
                self._query_c99(session),
                self._query_hackertarget(session),
                self._query_alienvault(session),
                self._query_threatcrowd(session),
                self._query_bufferover(session),
                self._query_dnsdumpster(session),
                self._query_riddler(session),
                self._query_virustotal(session),
                self._query_securitytrails(session),
            ]
            dns_results = await asyncio.gather(*dns_tasks, return_exceptions=True)
            for result in dns_results:
                if isinstance(result, list):
                    self.subdomains.update(result)
            print(f"  {C.GREEN}├─ Total: {len(self.subdomains)}{C.RST}")
            
            # Phase 3: Web Archives
            print(f"\n  {C.MAGENTA}[PHASE 3] Web Archives{C.RST}")
            archive_tasks = [
                self._query_wayback(session),
                self._query_commoncrawl(session),
            ]
            archive_results = await asyncio.gather(*archive_tasks, return_exceptions=True)
            for result in archive_results:
                if isinstance(result, list):
                    self.subdomains.update(result)
            print(f"  {C.GREEN}├─ Total: {len(self.subdomains)}{C.RST}")
            
            # Phase 4: Code Repositories
            print(f"\n  {C.MAGENTA}[PHASE 4] Code Repositories{C.RST}")
            code_tasks = [
                self._query_github(session),
            ]
            code_results = await asyncio.gather(*code_tasks, return_exceptions=True)
            for result in code_results:
                if isinstance(result, list):
                    # Extract domains from GitHub URLs
                    for github_url in result:
                        # GitHub URLs may contain references to subdomains
                        pass
            print(f"  {C.GREEN}├─ GitHub references found{C.RST}")
        
        # Phase 5: DNS Resolution & Wildcard Filter
        print(f"\n  {C.MAGENTA}[PHASE 5] DNS Resolution & Wildcard Filter{C.RST}")
        self._check_wildcard()
        valid_subdomains = set()
        sem = asyncio.Semaphore(self.max_workers)
        
        async def resolve_sub(sub: str) -> Tuple[str, bool]:
            async with sem:
                if not self._is_wildcard(sub):
                    ips = await self._resolve_dns_async(sub)
                    if ips:
                        return sub, True
                return sub, False
        
        tasks = [resolve_sub(sub) for sub in list(self.subdomains)[:self.max_subs]]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, tuple) and result[1]:
                sub = result[0]
                valid_subdomains.add(sub)
                ips = self._dns_cache.get(sub, [])
                self.resolved_hosts[sub] = set(ips)
        
        self.subdomains = valid_subdomains
        print(f"  {C.GREEN}├─ Resolved: {len(self.subdomains)} valid{C.RST}")
        
        # Phase 6: Permutation & Brute-Force
        if self.enable_permutations or self.enable_bruteforce:
            print(f"\n  {C.GREEN}[PHASE 6] Permutation & Brute-Force Engine{C.RST}")
            perm_count = 0
            perm_sem = asyncio.Semaphore(self.max_workers)
            
            async def check_perm(candidate: str) -> Optional[str]:
                async with perm_sem:
                    if not self._is_wildcard(candidate):
                        ips = await self._resolve_dns_async(candidate)
                        if ips:
                            return candidate
                    return None
            
            perm_tasks = []
            for candidate in self.generate_permutations(list(self.subdomains), max_perms=100000):
                perm_tasks.append(check_perm(candidate))
            
            if perm_tasks:
                perm_results = await asyncio.gather(*perm_tasks, return_exceptions=True)
                for result in perm_results:
                    if isinstance(result, str):
                        self.subdomains.add(result)
                        perm_count += 1
            
            print(f"  {C.GREEN}├─ Permutations found: {perm_count}{C.RST}")
            
            if self.enable_bruteforce:
                bf_count = 0
                common_words = self.PERMUTATION_PATTERNS[:self.brute_wordlist_size]
                
                bf_tasks = []
                for word in common_words:
                    candidate = f"{word}.{self.domain}"
                    bf_tasks.append(check_perm(candidate))
                
                if bf_tasks:
                    bf_results = await asyncio.gather(*bf_tasks, return_exceptions=True)
                    for result in bf_results:
                        if isinstance(result, str):
                            self.subdomains.add(result)
                            bf_count += 1
                
                print(f"  {C.GREEN}├─ Brute-force found: {bf_count}{C.RST}")
        
        # Phase 7: Cloud Buckets
        if self.enable_cloud_scan:
            print(f"\n  {C.MAGENTA}[PHASE 7] Cloud Bucket Discovery{C.RST}")
            await self._scan_cloud_buckets()
            print(f"  {C.GREEN}├─ Buckets: {len(self.cloud_buckets)}{C.RST}")
        
        self.end_time = time.time()
        return self._build_report()
    
    def _build_report(self) -> Dict:
        """Build comprehensive recon report."""
        duration = round(self.end_time - self.start_time, 2) if self.end_time else 0
        return {
            "session_id": self.session_id,
            "domain": self.domain,
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "duration_seconds": duration,
            "zombie_identity": self._zombie.fingerprint_report(),
            "statistics": {
                "total_subdomains": len(self.subdomains),
                "resolved_subdomains": len(self.resolved_hosts),
                "unique_ips": len(set().union(*self.resolved_hosts.values())) if self.resolved_hosts else 0,
                "cloud_buckets": len(self.cloud_buckets),
                "wildcard_detected": bool(self.wildcard_ips),
                "source_stats": dict(self.stats),
                "total_zombie_requests": self._zombie.total_requests,
                "zombie_rotations": self._zombie.stats.get("rotations", 0),
            },
            "subdomains": sorted(list(self.subdomains)),
            "resolved": {k: sorted(list(v)) for k, v in self.resolved_hosts.items()},
            "cloud_buckets": self.cloud_buckets,
            "permutation_patterns": len(self.PERMUTATION_PATTERNS),
        }
    
    def export_report(self, formats: List[str] = None) -> Dict[str, Path]:
        """Export recon report in multiple formats."""
        if formats is None:
            formats = ["json", "txt", "csv"]
        
        report = self._build_report()
        exported = {}
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        base_name = f"zombie_recon_{self.domain}_{ts}"
        
        for fmt in formats:
            if fmt == "json":
                path = self.output_dir / f"{base_name}.json"
                with open(path, "w") as f:
                    json.dump(report, f, default=str, indent=2)
                exported["json"] = path
            elif fmt == "txt":
                path = self.output_dir / f"{base_name}.txt"
                with open(path, "w") as f:
                    f.write(f"ZOMBIE RECON REPORT v50\n{'='*60}\n")
                    f.write(f"Domain: {self.domain}\n")
                    f.write(f"Total Subdomains: {len(self.subdomains)}\n")
                    f.write(f"Resolved: {len(self.resolved_hosts)}\n\n")
                    for sub in sorted(self.subdomains):
                        ips = self.resolved_hosts.get(sub, set())
                        f.write(f"  {sub} -> {', '.join(sorted(ips)) if ips else 'NXDOMAIN'}\n")
                exported["txt"] = path
            elif fmt == "csv":
                path = self.output_dir / f"{base_name}.csv"
                with open(path, "w") as f:
                    f.write("subdomain,ips\n")
                    for sub in sorted(self.subdomains):
                        ips = ",".join(sorted(self.resolved_hosts.get(sub, [])))
                        f.write(f"{sub},{ips}\n")
                exported["csv"] = path
        
        return exported


