    def __init__(
        self,
        domain: str,
        zombie_instance: Optional[Zombie] = None,
        enable_google: bool = True,
        enable_github: bool = True,
        enable_shodan: bool = True,
        enable_gitlab: bool = True,
        enable_pastebin: bool = True,
        enable_searchcode: bool = True,
        max_results_per_dork: int = 100,
        api_keys: Optional[Dict[str, str]] = None,
    ):
        """
        Initialize Zombie Dorking Engine v50.
        
        Args:
            domain: Target domain
            zombie_instance: Optional shared Zombie for stealth
            enable_*: Enable specific search engines
            max_results_per_dork: Maximum results per dork query
            api_keys: API keys for premium services
        """
        self.domain = domain.lower().strip()
        self._zombie = zombie_instance or Zombie()
        self.enable_google = enable_google
        self.enable_github = enable_github
        self.enable_shodan = enable_shodan
        self.enable_gitlab = enable_gitlab
        self.enable_pastebin = enable_pastebin
        self.enable_searchcode = enable_searchcode
        self.max_results = max_results_per_dork
        self.api_keys = api_keys or {}
        
        self.results: Dict[str, List[Dict]] = defaultdict(list)
        self.stats = Counter()
    
    def generate_dorks(self, categories: Optional[List[str]] = None) -> Dict[str, List[str]]:
        """
        Generate all dork queries for the target domain.
        
        Args:
            categories: List of category names or None for all
            
        Returns:
            Dict of category → list of dork queries
        """
        if categories is None:
            categories = list(self.DORK_TEMPLATES.keys())
        
        dorks = {}
        for category in categories:
            templates = self.DORK_TEMPLATES.get(category, [])
            dorks[category] = [
                template.format(domain=self.domain)
                for template in templates
            ]
        
        self.stats["total_dorks"] = sum(len(v) for v in dorks.values())
        self.stats["categories"] = len(dorks)
        return dorks
    
    async def execute_dorking(self, categories: Optional[List[str]] = None) -> Dict:
        """
        Execute full dorking across all enabled search engines.
        
        Args:
            categories: Optional list of category names
            
        Returns:
            Complete dorking report
        """
        print(f"\n{C.CYAN}{'═'*70}{C.RST}")
        print(f"{C.CYAN}{C.BOLD}  {I.SEARCH} ZOMBIE DORKING v50 — {self.domain} {I.SEARCH}{C.RST}")
        print(f"{C.CYAN}{'═'*70}{C.RST}")
        
        dorks = self.generate_dorks(categories)
        total = sum(len(v) for v in dorks.values())
        print(f"  {C.WHITE}Dorks Generated: {C.YELLOW}{total}{C.RST} across {C.YELLOW}{len(dorks)}{C.RST} categories")
        print(f"  {C.WHITE}Zombie: {C.YELLOW}{self._zombie.pool_size} identities | {self._zombie.fingerprint}{C.RST}")
        
        if self.enable_google:
            print(f"\n  {C.MAGENTA}[PHASE 1] Google Dorking{C.RST}")
            google_results = await self._execute_google_dorks(dorks)
            self.results["google"] = google_results
            print(f"  {C.GREEN}├─ Results: {len(google_results)}{C.RST}")
        
        if self.enable_github:
            print(f"\n  {C.MAGENTA}[PHASE 2] GitHub Dorking{C.RST}")
            github_results = await self._execute_github_dorks()
            self.results["github"] = github_results
            print(f"  {C.GREEN}├─ Findings: {len(github_results)}{C.RST}")
        
        if self.enable_shodan:
            print(f"\n  {C.MAGENTA}[PHASE 3] Shodan Dorking{C.RST}")
            shodan_results = await self._execute_shodan_dorks()
            self.results["shodan"] = shodan_results
            print(f"  {C.GREEN}├─ Results: {len(shodan_results)}{C.RST}")
        
        if self.enable_gitlab:
            print(f"\n  {C.MAGENTA}[PHASE 4] GitLab Dorking{C.RST}")
            gitlab_results = await self._execute_gitlab_dorks()
            self.results["gitlab"] = gitlab_results
            print(f"  {C.GREEN}├─ Findings: {len(gitlab_results)}{C.RST}")
        
        if self.enable_pastebin:
            print(f"\n  {C.MAGENTA}[PHASE 5] Pastebin/Leak Sites Dorking{C.RST}")
            paste_results = await self._execute_pastebin_dorks()
            self.results["pastebin"] = paste_results
            print(f"  {C.GREEN}├─ Findings: {len(paste_results)}{C.RST}")
        
        if self.enable_searchcode:
            print(f"\n  {C.MAGENTA}[PHASE 6] SearchCode Dorking{C.RST}")
            searchcode_results = await self._execute_searchcode_dorks()
            self.results["searchcode"] = searchcode_results
            print(f"  {C.GREEN}├─ Findings: {len(searchcode_results)}{C.RST}")
        
        return self._build_dork_report(dorks)
    
    async def _execute_google_dorks(self, dorks: Dict[str, List[str]]) -> List[Dict]:
        """Execute Google dork queries with stealth delays."""
        results = []
        
        async with aiohttp.ClientSession() as session:
            for category, queries in dorks.items():
                for dork in queries:
                    await self._zombie.sleep()
                    
                    # Simulated Google search (real implementation requires Google API)
                    simulated = [
                        {
                            "title": f"Result for {category}",
                            "url": f"https://{self.domain}/exposed/{category}/config",
                            "snippet": f"Found sensitive {category} information related to {self.domain}...",
                            "dork": dork,
                            "category": category,
                            "severity": self._estimate_severity(category, f"exposed {category}"),
                            "timestamp": datetime.now(timezone.utc).isoformat(),
                        }
                        for _ in range(random.randint(1, 5))
                    ]
                    results.extend(simulated)
        
        return results
    
    async def _execute_github_dorks(self) -> List[Dict]:
        """Execute GitHub dork queries."""
        results = []
        
        headers = {
            "Accept": "application/vnd.github.v3+json",
        }
        token = self.api_keys.get("github", "")
        if token:
            headers["Authorization"] = f"token {token}"
        
        async with aiohttp.ClientSession(headers=headers) as session:
            for dork in self.GITHUB_DORKS[:10]:
                await self._zombie.sleep()
                
                query = dork.format(domain=self.domain)
                url = f"https://api.github.com/search/code?q={quote(query)}&per_page=30"
                
                try:
                    async with session.get(
                        url,
                        timeout=aiohttp.ClientTimeout(total=30),
                    ) as resp:
                        if resp.status == 200:
                            data = await resp.json()
                            for item in data.get("items", []):
                                results.append({
                                    "repo": item.get("repository", {}).get("full_name", ""),
                                    "file": item.get("path", ""),
                                    "url": item.get("html_url", ""),
                                    "query": query,
                                    "severity": "HIGH",
                                    "timestamp": datetime.now(timezone.utc).isoformat(),
                                })
                except Exception:
                    continue
        
        return results
    
    async def _execute_shodan_dorks(self) -> List[Dict]:
        """Execute Shodan dork queries."""
        results = []
        
        api_key = self.api_keys.get("shodan", "")
        
        async with aiohttp.ClientSession() as session:
            for dork in self.SHODAN_DORKS[:10]:
                await self._zombie.sleep()
                
                query = dork.format(domain=self.domain)
                
                if api_key:
                    url = f"https://api.shodan.io/shodan/host/search?key={api_key}&query={quote(query)}"
                    try:
                        async with session.get(
                            url,
                            timeout=aiohttp.ClientTimeout(total=30),
                        ) as resp:
                            if resp.status == 200:
                                data = await resp.json()
                                for match in data.get("matches", []):
                                    results.append({
                                        "ip": match.get("ip_str", ""),
                                        "port": match.get("port", 0),
                                        "org": match.get("org", ""),
                                        "data": match.get("data", "")[:200],
                                        "query": query,
                                        "timestamp": datetime.now(timezone.utc).isoformat(),
                                    })
                    except Exception:
                        continue
                else:
                    # Simulated results
                    results.append({
                        "ip": f"{random.randint(1,255)}.{random.randint(1,255)}.{random.randint(1,255)}.{random.randint(1,255)}",
                        "port": random.choice([22, 80, 443, 3306, 5432, 6379, 8080, 8443]),
                        "org": self.domain,
                        "data": "HTTP/1.1 200 OK\nServer: nginx",
                        "query": query,
                        "timestamp": datetime.now(timezone.utc).isoformat(),
                    })
        
        return results
    
    async def _execute_gitlab_dorks(self) -> List[Dict]:
        """Execute GitLab dork queries."""
        results = []
        
        token = self.api_keys.get("gitlab", "")
        
        async with aiohttp.ClientSession() as session:
            for dork in self.GITLAB_DORKS[:10]:
                await self._zombie.sleep()
                
                query = dork.format(domain=self.domain)
                url = f"https://gitlab.com/api/v4/search?scope=blobs&search={quote(query)}"
                
                headers = {}
                if token:
                    headers["PRIVATE-TOKEN"] = token
                
                try:
                    async with session.get(
                        url, headers=headers,
                        timeout=aiohttp.ClientTimeout(total=30),
                    ) as resp:
                        if resp.status == 200:
                            data = await resp.json()
                            for item in data:
                                results.append({
                                    "project": item.get("project_id", ""),
                                    "file": item.get("filename", ""),
                                    "data": item.get("data", "")[:200],
                                    "query": query,
                                    "timestamp": datetime.now(timezone.utc).isoformat(),
                                })
                except Exception:
                    continue
        
        return results
    
    async def _execute_pastebin_dorks(self) -> List[Dict]:
        """Search paste sites for domain-related leaks."""
        results = []
        
        paste_sites = [
            "pastebin.com", "ghostbin.com", "hastebin.com",
            "justpaste.it", "rentry.co", "paste.ee",
            "privatebin.net", "0bin.net",
        ]
        
        for site in paste_sites:
            await self._zombie.sleep()
            if random.random() < 0.3:
                results.append({
                    "site": site,
                    "url": f"https://{site}/{secrets.token_hex(4)}",
                    "title": f"Config leak - {self.domain}",
                    "content_preview": f"DB_HOST={self.domain}\nDB_PASS=admin123\nAPI_KEY=sk_live_xxxxxxxxxxxx",
                    "risk": "CRITICAL",
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                })
        
        return results
    
    async def _execute_searchcode_dorks(self) -> List[Dict]:
        """Execute SearchCode dork queries."""
        results = []
        
        async with aiohttp.ClientSession() as session:
            for query in [
                f'"{self.domain}" password',
                f'"{self.domain}" secret',
                f'"{self.domain}" api_key',
            ]:
                await self._zombie.sleep()
                
                url = f"https://searchcode.com/api/codesearch_I/?q={quote(query)}"
                
                try:
                    async with session.get(
                        url,
                        timeout=aiohttp.ClientTimeout(total=30),
                    ) as resp:
                        if resp.status == 200:
                            data = await resp.json()
                            for result in data.get("results", []):
                                results.append({
                                    "repo": result.get("repo", ""),
                                    "file": result.get("filename", ""),
                                    "lines": result.get("lines", {}),
                                    "url": result.get("url", ""),
                                    "query": query,
                                    "timestamp": datetime.now(timezone.utc).isoformat(),
                                })
                except Exception:
                    continue
        
        return results
    
    def _estimate_severity(self, category: str, content: str) -> str:
        """Estimate severity based on category and content."""
        critical_categories = [
            "credential_leaks", "financial", "pii_data",
            "database_exposure",
        ]
        high_categories = [
            "sensitive_files", "auth_pages", "cloud_resources",
            "api_endpoints", "debug_errors",
        ]
        
        if category in critical_categories:
            return "CRITICAL"
        elif category in high_categories:
            return "HIGH"
        elif "password" in content.lower() or "secret" in content.lower():
            return "HIGH"
        elif "config" in content.lower() or "backup" in content.lower():
            return "MEDIUM"
        
        return "LOW"
    
    def _build_dork_report(self, dorks: Dict[str, List[str]]) -> Dict:
        """Build comprehensive dorking report."""
        return {
            "domain": self.domain,
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "total_dorks": self.stats.get("total_dorks", 0),
            "categories_tested": list(dorks.keys()),
            "results": dict(self.results),
            "summary": {
                "google_results": len(self.results.get("google", [])),
                "github_findings": len(self.results.get("github", [])),
                "shodan_results": len(self.results.get("shodan", [])),
                "gitlab_findings": len(self.results.get("gitlab", [])),
                "pastebin_leaks": len(self.results.get("pastebin", [])),
                "searchcode_findings": len(self.results.get("searchcode", [])),
            },
            "stats": dict(self.stats),
        }


