    def __init__(
        self,
        start_url: str,
        zombie_instance: Optional[Zombie] = None,
        db: Optional[Any] = None,
        max_depth: int = 5,
        max_pages: int = 1000,
        workers: int = 10,
        respect_robots: bool = True,
        crawl_subdomains: bool = False,
        extract_params: bool = True,
        detect_apis: bool = True,
        find_sensitive_files: bool = True,
        timeout: int = 30,
        user_agent: str = "",
        enable_js_analysis: bool = True,
    ):
        """
        Initialize Zombie Crawler v50.
        
        Args:
            start_url: Starting URL for crawling
            zombie_instance: Optional shared Zombie for stealth
            db: Database instance for saving findings
            max_depth: Maximum crawl depth
            max_pages: Maximum pages to crawl
            workers: Number of concurrent workers
            respect_robots: Respect robots.txt rules
            crawl_subdomains: Crawl across subdomains
            extract_params: Extract parameters from URLs
            detect_apis: Discover API endpoints
            find_sensitive_files: Scan for sensitive files
            timeout: Request timeout in seconds
            user_agent: Custom User-Agent override
            enable_js_analysis: Enable JavaScript analysis
        """
        self.start_url = start_url.rstrip("/")
        self._zombie = zombie_instance or Zombie()
        self.db = db
        self.max_depth = max_depth
        self.max_pages = max_pages
        self.workers = workers
        self.respect_robots = respect_robots
        self.crawl_subdomains = crawl_subdomains
        self.extract_params = extract_params
        self.detect_apis = detect_apis
        self.find_sensitive_files = find_sensitive_files
        self.timeout = timeout
        self.custom_ua = user_agent
        self.enable_js_analysis = enable_js_analysis
        
        parsed = urlparse(self.start_url)
        self.base_domain = parsed.netloc
        self.base_scheme = parsed.scheme
        
        # Storage
        self.visited_urls: Set[str] = set()
        self.url_queue: deque = deque()
        self.discovered_urls: Dict[str, Dict] = {}
        self.api_endpoints: List[Dict] = []
        self.sensitive_files_found: List[Dict] = []
        self.forms: List[Dict] = []
        self.params: Set[str] = set()
        self.sitemap_urls: List[str] = []
        self.all_findings: List[Dict] = []  # 🔴 FIX #3: Store crawl findings
        
        # Technology detection
        self.technologies: Dict[str, str] = {}
        
        # Stats
        self.stats = Counter()
        self.start_time = None
        self.end_time = None
        self.robots_disallowed: List[str] = []
        
        # Honeypot detector
        self.honeypot = HoneypotDetector()
    
    async def crawl(self) -> Dict:
        """
        Execute full crawl with Zombie stealth.
        
        Returns:
            Complete crawl report
        """
        self.start_time = time.time()
        
        print(f"\n{C.CYAN}{'═'*70}{C.RST}")
        print(f"{C.CYAN}{C.BOLD}  {I.SPIDER} ZOMBIE CRAWLER v50 — {self.start_url} {I.SPIDER}{C.RST}")
        print(f"{C.CYAN}{'═'*70}{C.RST}")
        print(f"  {C.WHITE}Workers: {C.YELLOW}{self.workers}{C.RST} | Depth: {C.YELLOW}{self.max_depth}{C.RST} | Max Pages: {C.YELLOW}{self.max_pages}{C.RST}")
        print(f"  {C.WHITE}Zombie:  {C.YELLOW}{self._zombie.pool_size} identities | {self._zombie.fingerprint}{C.RST}")
        
        # Phase 1: Robots.txt & Sitemap
        print(f"\n  {C.MAGENTA}[PHASE 1] Robots.txt & Sitemap Discovery{C.RST}")
        await self._parse_robots()
        await self._parse_sitemap()
        print(f"  {C.GREEN}├─ Sitemap URLs: {len(self.sitemap_urls)}{C.RST}")
        print(f"  {C.GREEN}├─ Disallowed: {len(self.robots_disallowed)} paths{C.RST}")
        
        # Phase 2: Crawling
        print(f"\n  {C.MAGENTA}[PHASE 2] Intelligent Crawling{C.RST}")
        self.url_queue.append((self.start_url, 0))
        
        sem = asyncio.Semaphore(self.workers)
        
        async def crawl_worker():
            while self.url_queue and len(self.visited_urls) < self.max_pages:
                async with sem:
                    if not self.url_queue:
                        break
                    url, depth = self.url_queue.popleft()
                    if url in self.visited_urls:
                        continue
                    self.visited_urls.add(url)
                    await self._crawl_page(url, depth)
        
        workers_list = [
            asyncio.create_task(crawl_worker())
            for _ in range(self.workers)
        ]
        await asyncio.gather(*workers_list, return_exceptions=True)
        
        print(f"  {C.GREEN}├─ Pages crawled: {len(self.visited_urls)}{C.RST}")
        print(f"  {C.GREEN}├─ URLs discovered: {len(self.discovered_urls)}{C.RST}")
        
        # Phase 3: API Discovery
        if self.detect_apis:
            print(f"\n  {C.MAGENTA}[PHASE 3] API Endpoint Discovery{C.RST}")
            await self._discover_apis()
            print(f"  {C.GREEN}├─ API endpoints: {len(self.api_endpoints)}{C.RST}")
            self._save_api_findings()
        
        # Phase 4: Sensitive File Scan
        if self.find_sensitive_files:
            print(f"\n  {C.MAGENTA}[PHASE 4] Sensitive File Detection{C.RST}")
            await self._scan_sensitive_files()
            print(f"  {C.GREEN}├─ Sensitive files: {len(self.sensitive_files_found)}{C.RST}")
            self._save_sensitive_file_findings()
        
        # Phase 5: Parameter Extraction
        if self.extract_params:
            print(f"\n  {C.MAGENTA}[PHASE 5] Parameter Extraction{C.RST}")
            await self._extract_all_params()
            print(f"  {C.GREEN}├─ Unique params: {len(self.params)}{C.RST}")
        
        # Phase 6: Technology Fingerprinting
        print(f"\n  {C.MAGENTA}[PHASE 6] Technology Fingerprinting{C.RST}")
        await self._fingerprint_technologies()
        for tech, value in self.technologies.items():
            print(f"  {C.DIM}├─ {tech}: {value}{C.RST}")
        
        self.end_time = time.time()
        return self._build_crawl_report()
    
    # ═══ SAVE FINDINGS ═══
    
    def _save_sensitive_file_findings(self) -> None:
        """Save discovered sensitive files as vulnerability findings."""
        for sf in self.sensitive_files_found:
            severity = sf.get("risk", "MEDIUM")
            finding = {
                "id": str(uuid.uuid4())[:12],
                "target": self.base_domain,
                "url": sf.get("url", ""),
                "vuln_type": "Sensitive File Exposure",
                "severity": severity,
                "param": sf.get("type", ""),
                "payload": "",
                "evidence": f"Status: {sf.get('status', 'N/A')} | Size: {sf.get('size', 0)} bytes",
                "confidence": 85 if sf.get("status") == 200 else 60,
                "method": "crawler_sensitive_file",
                "waf": None,
                "full_url": sf.get("url", ""),
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "response_length": sf.get("size", 0),
                "engine_name": f"{I.SPIDER} Zombie Crawler v50 — Sensitive File",
            }
            self.all_findings.append(finding)
            
            if self.db:
                try:
                    self.db.save_finding(finding)
                except Exception:
                    pass
    
    def _save_api_findings(self) -> None:
        """Save discovered API endpoints as vulnerability findings."""
        for api in self.api_endpoints:
            finding = {
                "id": str(uuid.uuid4())[:12],
                "target": self.base_domain,
                "url": api.get("url", ""),
                "vuln_type": "API Endpoint Discovered",
                "severity": "INFO",
                "param": api.get("type", ""),
                "payload": "",
                "evidence": f"API Pattern: {api.get('pattern', '')} | Source: {api.get('source', '')}",
                "confidence": 70,
                "method": "crawler_api_discovery",
                "waf": None,
                "full_url": api.get("url", ""),
                "timestamp": datetime.now(timezone.utc).isoformat(),
                "response_length": 0,
                "engine_name": f"{I.SPIDER} Zombie Crawler v50 — API Discovery",
            }
            self.all_findings.append(finding)
            
            if self.db:
                try:
                    self.db.save_finding(finding)
                except Exception:
                    pass
    
    # ═══ PARSING ═══
    
    async def _parse_robots(self) -> None:
        """Parse robots.txt for disallowed paths and sitemaps."""
        try:
            robots_url = urljoin(self.start_url, "/robots.txt")
            headers = self._zombie.get_headers(robots_url, domain=self.base_domain)
            
            async with aiohttp.ClientSession() as session:
                async with session.get(
                    robots_url, headers=headers,
                    timeout=aiohttp.ClientTimeout(total=10),
                ) as resp:
                    if resp.status == 200:
                        text = await resp.text()
                        for line in text.split("\n"):
                            line = line.strip().lower()
                            if line.startswith("disallow:"):
                                path = line.split(":", 1)[1].strip()
                                if path:
                                    self.robots_disallowed.append(path)
                            elif line.startswith("sitemap:"):
                                sitemap = line.split(":", 1)[1].strip()
                                if sitemap:
                                    self.sitemap_urls.append(sitemap)
        except Exception:
            pass
    
    async def _parse_sitemap(self) -> None:
        """Parse sitemap.xml for URLs with recursive sitemap discovery."""
        sitemap_urls = [urljoin(self.start_url, "/sitemap.xml")]
        sitemap_urls.extend(self.sitemap_urls)
        processed_sitemaps = set()
        
        async with aiohttp.ClientSession() as session:
            while sitemap_urls:
                sitemap_url = sitemap_urls.pop(0)
                if sitemap_url in processed_sitemaps:
                    continue
                processed_sitemaps.add(sitemap_url)
                
                try:
                    headers = self._zombie.get_headers(sitemap_url, domain=self.base_domain)
                    async with session.get(
                        sitemap_url, headers=headers,
                        timeout=aiohttp.ClientTimeout(total=15),
                    ) as resp:
                        if resp.status == 200:
                            text = await resp.text()
                            
                            # Check for sitemap index
                            nested_sitemaps = re.findall(
                                r'<sitemap>\s*<loc>(.*?)</loc>',
                                text, re.IGNORECASE | re.DOTALL
                            )
                            for ns in nested_sitemaps:
                                if ns not in processed_sitemaps:
                                    sitemap_urls.append(ns.strip())
                            
                            # Extract URLs
                            urls = re.findall(r'<loc>(.*?)</loc>', text)
                            for url in urls:
                                url = url.strip()
                                if url not in self.visited_urls and self._in_scope(url):
                                    self.url_queue.append((url, 0))
                except Exception:
                    continue
    
    async def _crawl_page(self, url: str, depth: int) -> None:
        """Crawl a single page with Zombie stealth."""
        if depth > self.max_depth:
            return
        
        # Check honeypot
        if self.honeypot.is_trap(url, threshold=0.5):
            self.stats["honeypot_avoided"] += 1
            return
        
        # Respect robots.txt
        if self.respect_robots:
            parsed_path = urlparse(url).path
            if any(parsed_path.startswith(d) for d in self.robots_disallowed):
                self.stats["robots_skipped"] += 1
                return
        
        try:
            headers = self._zombie.get_headers(url, domain=self.base_domain)
            if self.custom_ua:
                headers["User-Agent"] = self.custom_ua
            
            await self._zombie.sleep(domain=self.base_domain)
            
            async with aiohttp.ClientSession() as session:
                async with session.get(
                    url, headers=headers,
                    timeout=aiohttp.ClientTimeout(total=self.timeout),
                    ssl=False,
                ) as resp:
                    if resp.status >= 400:
                        self.stats["errors"] += 1
                        # Record response time
                        self.honeypot.record_response_time(url, 0)
                        return
                    
                    content_type = resp.headers.get("Content-Type", "")
                    html = await resp.text()
                    resp_size = len(html)
                    
                    self.stats["crawled"] += 1
                    
                    # Record response metrics
                    self.honeypot.record_response_time(url, 0)
                    self.honeypot.record_response_size(url, resp_size)
                    
                    # Check for honeypot indicators
                    honeypot_traps = await self.honeypot.scan_page(
                        url, html,
                        headers=dict(resp.headers),
                        cookies={k: v.value for k, v in resp.cookies.items()},
                    )
                    if honeypot_traps:
                        self.stats["honeypot_detected"] += len(honeypot_traps)
                    
                    # Store discovered URL
                    self.discovered_urls[url] = {
                        "status": resp.status,
                        "content_type": content_type,
                        "length": resp_size,
                        "depth": depth,
                        "timestamp": datetime.now(timezone.utc).isoformat(),
                        "headers": dict(resp.headers),
                    }
                    
                    # Process based on content type
                    if "text/html" in content_type or "application/xhtml" in content_type:
                        # Extract links
                        links = self._extract_links(html, url)
                        for link in links:
                            if link not in self.visited_urls:
                                self.url_queue.append((link, depth + 1))
                        
                        # Extract forms
                        forms = self._extract_forms(html, url)
                        self.forms.extend(forms)
                        
                        # Extract comments
                        self._extract_comments(html, url, depth)
                    
                    elif "application/json" in content_type:
                        # Extract URLs from JSON
                        self._extract_urls_from_json(html, url, depth)
                    
                    elif "text/javascript" in content_type or "application/javascript" in content_type:
                        # Extract API endpoints from JS
                        if self.enable_js_analysis:
                            self._extract_api_from_js(html, url, depth)
                    
                    # Extract params from URL
                    params = SignatureDB.extract_all_params(url)
                    self.params.update(params)
        
        except asyncio.TimeoutError:
            self.stats["timeouts"] += 1
        except Exception:
            self.stats["errors"] += 1
    
    def _extract_links(self, html: str, base_url: str) -> List[str]:
        """Extract all links from HTML including JS-embedded URLs."""
        links = []
        
        # Standard href links
        for match in re.finditer(r'<a[^>]+href=["\']([^"\']+)["\']', html, re.IGNORECASE):
            absolute_url = urljoin(base_url, match.group(1))
            if self._in_scope(absolute_url):
                links.append(absolute_url.split("#")[0])
        
        # Link tags (stylesheets, etc.)
        for match in re.finditer(r'<link[^>]+href=["\']([^"\']+)["\']', html, re.IGNORECASE):
            absolute_url = urljoin(base_url, match.group(1))
            if self._in_scope(absolute_url):
                links.append(absolute_url)
        
        # Script src
        for match in re.finditer(r'<script[^>]+src=["\']([^"\']+)["\']', html, re.IGNORECASE):
            absolute_url = urljoin(base_url, match.group(1))
            if self._in_scope(absolute_url):
                links.append(absolute_url)
        
        # Image src (for potential path discovery)
        for match in re.finditer(r'<img[^>]+src=["\']([^"\']+)["\']', html, re.IGNORECASE):
            absolute_url = urljoin(base_url, match.group(1))
            if self._in_scope(absolute_url):
                links.append(absolute_url)
        
        # Form actions
        for match in re.finditer(r'<form[^>]+action=["\']([^"\']+)["\']', html, re.IGNORECASE):
            absolute_url = urljoin(base_url, match.group(1))
            if self._in_scope(absolute_url):
                links.append(absolute_url)
        
        # JavaScript URL patterns
        js_url_patterns = [
            r'(?:window\.location(?:\s*=\s*|\.href\s*=\s*)["\']([^"\']+)["\'])',
            r'(?:fetch\s*\(\s*["\']([^"\']+)["\'])',
            r'(?:axios\.(?:get|post|put|delete|patch)\s*\(\s*["\']([^"\']+)["\'])',
            r'(?:XMLHttpRequest.*?\.open\s*\([^,]+,\s*["\']([^"\']+)["\'])',
            r'(?:\.load\s*\(\s*["\']([^"\']+)["\'])',
            r'(?:\.get\s*\(\s*["\']([^"\']+)["\'])',
            r'(?:\.post\s*\(\s*["\']([^"\']+)["\'])',
            r'(?:location\.replace\s*\(\s*["\']([^"\']+)["\'])',
            r'(?:location\.assign\s*\(\s*["\']([^"\']+)["\'])',
        ]
        
        for pattern in js_url_patterns:
            for match in re.finditer(pattern, html, re.IGNORECASE):
                js_url = match.group(1)
                if js_url.startswith("/") or js_url.startswith("http"):
                    absolute_url = urljoin(base_url, js_url)
                    if self._in_scope(absolute_url):
                        links.append(absolute_url)
        
        return list(set(links))
    
    def _extract_api_from_js(self, js_code: str, base_url: str, depth: int) -> None:
        """Extract API endpoints from inline JavaScript."""
        for pattern in self.API_PATTERNS_INLINE:
            for match in re.finditer(pattern, js_code, re.IGNORECASE):
                endpoint = match.group(1)
                if endpoint.startswith('/'):
                    full_url = urljoin(base_url, endpoint)
                    if full_url not in self.visited_urls and self._in_scope(full_url):
                        self.url_queue.append((full_url, depth + 1))
                        self.api_endpoints.append({
                            "url": full_url,
                            "pattern": pattern,
                            "type": "API (JS)",
                            "source": "javascript",
                            "found_at": datetime.now(timezone.utc).isoformat(),
                        })
    
    def _extract_forms(self, html: str, page_url: str) -> List[Dict]:
        """Extract form details from HTML including all input types."""
        forms = []
        
        for form_match in re.finditer(
            r'<form[^>]*>.*?</form>', html, re.IGNORECASE | re.DOTALL
        ):
            form_html = form_match.group(0)
            
            action_match = re.search(
                r'action=["\']([^"\']*)["\']', form_html, re.IGNORECASE
            )
            action = action_match.group(1) if action_match else ""
            action_url = urljoin(page_url, action)
            
            method_match = re.search(
                r'method=["\']([^"\']*)["\']', form_html, re.IGNORECASE
            )
            method = (method_match.group(1) or "GET").upper()
            
            # Extract all input types
            inputs = []
            input_patterns = [
                r'<input[^>]+name=["\']([^"\']+)["\'][^>]*>',
                r'<select[^>]+name=["\']([^"\']+)["\']',
                r'<textarea[^>]+name=["\']([^"\']+)["\']',
                r'<button[^>]+name=["\']([^"\']+)["\']',
            ]
            
            for pattern in input_patterns:
                for input_match in re.finditer(pattern, form_html, re.IGNORECASE):
                    inputs.append(input_match.group(1))
            
            forms.append({
                "action": action_url,
                "method": method,
                "inputs": list(set(inputs)),
                "page_url": page_url,
                "timestamp": datetime.now(timezone.utc).isoformat(),
            })
        
        return forms
    
    def _extract_comments(self, html: str, base_url: str, depth: int) -> None:
        """Extract hidden endpoints from HTML comments."""
        comments = re.findall(r'<!--(.*?)-->', html, re.DOTALL)
        
        for comment in comments:
            # Extract URLs from comments
            urls_in_comment = re.findall(r'https?://[^\s<>"\']+', comment)
            for u in urls_in_comment:
                if u not in self.visited_urls and self._in_scope(u):
                    self.url_queue.append((u, depth + 1))
            
            # Extract paths from comments
            paths_in_comment = re.findall(
                r'(?:TODO|FIXME|HACK|NOTE|DEBUG|TEST)[\s:]+([/\w.-]+)',
                comment, re.IGNORECASE
            )
            for path in paths_in_comment:
                if path.startswith('/'):
                    full_url = urljoin(base_url, path)
                    if self._in_scope(full_url):
                        self.url_queue.append((full_url, depth + 1))
    
    def _extract_urls_from_json(self, json_str: str, base_url: str, depth: int) -> None:
        """Extract URLs from JSON responses."""
        url_pattern = r'https?://[^\s"\'\\]+'
        for match in re.finditer(url_pattern, json_str):
            url = match.group(0).rstrip(',')
            if self._in_scope(url) and url not in self.visited_urls:
                self.url_queue.append((url, depth + 1))
    
    def _in_scope(self, url: str) -> bool:
        """Check if URL is within crawl scope."""
        try:
            parsed = urlparse(url)
            domain = parsed.netloc
            
            if self.crawl_subdomains:
                return (
                    self.base_domain in domain or
                    domain.endswith("." + self.base_domain.split(".", 1)[-1])
                )
            else:
                return (
                    domain == self.base_domain or
                    domain.endswith("." + self.base_domain)
                )
        except Exception:
            return False
    
    async def _discover_apis(self) -> None:
        """Discover API endpoints from crawled URLs."""
        for url in self.discovered_urls:
            for pattern in self.API_PATTERNS:
                if re.search(pattern, url):
                    if not any(a.get("url") == url for a in self.api_endpoints):
                        api_type = "REST"
                        if "graphql" in url:
                            api_type = "GraphQL"
                        elif "websocket" in url or "/ws" in url:
                            api_type = "WebSocket"
                        elif "grpc" in url:
                            api_type = "gRPC"
                        elif "soap" in url:
                            api_type = "SOAP"
                        
                        self.api_endpoints.append({
                            "url": url,
                            "pattern": pattern,
                            "type": api_type,
                            "source": "url_pattern",
                            "found_at": datetime.now(timezone.utc).isoformat(),
                        })
                    break
    
    async def _scan_sensitive_files(self) -> None:
        """Scan for sensitive files on the target domain."""
        base_url = f"{self.base_scheme}://{self.base_domain}"
        
        sem = asyncio.Semaphore(10)
        
        async def check_file(file_path: str) -> None:
            async with sem:
                url = f"{base_url}/{file_path}"
                try:
                    headers = self._zombie.get_headers(url, domain=self.base_domain)
                    async with aiohttp.ClientSession() as session:
                        async with session.get(
                            url, headers=headers,
                            timeout=aiohttp.ClientTimeout(total=5),
                            ssl=False,
                        ) as resp:
                            if resp.status in [200, 403, 401]:
                                risk = "HIGH"
                                if resp.status in [401, 403]:
                                    risk = "MEDIUM"
                                if file_path in ["robots.txt", "sitemap.xml"]:
                                    risk = "INFO"
                                
                                body = await resp.text() if resp.status == 200 else ""
                                
                                self.sensitive_files_found.append({
                                    "url": url,
                                    "status": resp.status,
                                    "type": file_path,
                                    "risk": risk,
                                    "size": len(body),
                                    "timestamp": datetime.now(timezone.utc).isoformat(),
                                })
                except Exception:
                    pass
        
        tasks = [check_file(f) for f in self.SENSITIVE_FILES[:100]]
        await asyncio.gather(*tasks, return_exceptions=True)
    
    async def _extract_all_params(self) -> None:
        """Extract all unique parameters from crawled URLs and forms."""
        for url in self.discovered_urls:
            parsed = urlparse(url)
            params = parse_qs(parsed.query)
            self.params.update(params.keys())
        
        for form in self.forms:
            self.params.update(form.get("inputs", []))
    
    async def _fingerprint_technologies(self) -> None:
        """Fingerprint technologies from response headers."""
        if not self.discovered_urls:
            return
        
        # Sample first URL for fingerprinting
        sample_url = next(iter(self.discovered_urls))
        sample_data = self.discovered_urls[sample_url]
        headers = sample_data.get("headers", {})
        
        # Server
        server = headers.get("Server", headers.get("server", ""))
        if server:
            self.technologies["Server"] = server
        
        # Powered by
        powered_by = headers.get("X-Powered-By", "")
        if powered_by:
            self.technologies["Powered-By"] = powered_by
        
        # Framework detection from headers
        framework_headers = {
            "X-Drupal-Cache": "Drupal",
            "X-Generator": headers.get("X-Generator", ""),
            "X-Laravel": "Laravel",
            "X-Django-Version": "Django",
        }
        for header, framework in framework_headers.items():
            if header in headers:
                self.technologies["Framework"] = framework
        
        # Detect from cookies
        set_cookie = headers.get("Set-Cookie", "")
        cookie_frameworks = {
            "laravel_session": "Laravel",
            "PHPSESSID": "PHP",
            "JSESSIONID": "Java",
            "ASP.NET_SessionId": "ASP.NET",
            "wordpress_logged_in": "WordPress",
        }
        for cookie, tech in cookie_frameworks.items():
            if cookie in set_cookie:
                self.technologies["Framework"] = tech
    
    def _build_crawl_report(self) -> Dict:
        """Build comprehensive crawl report."""
        duration = round(self.end_time - self.start_time, 2) if self.end_time else 0
        
        return {
            "start_url": self.start_url,
            "base_domain": self.base_domain,
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "duration_seconds": duration,
            "statistics": {
                "pages_crawled": len(self.visited_urls),
                "unique_urls": len(self.discovered_urls),
                "api_endpoints": len(self.api_endpoints),
                "sensitive_files": len(self.sensitive_files_found),
                "forms": len(self.forms),
                "unique_params": len(self.params),
                "errors": self.stats.get("errors", 0),
                "timeouts": self.stats.get("timeouts", 0),
                "honeypot_avoided": self.stats.get("honeypot_avoided", 0),
                "honeypot_detected": self.stats.get("honeypot_detected", 0),
                "findings": len(self.all_findings),
            },
            "api_endpoints": self.api_endpoints,
            "sensitive_files": self.sensitive_files_found,
            "forms": self.forms,
            "params": sorted(list(self.params)),
            "technologies": self.technologies,
            "findings": self.all_findings,
        }


