    def __init__(
        self,
        subdomains: List[str],
        zombie_instance: Optional[Any] = None,
        max_workers: int = 30,
        timeout: int = 15,
        verify_takeover: bool = True,
    ):
        """
        Initialize Subdomain Takeover Engine v50.
        
        Args:
            subdomains: List of subdomains to check
            zombie_instance: Optional shared Zombie for stealth
            max_workers: Max concurrent workers
            timeout: HTTP request timeout
            verify_takeover: Enable actual takeover verification
        """
        self.subdomains = subdomains
        self._zombie = zombie_instance
        self.max_workers = max_workers
        self.timeout = timeout
        self.verify_takeover = verify_takeover
        
        self.vulnerable: List[Dict] = []
        self.checked: Dict[str, Dict] = {}
        self.stats = Counter()
        
        self.session_id = dhash(str(time.time()), 12)
    
    async def scan_all(self) -> Dict:
        """
        Scan all subdomains for takeover vulnerabilities.
        
        Returns:
            Dict with all findings and statistics
        """
        print(f"\n{C.CYAN}{'═'*70}{C.RST}")
        print(f"{C.CYAN}{C.BOLD}  {I.CLOUD} SUBDOMAIN TAKEOVER ENGINE v50 — {len(self.subdomains)} targets {I.CLOUD}{C.RST}")
        print(f"{C.CYAN}{'═'*70}{C.RST}")
        print(f"  {C.WHITE}Services: {C.YELLOW}{len(self.TAKEOVER_SERVICES)}{C.RST} | Workers: {C.YELLOW}{self.max_workers}{C.RST}")
        
        # Phase 1: DNS CNAME Resolution
        print(f"\n  {C.MAGENTA}[PHASE 1] DNS CNAME Resolution{C.RST}")
        cname_map = await self._resolve_cnames()
        cname_subdomains = sum(1 for v in cname_map.values() if v)
        print(f"  {C.GREEN}├─ Subdomains with CNAME: {cname_subdomains}{C.RST}")
        
        # Phase 2: Service Matching
        print(f"\n  {C.MAGENTA}[PHASE 2] Service Fingerprint Matching{C.RST}")
        matched = self._match_services(cname_map)
        print(f"  {C.GREEN}├─ Matched services: {len(matched)}{C.RST}")
        
        # Phase 3: HTTP Error Probe
        print(f"\n  {C.MAGENTA}[PHASE 3] HTTP Error Signature Detection{C.RST}")
        vulnerable = await self._probe_errors(matched)
        self.vulnerable = vulnerable
        print(f"  {C.GREEN}├─ Vulnerable: {len(vulnerable)}{C.RST}")
        
        # Phase 4: Takeover Verification
        if self.verify_takeover and vulnerable:
            print(f"\n  {C.MAGENTA}[PHASE 4] Takeover Verification{C.RST}")
            verified = await self._verify_takeover(vulnerable)
            print(f"  {C.GREEN}├─ Verified takeovers: {len(verified)}{C.RST}")
        
        # Print results
        if self.vulnerable:
            print(f"\n  {C.RED}{C.BOLD}  VULNERABLE SUBDOMAINS:{C.RST}")
            for v in self.vulnerable:
                icon = I.FIRE if v["impact"] == "HIGH" else I.WARN
                print(f"  {C.RED}  {icon} {v['subdomain']} → {v['service_name']} [{v['impact']}] — {v['cname']}{C.RST}")
        
        return self._build_report()
    
    async def _resolve_cnames(self) -> Dict[str, List[str]]:
        """Resolve CNAME records for all subdomains with DNS resolver fallback."""
        cname_map = defaultdict(list)
        
        sem = asyncio.Semaphore(self.max_workers)
        
        async def resolve_one(subdomain: str) -> Tuple[str, List[str]]:
            async with sem:
                cnames = []
                
                # Try DNS resolver first (proper CNAME resolution)
                if DNS_AVAILABLE and dns_resolver:
                    try:
                        loop = asyncio.get_event_loop()
                        answers = await loop.run_in_executor(
                            None,
                            lambda: dns_resolver.resolve(subdomain, 'CNAME')
                        )
                        for rdata in answers:
                            cnames.append(str(rdata.target).rstrip('.'))
                        return subdomain, cnames
                    except Exception:
                        pass
                
                # Fallback to socket
                try:
                    loop = asyncio.get_event_loop()
                    result = await loop.run_in_executor(
                        None,
                        lambda: socket.gethostbyname_ex(subdomain)
                    )
                    if result[1]:
                        cnames = list(result[1])
                except socket.gaierror:
                    pass
                except Exception:
                    pass
                
                return subdomain, cnames
        
        tasks = [resolve_one(sub) for sub in self.subdomains[:10000]]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, tuple) and result[1]:
                subdomain, cnames = result
                cname_map[subdomain] = cnames
        
        return dict(cname_map)
    
    def _match_services(self, cname_map: Dict[str, List[str]]) -> List[Dict]:
        """Match CNAME records against 100+ service fingerprints."""
        matched = []
        
        for subdomain, cnames in cname_map.items():
            for cname in cnames:
                cname_lower = cname.lower().rstrip('.')
                
                for service_id, service_info in self.TAKEOVER_SERVICES.items():
                    for pattern in service_info["cname_patterns"]:
                        if re.search(pattern, cname_lower):
                            matched.append({
                                "subdomain": subdomain,
                                "cname": cname,
                                "service_id": service_id,
                                "service_name": service_id.replace("_", " ").title(),
                                "service_info": service_info,
                                "impact": service_info["impact"],
                                "difficulty": service_info["difficulty"],
                                "service_url": service_info["service_url"],
                                "provider": service_info.get("provider", "Unknown"),
                            })
                            self.stats[service_id] += 1
                            break
        
        return matched
    
    async def _probe_errors(self, matched: List[Dict]) -> List[Dict]:
        """HTTP probe to confirm takeover vulnerability."""
        vulnerable = []
        
        sem = asyncio.Semaphore(self.max_workers)
        
        async def probe_single(match: Dict) -> Optional[Dict]:
            async with sem:
                for protocol in ["https", "http"]:
                    url = f"{protocol}://{match['subdomain']}/"
                    try:
                        async with aiohttp.ClientSession() as session:
                            headers = {}
                            if self._zombie:
                                headers = self._zombie.get_headers(url)
                            
                            async with session.get(
                                url, headers=headers,
                                timeout=aiohttp.ClientTimeout(total=self.timeout),
                                allow_redirects=True, ssl=False,
                            ) as resp:
                                body = await resp.text()
                                status = resp.status
                                service_info = match["service_info"]
                                
                                # Check status code
                                if status in service_info["error_status"]:
                                    # Check error patterns
                                    for pattern in service_info["error_patterns"]:
                                        if re.search(pattern, body, re.IGNORECASE):
                                            return {
                                                **match,
                                                "status": status,
                                                "error_match": pattern,
                                                "body_sample": body[:500],
                                                "confirmed": True,
                                                "protocol": protocol,
                                            }
                    except (asyncio.TimeoutError, Exception):
                        continue
                return None
        
        tasks = [probe_single(m) for m in matched]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for r in results:
            if r and isinstance(r, dict) and r.get("confirmed"):
                vulnerable.append(r)
        
        return vulnerable
    
    async def _verify_takeover(self, vulnerable: List[Dict]) -> List[Dict]:
        """Verify actual takeover possibility."""
        verified = []
        
        for v in vulnerable:
            service_id = v.get("service_id", "")
            service_info = self.TAKEOVER_SERVICES.get(service_id, {})
            
            # Check if service still allows claiming
            if service_info.get("difficulty") == "EASY":
                v["takeover_verified"] = True
                v["poc"] = f"Register the {service_info.get('provider', '')} service at {service_info.get('service_url', '')}"
                v["impact_detail"] = (
                    f"Subdomain {v['subdomain']} is pointing to an unclaimed "
                    f"{service_info.get('provider', '')} {v['service_name']} service. "
                    f"An attacker can claim this service and host malicious content, "
                    f"potentially leading to phishing, cookie theft, or full account takeover."
                )
                verified.append(v)
        
        return verified
    
    def _build_report(self) -> Dict:
        """Build comprehensive takeover report."""
        return {
            "session_id": self.session_id,
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "total_scanned": len(self.subdomains),
            "total_vulnerable": len(self.vulnerable),
            "vulnerable_subdomains": self.vulnerable,
            "by_impact": {
                "HIGH": [v for v in self.vulnerable if v["impact"] == "HIGH"],
                "MEDIUM": [v for v in self.vulnerable if v["impact"] == "MEDIUM"],
                "LOW": [v for v in self.vulnerable if v["impact"] == "LOW"],
            },
            "by_provider": dict(Counter(v.get("provider", "Unknown") for v in self.vulnerable)),
            "service_stats": dict(self.stats),
        }


