# PAYLOAD MEMORY v50 — Cross-Target Learning System
# ═══════════════════════════════════════════════════════════════

class PayloadMemory:
    """
    🧠 PAYLOAD MEMORY v50 — Cross-target learning system.
    
    Menyimpan payload yang berhasil dari target sebelumnya,
    digunakan untuk mempercepat discovery di target baru yang mirip.
    
    Features:
    - JSON persistence with auto-save
    - Technology stack-based retrieval
    - WAF-aware payload selection
    - Success rate tracking
    - Similar target matching
    - Payload aging (decay old payloads)
    
    Connected to: ZombieDatabase, SmartPayloadFactory, ZombieGenesisEngine
    """
    
    def __init__(
        self,
        memory_file: str = "./zombie_data/payload_memory.json",
        database: Optional[ZombieDatabase] = None,
        max_memory_size: int = 10000,
    ):
        """
        Initialize Payload Memory v50.
        
        Args:
            memory_file: Path to JSON memory file
            database: Optional ZombieDatabase instance
            max_memory_size: Maximum payloads to store
        """
        self.memory_file = Path(memory_file)
        self.memory_file.parent.mkdir(parents=True, exist_ok=True)
        self.db = database
        self.max_memory_size = max_memory_size
        
        self.memory: Dict[str, List[Dict]] = defaultdict(list)
        self._load()
    
    def _load(self) -> None:
        """Load payload memory from disk."""
        if self.memory_file.exists():
            try:
                with open(self.memory_file) as f:
                    data = json.load(f)
                    self.memory = defaultdict(list, data)
            except Exception:
                pass
    
    def save(self) -> None:
        """Save payload memory to disk."""
        with open(self.memory_file, "w") as f:
            json.dump(dict(self.memory), f, default=str, indent=2)
    
    def add_success(
        self, vuln_type: str, tech_stack: str, payload: Dict,
        waf_type: str = "",
    ) -> None:
        """
        Record a successful payload with technology context.
        
        Args:
            vuln_type: Vulnerability type
            tech_stack: Technology stack string
            payload: Payload dictionary
            waf_type: WAF type if any
        """
        key = f"{vuln_type}:{tech_stack}"
        if waf_type:
            key += f":{waf_type}"
        
        entry = {
            **payload,
            "recorded_at": datetime.now(timezone.utc).isoformat(),
            "success_count": 1,
        }
        
        # Check for duplicate
        for existing in self.memory[key]:
            if existing.get("payload") == payload.get("payload"):
                existing["success_count"] = existing.get("success_count", 0) + 1
                existing["recorded_at"] = datetime.now(timezone.utc).isoformat()
                self.save()
                return
        
        self.memory[key].append(entry)
        
        # Trim if too large
        if len(self.memory[key]) > self.max_memory_size:
            self.memory[key] = self.memory[key][-self.max_memory_size:]
        
        # Save to database
        if self.db:
            try:
                self.db.add_payload(
                    vuln_type=vuln_type,
                    tech_stack=tech_stack,
                    payload=payload.get("payload", ""),
                    method=payload.get("method", ""),
                    fitness=payload.get("fitness", 0.0),
                    waf_name=waf_type,
                )
            except Exception:
                pass
        
        self.save()
    
    def get_for_tech(
        self, vuln_type: str, tech_stack: str,
        waf_type: str = "", limit: int = 50,
    ) -> List[Dict]:
        """
        Retrieve successful payloads for a specific technology stack.
        
        Args:
            vuln_type: Vulnerability type
            tech_stack: Technology stack string
            waf_type: WAF type if any
            limit: Maximum results
            
        Returns:
            List of payload dictionaries sorted by success
        """
        # Exact match
        key = f"{vuln_type}:{tech_stack}"
        if waf_type:
            key += f":{waf_type}"
        exact = self.memory.get(key, [])
        
        # Partial match
        partial = []
        for mem_key, payloads in self.memory.items():
            if mem_key.startswith(f"{vuln_type}:") and mem_key != key:
                mem_tech = mem_key.split(":", 1)[1]
                if any(t in tech_stack for t in mem_tech.split(",")):
                    partial.extend(payloads)
        
        # Combine and sort by success count
        combined = exact + partial
        combined.sort(
            key=lambda x: (
                x.get("success_count", 0),
                x.get("confidence", x.get("fitness", 0))
            ),
            reverse=True
        )
        
        return combined[:limit]
    
    def find_similar_targets(self, tech_stack: str, threshold: float = 0.5) -> List[str]:
        """
        Find similar technology stacks from memory.
        
        Args:
            tech_stack: Current target technology stack
            threshold: Similarity threshold
            
        Returns:
            List of similar tech stacks
        """
        similar = []
        current_techs = set(tech_stack.lower().split(","))
        
        for key in self.memory.keys():
            parts = key.split(":")
            if len(parts) >= 2:
                mem_techs = set(parts[1].lower().split(","))
                if current_techs and mem_techs:
                    intersection = current_techs & mem_techs
                    union = current_techs | mem_techs
                    similarity = len(intersection) / len(union) if union else 0
                    if similarity >= threshold:
                        similar.append(parts[1])
        
        return list(set(similar))
    
    def get_stats(self) -> Dict:
        """Return payload memory statistics."""
        total_payloads = sum(len(v) for v in self.memory.values())
        unique_types = len(set(k.split(":")[0] for k in self.memory.keys()))
        
        return {
            "total_entries": len(self.memory),
            "total_payloads": total_payloads,
            "unique_vuln_types": unique_types,
            "memory_file": str(self.memory_file),
            "max_size": self.max_memory_size,
        }
    
    def clear(self) -> None:
        """Clear all memory."""
        self.memory.clear()
        self.save()


