    def __init__(self) -> None:
        """Initialize Scanner Registry v50."""
        self._scanners: Dict[str, Callable] = {}
        self._categories: Dict[str, List[str]] = defaultdict(list)
        self._enabled: Dict[str, bool] = {}
        self._engine_stats: Dict[str, Dict] = {}
        self.stats = Counter()
    
    def register(self, name: str, category: str, scanner_func: Callable) -> None:
        """Register a scanner engine."""
        self._scanners[name] = scanner_func
        self._categories[category].append(name)
        self._enabled[name] = True
        self._engine_stats[name] = {
            "runs": 0, "findings": 0, "errors": 0,
            "avg_time_ms": 0, "registered_at": datetime.now(timezone.utc).isoformat(),
        }
        self.stats["registered"] += 1
    
    def enable(self, name: str) -> None:
        self._enabled[name] = True
    
    def disable(self, name: str) -> None:
        self._enabled[name] = False
    
    def enable_category(self, category: str) -> None:
        for name in self._categories.get(category, []):
            self._enabled[name] = True
    
    def disable_category(self, category: str) -> None:
        for name in self._categories.get(category, []):
            self._enabled[name] = False
    
    def get_enabled(self) -> Dict[str, List[str]]:
        """Get all enabled scanners by category."""
        result = {}
        for category, scanners in self._categories.items():
            enabled = [s for s in scanners if self._enabled.get(s, True)]
            if enabled:
                result[category] = enabled
        return result
    
    def get_all(self) -> Dict[str, List[str]]:
        """Get all registered scanners."""
        return dict(self._categories)
    
    def count_enabled(self) -> int:
        """Count enabled scanners."""
        return sum(1 for v in self._enabled.values() if v)
    
    def count_total(self) -> int:
        """Count total registered scanners."""
        return len(self._scanners)
    
    def record_run(self, name: str, findings: int = 0, time_ms: float = 0, error: bool = False) -> None:
        """Record scanner run statistics."""
        if name in self._engine_stats:
            stats = self._engine_stats[name]
            stats["runs"] += 1
            stats["findings"] += findings
            if error:
                stats["errors"] += 1
            if stats["avg_time_ms"] == 0:
                stats["avg_time_ms"] = time_ms
            else:
                stats["avg_time_ms"] = (stats["avg_time_ms"] * (stats["runs"] - 1) + time_ms) / stats["runs"]
    
    def get_stats(self) -> Dict:
        """Return scanner registry statistics."""
        return {
            "total_scanners": self.count_total(),
            "enabled_scanners": self.count_enabled(),
            "categories": len(self._categories),
            "registered": self.stats.get("registered", 0),
            "total_runs": sum(s["runs"] for s in self._engine_stats.values()),
            "total_findings": sum(s["findings"] for s in self._engine_stats.values()),
        }


