    def __init__(self, config: Optional[Any] = None):
        """
        Initialize Wormhole v50.
        
        Args:
            config: Optional configuration object
        """
        self.config = config
        self.discovered_targets: Set[str] = set()
        self.internal_network: Dict[str, List[int]] = defaultdict(list)
        self.pivot_history: List[Dict] = []
        self.wormhole_count: int = 0
        self.active_pivots: List[Dict] = []
    
    def feed_finding(self, finding: Dict) -> List[str]:
        """
        🔴 FIX #11: Feed vulnerability finding to discover new pivot targets.
        Called by CloudMetadataExfiltrator and other modules.
        
        Args:
            finding: Vulnerability finding dictionary
            
        Returns:
            List of newly discovered target URLs
        """
        vuln_type = finding.get('vuln_type', '').lower()
        url = finding.get('url', '')
        new_targets: List[str] = []
        
        # SSRF → Internal Network
        if 'ssrf' in vuln_type:
            internal_ips = [
                '127.0.0.1', '10.0.0.1', '10.0.0.2', '10.0.0.254',
                '172.16.0.1', '172.16.0.254',
                '192.168.0.1', '192.168.1.1', '192.168.1.254',
                '169.254.169.254', '100.100.100.200',
            ]
            for ip in internal_ips:
                for port in [22, 80, 443, 8080, 8443, 3000, 3306, 5432, 6379, 9200, 27017, 5000, 8000, 9090]:
                    target = f"http://{ip}:{port}"
                    new_targets.append(target)
                    self.internal_network[ip].append(port)
            
            self.discovered_targets.update(new_targets)
            self.pivot_history.append({
                'type': 'ssrf_to_internal',
                'source_url': url,
                'targets_count': len(new_targets),
                'timestamp': datetime.now(timezone.utc).isoformat(),
            })
            self.wormhole_count += 1
        
        # IDOR → Cross-Tenant
        elif 'idor' in vuln_type:
            id_patterns = re.findall(r'(?:id|user|org|tenant|account|customer)[=_-](\d+)', url)
            for match in id_patterns:
                try:
                    id_num = int(match)
                    for offset in [1, 2, 3, -1, -2, -3, 100, 1000, 10000]:
                        new_url = re.sub(
                            re.escape(match), str(id_num + offset), url, count=1,
                        )
                        new_targets.append(new_url)
                except ValueError:
                    pass
            
            self.discovered_targets.update(new_targets)
            self.pivot_history.append({
                'type': 'idor_cross_tenant',
                'source_url': url,
                'targets_count': len(new_targets),
                'timestamp': datetime.now(timezone.utc).isoformat(),
            })
            self.wormhole_count += 1
        
        # Cloud Credentials → Resource Enumeration
        elif 'cloud' in str(finding.get('evidence', '')).lower() or 'credentials' in vuln_type:
            cloud_targets = [
                # AWS
                's3.amazonaws.com', 'ec2.amazonaws.com', 'lambda.amazonaws.com',
                'rds.amazonaws.com', 'dynamodb.amazonaws.com',
                # GCP
                'storage.googleapis.com', 'compute.googleapis.com',
                'cloudfunctions.googleapis.com',
                # Azure
                'management.azure.com', 'database.windows.net',
                'vault.azure.net',
            ]
            for target in cloud_targets:
                new_targets.append(f"https://{target}")
            
            self.discovered_targets.update(new_targets)
            self.pivot_history.append({
                'type': 'cloud_to_all_resources',
                'source_url': url,
                'targets_count': len(new_targets),
                'timestamp': datetime.now(timezone.utc).isoformat(),
            })
            self.wormhole_count += 1
        
        # LFI → Log Poisoning Targets
        elif 'lfi' in vuln_type or 'path traversal' in vuln_type:
            log_targets = self.PIVOT_TECHNIQUES['lfi_to_rce']['log_paths']
            for log_path in log_targets:
                new_targets.append(f"file://{log_path}")
            
            self.discovered_targets.update(new_targets)
            self.pivot_history.append({
                'type': 'lfi_to_rce',
                'source_url': url,
                'targets_count': len(new_targets),
                'timestamp': datetime.now(timezone.utc).isoformat(),
            })
            self.wormhole_count += 1
        
        return new_targets
    
    def suggest_pivots(self, findings: List[Dict]) -> List[Dict]:
        """
        Analyze all findings and suggest possible pivot techniques.
        
        Args:
            findings: List of all vulnerability findings
            
        Returns:
            List of suggested pivot actions
        """
        suggestions = []
        
        vuln_types = [f.get('vuln_type', '').lower() for f in findings]
        
        for technique_name, technique_info in self.PIVOT_TECHNIQUES.items():
            trigger = technique_info['trigger'].lower()
            
            # Check if any finding matches the trigger
            matched = False
            for vt in vuln_types:
                if any(kw in vt for kw in trigger.split()):
                    matched = True
                    break
            
            if matched:
                suggestions.append({
                    'technique': technique_name,
                    'action': technique_info['action'],
                    'impact': technique_info['impact'],
                    'trigger_found': True,
                })
        
        return suggestions
    
    def get_internal_network_map(self) -> Dict[str, List[int]]:
        """Get discovered internal network map."""
        return dict(self.internal_network)
    
    def get_stats(self) -> Dict:
        """Return wormhole pivot statistics."""
        return {
            'wormhole_count': self.wormhole_count,
            'discovered_targets': len(self.discovered_targets),
            'internal_hosts': len(self.internal_network),
            'internal_ports': sum(len(ports) for ports in self.internal_network.values()),
            'pivot_history': [
                {
                    'type': p.get('type', 'unknown'),
                    'source_url': p.get('source_url', '')[:80],
                    'targets_count': p.get('targets_count', 0),
                    'timestamp': p.get('timestamp', ''),
                }
                for p in self.pivot_history[-10:]
            ],
            'available_techniques': len(self.PIVOT_TECHNIQUES),
        }


