    def __init__(self) -> None:
        """Initialize TLS Fingerprint Rotator v50."""
        self.current_profile: Optional[Dict] = None
        self.rotation_count: int = 0
        self.profile_history: List[str] = []
        self.rotate()
    
    def rotate(self) -> Dict:
        """
        Rotate to a new TLS fingerprint profile.
        
        Returns:
            Current TLS profile dict
        """
        profile_name = random.choice(list(self.TLS_PROFILES.keys()))
        self.current_profile = self.TLS_PROFILES[profile_name].copy()
        self.current_profile["name"] = profile_name
        self.rotation_count += 1
        self.profile_history.append(profile_name)
        return self.current_profile
    
    def get_ja4(self) -> str:
        """Return current JA4 fingerprint hash."""
        if not self.current_profile:
            self.rotate()
        return self.current_profile.get("ja4", "unknown")
    
    def get_ciphers(self) -> List[str]:
        """Return current cipher suite list."""
        if not self.current_profile:
            self.rotate()
        return self.current_profile.get("ciphers", [])
    
    def get_alpn(self) -> List[str]:
        """Return current ALPN protocols."""
        if not self.current_profile:
            self.rotate()
        return self.current_profile.get("alpn", ["http/1.1"])
    
    def get_supported_groups(self) -> List[str]:
        """Return current supported ECDHE groups."""
        if not self.current_profile:
            self.rotate()
        return self.current_profile.get("supported_groups", ["x25519", "secp256r1"])
    
    def get_ssl_context(self) -> ssl.SSLContext:
        """
        Create SSL context with current fingerprint settings.
        
        Returns:
            Configured SSL context
        """
        context = ssl.create_default_context()
        
        # Set ciphers
        ciphers = self.get_ciphers()
        cipher_string = ":".join(ciphers)
        try:
            context.set_ciphers(cipher_string)
        except Exception:
            pass
        
        # Set ALPN
        alpn = self.get_alpn()
        try:
            context.set_alpn_protocols(alpn)
        except Exception:
            pass
        
        return context
    
    def get_stats(self) -> Dict:
        """Return TLS rotator statistics."""
        return {
            "rotation_count": self.rotation_count,
            "current_ja4": self.get_ja4(),
            "current_profile": self.current_profile.get("name", "unknown") if self.current_profile else "none",
            "available_profiles": len(self.TLS_PROFILES),
            "profile_history": self.profile_history[-10:],
        }


