            {'name': 'unicode_encode', 'apply': lambda p: ''.join(f'\\u{ord(c):04x}' for c in p)},
            {'name': 'base64_wrap', 'apply': lambda p: f'eval(atob("{base64.b64encode(p.encode()).decode()}"))'},
