    def __init__(self):
        """🤖 Initialize AI Payload Generator v50"""
        self.generated_count: int = 0
        self.successful_payloads: List[Dict] = []
        self.waf_specific_rules: Dict[str, List[str]] = {
            'cloudflare': ['case_variation', 'comment_injection', 'url_encode'],
            'akamai': ['newline_bypass', 'null_byte', 'double_encode'],
            'imperva': ['tab_bypass', 'hex_encode', 'float_bypass'],
            'f5': ['parenthesis_bypass', 'like_bypass', 'between_bypass'],
            'modsecurity': ['case_variation', 'comment_injection', 'whitespace_bypass'],
        }
    
    def generate(
        self,
        vuln_type: str,
        base_payload: str,
        count: int = 10,
        waf: Optional[str] = None,
        max_length: int = 1000,
    ) -> List[str]:
        """
        🤖 Generate intelligent payload variations
        
        Args:
            vuln_type: Vulnerability type (xss, sqli, lfi, cmdi, ssti)
            base_payload: Base payload to mutate
            count: Number of variations to generate
            waf: Detected WAF (for adaptive bypass)
            max_length: Maximum payload length
            
        Returns:
            List of generated payloads
        """
        payloads: List[str] = []
        
        rules = self.MUTATION_RULES.get(vuln_type.lower(), [])
        if not rules:
            return [base_payload]
        
        # Filter rules based on WAF
        if waf:
            waf_lower = waf.lower()
            preferred_rules = []
            for waf_name, rule_names in self.waf_specific_rules.items():
                if waf_name in waf_lower:
                    preferred_rules = [r for r in rules if r['name'] in rule_names]
                    break
            if preferred_rules:
                rules = preferred_rules + rules  # Prefer WAF-specific rules first
        
        # Generate variations
        for _ in range(count * 2):  # Generate extra, deduplicate later
            payload = base_payload
            
            # Apply 1-3 random mutations
            num_mutations = random.randint(1, min(3, len(rules)))
            selected_rules = random.sample(rules, num_mutations)
            
            for rule in selected_rules:
                try:
                    payload = rule['apply'](payload)
                except Exception:
                    pass
            
            # Validate
            if payload and payload != base_payload and len(payload) <= max_length:
                payloads.append(payload)
                self.generated_count += 1
            
            if len(set(payloads)) >= count:
                break
        
        return list(set(payloads))[:count]
    
    def generate_chain(
        self,
        vuln_types: List[str],
        base_payloads: List[str],
        count_per_type: int = 5,
    ) -> Dict[str, List[str]]:
        """
        Generate payloads for multiple vulnerability types.
        
        Args:
            vuln_types: List of vulnerability types
            base_payloads: Corresponding base payloads
            count_per_type: Payloads per type
            
        Returns:
            Dict of vuln_type → list of payloads
        """
        result = {}
        
        for vuln_type, base_payload in zip(vuln_types, base_payloads):
            payloads = self.generate(vuln_type, base_payload, count_per_type)
            result[vuln_type] = payloads
        
        return result
    
    def learn_success(self, payload: str, vuln_type: str, context: Dict):
        """🧠 Learn from successful payload"""
        self.successful_payloads.append({
            'payload': payload,
            'vuln_type': vuln_type,
            'context': context,
            'timestamp': datetime.now(timezone.utc).isoformat(),
            'length': len(payload),
        })
        
        # Keep only last 200 successful payloads
        if len(self.successful_payloads) > 200:
            self.successful_payloads = self.successful_payloads[-200:]
    
    def get_best_payload(self, vuln_type: str, prefer_short: bool = True) -> Optional[str]:
        """🏆 Get best historically successful payload"""
        matching = [
            p for p in self.successful_payloads
            if p['vuln_type'] == vuln_type
        ]
        if matching:
            if prefer_short:
                matching.sort(key=lambda x: x.get('length', 999))
            return matching[-1]['payload']
        return None
    
    def get_stats(self) -> Dict:
        """📊 Get AI payload generator statistics"""
        return {
            'total_generated': self.generated_count,
            'successful_payloads': len(self.successful_payloads),
            'mutation_rules': {
                k: len(v) for k, v in self.MUTATION_RULES.items()
            },
            'waf_rules': {
                k: len(v) for k, v in self.waf_specific_rules.items()
            },
        }


