async def scan_sensitive_files(
    session: Any,
    domain: str,
    db: Any = None,
    max_checks: int = 200,
) -> List[Dict]:
    """
    📁 Scan for sensitive/exposed files on target domain
    
    Args:
        session: HTTP session manager
        domain: Target domain
        db: Database instance for saving findings
        max_checks: Maximum paths to check
        
    Returns:
        List of findings
    """
    findings: List[Dict] = []
    
    print(f"\n{C.CYAN}{'═'*60}{C.RST}")
    print(f"{C.CYAN}  {I.FILE} SENSITIVE FILES SCANNER v50{C.RST}")
    print(f"{C.CYAN}  {I.FILE} {len(SENSITIVE_PATHS)} paths available, checking {min(max_checks, len(SENSITIVE_PATHS))}{C.RST}")
    print(f"{C.CYAN}{'═'*60}{C.RST}")
    
    checked = 0
    found = 0
    
    fp_indicators = [
        'not found', '404 not found', 'error 404',
        'page not found', 'file not found',
        '403 forbidden', 'access denied', 'forbidden',
        '500 internal server error', 'server error',
        'under maintenance', 'under construction',
        'cloudflare', 'cf-ray', 'cf-cache-status',
        'captcha', 'recaptcha', 'hcaptcha',
        'rate limit', 'too many requests',
        'blocked', 'ip blocked', 'banned',
        'welcome to nginx', 'welcome to apache',
        'default web site page',
    ]
    
    critical_keywords = [
        'private_key', 'private key',
        '-----begin rsa private key-----',
        '-----begin openssh private key-----',
        'client_secret', 'secret_key',
        'password', 'passwd',
        'api_key', 'api secret',
        'access_key', 'access token',
        'aws_access_key_id', 'aws_secret_access_key',
        'sk_live_', 'sk_test_',
        'connection_string', 'mongodb://',
        'mysql://', 'postgresql://', 'redis://',
        'github_token', 'ghp_',
        'gitlab_token', 'glpat-',
        'APP_KEY', 'APP_SECRET',
        'DATABASE_URL', 'DATABASE_PASSWORD',
        'JWT_SECRET', 'ENCRYPTION_KEY',
    ]
    
    sem = asyncio.Semaphore(20)
    
    async def check_path(path: str) -> Optional[Dict]:
        async with sem:
            url = f"https://{domain}/{path}"
            
            try:
                resp = await session.fetch(url, timeout=5)
                
                if resp.get('status') == 200 and resp.get('size', 0) > 50:
                    text = (resp.get('text', '') or '').lower()
                    
                    if any(k in text for k in fp_indicators):
                        return None
                    
                    # Determine severity
                    sev = 'INFO'
                    
                    if any(k in text for k in critical_keywords):
                        sev = 'CRITICAL'
                    elif path.startswith('.git/'):
                        sev = 'HIGH'
                    elif 'admin' in path.lower():
                        sev = 'MEDIUM'
                    elif 'backup' in path.lower() or 'dump' in path.lower():
                        sev = 'HIGH'
                    
                    return {
                        'id': str(uuid.uuid4())[:12],
                        'target': domain,
                        'url': url,
                        'vuln_type': 'Sensitive File/Endpoint',
                        'severity': sev,
                        'param': path,
                        'evidence': (resp.get('text', '') or '')[:300].strip(),
                        'confidence': 85,
                        'method': 'sensitive_file',
                        'waf': resp.get('waf'),
                        'full_url': url,
                        'timestamp': datetime.now(timezone.utc).isoformat(),
                        'response_length': resp.get('size', 0),
                        'engine_name': f'{I.FILE} Sensitive File Scanner v50',
                    }
            
            except Exception:
                pass
            
            return None
    
    tasks = [check_path(p) for p in SENSITIVE_PATHS[:max_checks]]
    results = await asyncio.gather(*tasks, return_exceptions=True)
    
    for result in results:
        checked += 1
        if isinstance(result, dict) and result:
            found += 1
            findings.append(result)
            
            if db:
                try:
                    db.save_finding(result)
                except Exception:
                    pass
            
            icon = {
                'CRITICAL': f'{C.RED}🔴', 'HIGH': f'{C.YELLOW}🟡',
                'MEDIUM': f'{C.BLUE}🔵', 'LOW': f'{C.WHITE}⚪',
            }.get(result['severity'], f'{C.WHITE}⚪')
            
            print(f"  {C.GREEN}[{icon} {result['severity']:8s}] {result['url']}{C.RST}")
    
    print(f"\n  {C.GREEN}Checked: {checked} | Found: {found}{C.RST}")
    
    return findings


