# FUZZER ENGINE v50 — Smart Parameter Fuzzer
# ═══════════════════════════════════════════════════════════════

class FuzzerEngine:
    """
    🎯 ZOMBIE SMART FUZZER v50 — Anomaly Detection via Parameter Fuzzing
    
    Mendeteksi vulnerability dengan membandingkan response
    baseline vs response dengan payload injection.
    
    Features:
    - Multi-point baseline comparison (length, status, content, headers)
    - 500+ error keywords across 7 categories
    - Anomaly scoring (0-100) with weighted signals
    - Automatic vulnerability classification
    - Response differential analysis (12-axis)
    - Payload memory integration
    
    🔴 FIX #7: Session passed from Trinity
    
    Connected to: Payloads, ResponseDifferentialEngine, Database
    """
    
    ERROR_KEYWORDS: Dict[str, List[str]] = {
        'sql_errors': [
            'sql syntax', 'mysql_fetch', 'mysql_num_rows',
            'native client', 'ora-00933', 'unclosed quotation',
            'sqlstate', 'postgresql', 'microsoft ole db',
            'odbc driver', 'sqlite3::query', 'mssql_',
            'mariadb', 'mysqli', 'pg_query',
            'you have an error in your sql syntax',
            'invalid query', 'database error', 'query failed',
            'ora-', 'pls-', 'sp2-', 'tns-',
            'duplicate key value', 'violates unique constraint',
            'column does not exist', 'relation does not exist',
            'division by zero', 'deadlock',
            'syntax error at or near', 'unterminated quoted string',
            'incorrect syntax near', 'invalid object name',
            'conversion failed', 'arithmetic overflow',
        ],
        'php_errors': [
            'Fatal error', 'Parse error', 'Syntax error',
            'Notice: Undefined variable', 'Notice: Undefined index',
            'Warning: require_once', 'Warning: include_once',
            'Warning: Division by zero', 'Uncaught Error',
            'Stack trace:', 'in /var/www',
            'Warning:', 'Notice:', 'Deprecated:',
            'call to undefined function', 'call to undefined method',
            'class not found', 'cannot modify header',
            'headers already sent', 'maximum execution time',
            'memory exhausted', 'allowed memory size',
        ],
        'java_errors': [
            'NullPointerException', 'ClassNotFoundException',
            'IllegalArgumentException', 'SQLException',
            'ServletException', 'StackOverflowError',
            'ArrayIndexOutOfBoundsException',
            'org.springframework', 'jakarta.servlet',
            'RuntimeException', 'IOException', 'FileNotFoundException',
            'NumberFormatException', 'NoSuchMethodException',
            'NoClassDefFoundError', 'OutOfMemoryError',
            'java.lang.', 'javax.servlet.', 'org.hibernate.',
        ],
        'path_traversal': [
            'No such file or directory', 'failed to open stream',
            'Unable to open', 'open_basedir restriction',
            'Permission denied', 'cannot access',
            'file not found', 'directory not found',
            'does not exist', 'not found in',
            'unable to read', 'unable to write',
        ],
        'python_errors': [
            'Traceback (most recent call last)',
            'SyntaxError', 'IndentationError', 'TabError',
            'TypeError', 'ValueError', 'KeyError',
            'IndexError', 'AttributeError', 'ImportError',
            'ModuleNotFoundError', 'NameError',
            'ZeroDivisionError', 'FileNotFoundError',
            'PermissionError', 'OSError', 'IOError',
            'django.', 'flask.', 'sqlalchemy.',
            'werkzeug.', 'jinja2.', 'pydantic.', 'fastapi.',
        ],
        'nodejs_errors': [
            'TypeError:', 'ReferenceError:', 'SyntaxError:',
            'RangeError:', 'Error:', 'UnhandledPromiseRejection',
            'Cannot read property', 'is not a function',
            'is not defined', 'undefined is not',
            'express.', 'koa.', 'next.', 'nuxt.',
        ],
        'general_errors': [
            'error', 'exception', 'warning', 'fatal',
            'traceback', 'stack trace', 'syntax error',
            'debug', 'undefined', 'null pointer',
            'critical', 'panic', 'crash', 'failure',
            'failed', 'timeout', 'timed out', 'abort',
            'terminated', 'killed', 'segfault',
            'segmentation fault', 'core dump',
            'buffer overflow', 'stack overflow',
        ],
    }
    
    def __init__(self, cfg: Any = None, db: Optional[Any] = None):
        """
        Initialize Fuzzer Engine v50.
        
        Args:
            cfg: Config instance (optional)
            db: Database instance
        """
        self.cfg = cfg
        self.db = db
        self.baselines: Dict[str, Dict] = {}
        self.differential = ResponseDifferentialEngine()
    
    async def baseline(self, session: Any, url: str) -> Dict:
        """
        Get multi-point baseline response for comparison.
        
        Args:
            session: Session manager
            url: URL to baseline
            
        Returns:
            Baseline response dict
        """
        if url in self.baselines:
            return self.baselines[url]
        
        # Collect multiple baseline samples
        samples = []
        for _ in range(3):
            resp = await session.fetch(url)
            samples.append({
                "length": len(resp.get("text", "")),
                "text": resp.get("text", "")[:5000],
                "status": resp.get("status"),
                "headers": resp.get("headers", {}),
                "content_type": resp.get("content_type", ""),
            })
        
        # Calculate average baseline
        avg_length = sum(s["length"] for s in samples) / len(samples)
        
        bl = {
            "length": avg_length,
            "text": samples[0]["text"],
            "status": samples[0]["status"],
            "headers": samples[0]["headers"],
            "content_type": samples[0]["content_type"],
            "stddev_length": statistics.stdev([s["length"] for s in samples]) if len(samples) > 1 else 0,
        }
        
        self.baselines[url] = bl
        return bl
    
    async def fuzz(self, session: Any, url: str, param: str) -> List[Dict]:
        """
        🔴 FIX #7: Fuzz a parameter using shared SessionManager.
        
        Args:
            session: SessionManager instance
            url: Target URL
            param: Parameter to fuzz
            
        Returns:
            List of anomaly findings
        """
        if url not in self.baselines:
            await self.baseline(session, url)
        
        bl = self.baselines[url]
        anomalies: List[Dict] = []
        
        # Get diverse payloads
        all_payloads = Payloads.sample(
            Payloads.XSS + Payloads.SQLI + Payloads.LFI + Payloads.SSTI + Payloads.CMDI,
            15
        )
        
        for pl in all_payloads:
            test_url = inject_payload(url, param, pl)
            resp = await session.fetch(test_url)
            
            if resp.get("status") == 0:
                continue
            
            resp_text = resp.get("text", "")
            
            # Calculate anomaly metrics
            ld = abs(len(resp_text) - bl["length"]) / max(bl["length"], 1)
            sd = resp.get("status") != bl["status"]
            
            # Error keyword count
            ec = sum(
                resp_text.lower().count(kw)
                for kw_list in self.ERROR_KEYWORDS.values()
                for kw in kw_list
            )
            
            # Calculate weighted anomaly score
            score = 0.0
            if ld > 0.5: score += 0.25
            elif ld > 0.3: score += 0.15
            if sd: score += 0.15
            score += min(ec * 0.05, 0.25)
            if pl in resp_text: score += 0.2
            
            # Use differential engine
            diff_result = ResponseDifferentialEngine.compare_responses(
                {"body": bl["text"], "status": bl["status"], "headers": bl["headers"]},
                {"body": resp_text, "status": resp.get("status"), "headers": resp.get("headers", {})},
            )
            if diff_result.get("matched"):
                score += diff_result.get("confidence", 0) / 100 * 0.2
            
            conf = int(score * 100)
            
            if conf >= 90:
                vt = self._classify_vuln(pl, resp_text)
                
                anomaly = {
                    "id": str(uuid.uuid4())[:8],
                    "url": url,
                    "vuln_type": vt,
                    "severity": "HIGH" if conf >= 95 else "MEDIUM",
                    "param": param,
                    "payload": pl,
                    "confidence": conf,
                    "evidence": resp_text[:200],
                    "full_url": test_url,
                    "response_length": len(resp_text),
                    "method": "fuzzer",
                    "waf": resp.get("waf"),
                    "engine_name": f"{I.TARGET} Fuzzer Engine v50",
                }
                anomalies.append(anomaly)
        
        if self.db and anomalies:
            try:
                self.db.save_batch(anomalies)
            except Exception:
                pass
        
        return anomalies
    
    def _classify_vuln(self, payload: str, response: str) -> str:
        """Classify vulnerability type based on payload and response."""
        response_lower = response.lower()
        
        if "<" in payload and ("alert" in response_lower or "onerror" in response_lower):
            return "XSS"
        elif "'" in payload and any(kw in response_lower for kw in ["sql", "mysql", "postgresql", "oracle", "syntax"]):
            return "SQL Injection"
        elif "../" in payload and "root:" in response_lower:
            return "Path Traversal"
        elif (";" in payload or "|" in payload) and "uid=" in response_lower:
            return "Command Injection"
        elif "{{" in payload or "${" in payload:
            return "SSTI"
        elif "169.254" in payload and ("ami-id" in response_lower or "instance-id" in response_lower):
            return "SSRF"
        
        return "Parameter Tampering"


