    def get_stealth_headers(self, url: str = "", mode: str = "browser") -> Dict[str, str]:
        """Get stealth headers from multiple engines based on mode."""
        if mode == "bot":
            return self.mimicry.get_headers(url)
        elif mode == "random":
            return self.shapeshifter.morph()
        elif mode == "tls":
            self.tls_rotator.rotate()
            return self.zombie.get_headers(url)
        elif mode == "blood":
            self.blood_identity.rotate()
            return self.blood_identity.get_headers()
        else:
            self.tls_rotator.rotate()
            return self.zombie.get_headers(url)
    
