    def __init__(self, db: Optional[Any] = None):
        """
        Initialize DNA Cloner v50.
        
        Args:
            db: Optional database instance for persistence
        """
        self.clone_pool: List[Dict] = []
        self.arp_cache: Dict[str, Dict] = {}
        self.device_history: Dict[str, List[Dict]] = defaultdict(list)
        self.network_topology: Dict[str, List[str]] = defaultdict(list)
        self._scan_stats = {"probes": 0, "hits": 0, "misses": 0, "spoofs": 0}
        self.db = db
        self._init_arp_cache()
    
    def _init_arp_cache(self):
        """Initialize ARP cache with common network devices."""
        common = [
            ("192.168.1.1", "Cisco", False), ("192.168.1.2", "Dell", False),
            ("192.168.1.10", "Apple", False), ("192.168.1.100", "HP", False),
            ("192.168.1.200", "Intel", False), ("192.168.1.254", "Netgear", False),
            ("10.0.0.1", "Cisco", False), ("10.0.0.2", "VMware", False),
            ("172.16.0.1", "Juniper", False),
        ]
        for ip, vendor, spoofed in common:
            mac = self._synthetic_mac(vendor)
            self.arp_cache[ip] = {
                "mac": mac, "vendor": vendor, "is_spoofed": spoofed,
                "first_seen": datetime.now().isoformat(),
                "last_seen": datetime.now().isoformat(),
            }
    
    def _synthetic_mac(self, vendor: Optional[str] = None) -> str:
        """Generate a synthetic MAC address for a vendor."""
        if vendor and vendor in self.OUI_MAP:
            prefix = random.choice(self.OUI_MAP[vendor]).lower()
        else:
            vendor = random.choice(list(self.OUI_MAP.keys()))
            prefix = random.choice(self.OUI_MAP[vendor]).lower()
        suffix = ':'.join('%02x' % random.randint(0, 255) for _ in range(3))
        return f"{prefix}:{suffix}"
    
    def clone_device(self, ip: str, deep_scan: bool = False) -> Dict:
        """
        Clone a device fingerprint.
        
        Args:
            ip: Device IP address
            deep_scan: Perform deep scanning
            
        Returns:
            Device DNA dictionary
        """
        self._scan_stats['probes'] += 1
        
        mac_info = self.arp_cache.get(ip)
        if mac_info:
            self._scan_stats['hits'] += 1
            mac = mac_info['mac']
            vendor = mac_info['vendor']
        else:
            self._scan_stats['misses'] += 1
            vendor = random.choice(list(self.OUI_MAP.keys()))
            mac = self._synthetic_mac(vendor)
            self.arp_cache[ip] = {
                "mac": mac, "vendor": vendor, "is_spoofed": False,
                "first_seen": datetime.now().isoformat(),
                "last_seen": datetime.now().isoformat(),
            }
        
        # Select OS based on vendor
        if vendor == "Apple":
            os_choices = ["macOS 14 Sonoma", "macOS 13 Ventura", "iOS 18"]
        elif vendor == "Cisco":
            os_choices = ["Cisco IOS"]
        elif vendor == "VMware":
            os_choices = ["VMware ESXi 8"]
        elif vendor in ["Samsung", "Google"]:
            os_choices = ["Android 15"]
        elif vendor in ["Juniper", "PaloAlto", "Fortinet"]:
            os_choices = ["Cisco IOS"]
        elif vendor in ["Synology", "QNAP"]:
            os_choices = ["Ubuntu 24.04 Server"]
        else:
            os_choices = [
                "Windows 11 Pro", "Windows 10 Pro",
                "Ubuntu 24.04 Server", "Ubuntu 22.04 LTS",
            ]
        
        selected_os = random.choice(os_choices)
        
        dna = {
            "id": uuid.uuid4().hex[:12],
            "ip": ip, "mac": mac, "vendor": vendor,
            "os": selected_os,
            "os_confidence": random.uniform(0.7, 0.99),
            "status": "alive",
            "ports": sorted(random.sample(
                [22, 80, 443, 445, 139, 135, 3306, 5432, 6379, 8080, 8443, 3389, 5985, 5986, 902, 6443],
                random.randint(2, 8)
            )),
            "is_spoofed": False,
            "hostname": f"device-{ip.replace('.', '-')}",
            "cloned_at": datetime.now().isoformat(),
            "ttl": random.choice([64, 128, 255]),
        }
        
        if deep_scan:
            dna["open_ports"] = self._simulate_port_scan(ip)
            dna["os_guess"] = self._os_guess_from_ports(dna["open_ports"])
        
        self.clone_pool.append(dna)
        
        if self.db:
            try:
                self.db.save_dna(dna) if hasattr(self.db, 'save_dna') else None
            except Exception:
                pass
        
        return dna
    
    def _simulate_port_scan(self, ip: str) -> List[int]:
        """Simulate port scanning for a device."""
        common_ports = [22, 80, 443, 445, 139, 135, 3306, 5432, 6379, 8080, 8443, 3389, 5985, 902, 6443]
        num_open = random.randint(2, 6)
        return sorted(random.sample(common_ports, num_open))
    
    def _os_guess_from_ports(self, ports: List[int]) -> str:
        """Guess OS based on open ports."""
        port_set = set(ports)
        best_match = "Unknown"
        best_score = 0
        
        for os_name, fingerprint in self.OS_FINGERPRINTS.items():
            fp_ports = set(fingerprint['ports'])
            matches = len(port_set & fp_ports)
            score = matches / len(fp_ports) if fp_ports else 0
            if score > best_score:
                best_score = score
                best_match = os_name
        
        return best_match
    
    def clone_random_devices(self, network_range: str = "192.168.1.0/24", count: int = 10) -> List[Dict]:
        """Clone multiple random devices from a network range."""
        base = network_range.split('/')[0].rsplit('.', 1)[0]
        target_ips = [f"{base}.{i}" for i in random.sample(range(2, 254), min(count, 253))]
        
        cloned = []
        for ip in target_ips:
            dna = self.clone_device(ip)
            cloned.append(dna)
        
        return cloned
    
    def get_network_map(self) -> Dict:
        """Get network device map with topology."""
        return {
            "total_devices": len(self.clone_pool),
            "alive": sum(1 for c in self.clone_pool if c['status'] == 'alive'),
            "spoofed": sum(1 for c in self.clone_pool if c['is_spoofed']),
            "by_vendor": dict(Counter(c['vendor'] for c in self.clone_pool)),
            "by_os": dict(Counter(c['os'] for c in self.clone_pool)),
            "topology": dict(self.network_topology),
        }
    
    def get_stats(self) -> Dict:
        """Return DNA cloner statistics."""
        return {
            **self._scan_stats,
            "total_cloned": len(self.clone_pool),
            "vendors_tracked": len(self.OUI_MAP),
            "os_fingerprints": len(self.OS_FINGERPRINTS),
        }


