# 🧟 MAIN — Entry Point with Advanced CLI
# ═══════════════════════════════════════════════════════════════

def main():
    """Main entry point — Advanced CLI interface."""
    parser = argparse.ArgumentParser(
        description="🧟 ZOMBIE ULTIMATE v50.0.0 — Full Autonomous Bug Bounty Framework",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
╔══════════════════════════════════════════════════════════════╗
║                  🧟 USAGE EXAMPLES 🧟                        ║
╠══════════════════════════════════════════════════════════════╣
║  Full Apocalypse:                                            ║
║    python zombie.py -t example.com --full-apocalypse         ║
║    python zombie.py -t example.com --full-apocalypse -w 50   ║
║                                                              ║
║  Recon Only:                                                 ║
║    python zombie.py -t example.com --recon                   ║
║    python zombie.py -t example.com --recon -o ./output       ║
║                                                              ║
║  WAF Bypass:                                                 ║
║    python zombie.py -u https://target.com/page?q=test --waf  ║
║    python zombie.py -u https://target.com --waf -p id --sqli ║
║                                                              ║
║  Subdomain Takeover:                                         ║
║    python zombie.py -t example.com --takeover                ║
║    python zombie.py --takeover --subs-file subs.txt          ║
║                                                              ║
║  Crawler Only:                                               ║
║    python zombie.py -u https://target.com --crawler          ║
║                                                              ║
║  Dorking Only:                                               ║
║    python zombie.py -t example.com --dorking                 ║
║                                                              ║
║  Stealth Modes:                                              ║
║    python zombie.py -t example.com --stealth firefox --eu    ║
║    python zombie.py -t example.com --stealth safari --mobile ║
║                                                              ║
║  Aggressive Mode:                                            ║
║    python zombie.py -t example.com --full-apocalypse --aggr  ║
╚══════════════════════════════════════════════════════════════╝
        """
    )
    
    # ═══ TARGET ARGUMENTS ═══
    target_group = parser.add_argument_group('🎯 Target Options')
    target_group.add_argument("-t", "--target", help="Target domain (e.g., example.com)")
    target_group.add_argument("-u", "--url", help="Target URL for WAF bypass or crawler")
    target_group.add_argument("-p", "--param", default="q", help="Parameter to test (default: q)")
    target_group.add_argument("--vuln-type", default="sqli",
                        choices=["sqli", "xss", "ssti", "lfi", "ssrf", "cmdi", "xxe", "nosql"],
                        help="Vulnerability type for testing")
    
    # ═══ SCAN MODES ═══
    mode_group = parser.add_argument_group('🔍 Scan Modes')
    mode_group.add_argument("--recon", action="store_true", help="Run subdomain recon only")
    mode_group.add_argument("--waf-bypass", "--waf", action="store_true", help="Run WAF bypass only")
    mode_group.add_argument("--takeover", action="store_true", help="Run subdomain takeover scan")
    mode_group.add_argument("--dorking", action="store_true", help="Run dorking only")
    mode_group.add_argument("--crawler", action="store_true", help="Run crawler only")
    mode_group.add_argument("--full-apocalypse", "--apocalypse", action="store_true",
                        help="Run FULL apocalypse — ALL 60+ modules")
    mode_group.add_argument("--aggressive", "--aggr", action="store_true",
                        help="Enable aggressive mode (more payloads, higher intensity)")
    
    # ═══ SKIP FLAGS ═══
    skip_group = parser.add_argument_group('⏭️ Skip Options')
    skip_group.add_argument("--skip-recon", action="store_true", help="Skip recon step")
    skip_group.add_argument("--skip-dorking", action="store_true", help="Skip dorking step")
    skip_group.add_argument("--skip-crawler", action="store_true", help="Skip crawler step")
    skip_group.add_argument("--skip-takeover", action="store_true", help="Skip takeover step")
    skip_group.add_argument("--skip-waf", action="store_true", help="Skip WAF bypass step")
    skip_group.add_argument("--skip-fuzzer", action="store_true", help="Skip fuzzer step")
    skip_group.add_argument("--skip-verify", action="store_true", help="Skip verification step")
    
    # ═══ FILE INPUT ═══
    file_group = parser.add_argument_group('📁 File Options')
    file_group.add_argument("--subs-file", help="File with subdomains for takeover scan")
    file_group.add_argument("--urls-file", help="File with URLs for crawling/fuzzing")
    file_group.add_argument("--config", help="Configuration file (JSON/YAML)")
    
    # ═══ OUTPUT & CONFIG ═══
    output_group = parser.add_argument_group('💾 Output Options')
    output_group.add_argument("-o", "--output", default="./zombie_output",
                        help="Output directory (default: ./zombie_output)")
    output_group.add_argument("-w", "--workers", type=int, default=30,
                        help="Number of concurrent workers (default: 30)")
    output_group.add_argument("--max-pages", type=int, default=500,
                        help="Maximum pages to crawl (default: 500)")
    output_group.add_argument("--max-depth", type=int, default=5,
                        help="Maximum crawl depth (default: 5)")
    output_group.add_argument("--timeout", type=int, default=30,
                        help="Request timeout in seconds (default: 30)")
    
    # ═══ STEALTH ═══
    stealth_group = parser.add_argument_group('🕵️ Stealth Options')
    stealth_group.add_argument("--stealth", default="chrome",
                        choices=["chrome", "firefox", "safari", "edge", "brave", "opera", "chromium"],
                        help="Browser fingerprint for stealth (default: chrome)")
    stealth_group.add_argument("--region", default="us",
                        choices=["us", "uk", "eu", "asia", "japan", "aus", "brazil", "india", "canada", "korea"],
                        help="Geo region for identity (default: us)")
    stealth_group.add_argument("--pool-size", type=int, default=7,
                        help="Identity pool size (default: 7, max: 25)")
    stealth_group.add_argument("--delay", type=float, default=0.3,
                        help="Base delay between requests (default: 0.3s)")
    stealth_group.add_argument("--camouflage", action="store_true",
                        help="Enable network camouflage (DNACloner + GhostFlood)")
    
    # ═══ RATE LIMITING ═══
    rate_group = parser.add_argument_group('⏱️ Rate Limiting')
    rate_group.add_argument("--rate-limit", type=float, default=2.0,
                        help="Requests per second rate limit (default: 2.0)")
    rate_group.add_argument("--burst", type=int, default=20,
                        help="Burst capacity (default: 20)")
    rate_group.add_argument("--no-circuit-breaker", action="store_true",
                        help="Disable circuit breaker")
    
    # ═══ REPORT ═══
    report_group = parser.add_argument_group('📊 Report Options')
    report_group.add_argument("--formats", nargs="+",
                        choices=["html", "json", "txt", "md", "csv"],
                        default=["html", "json", "txt", "md"],
                        help="Report formats (default: html json txt md)")
    
    args = parser.parse_args()
    
    # ═══ BANNER ═══
    print_banner()
    
    # ═══ NO ARGS — Show Interactive Menu ═══
    if not args.target and not args.url:
        print(f"\n{C.YELLOW}{'═'*70}{C.RST}")
        print(f"{C.YELLOW}{C.BOLD}  🧟 ZOMBIE ULTIMATE v50.0.0 — PHANTOM REQUIEM{C.RST}")
        print(f"{C.YELLOW}{'═'*70}{C.RST}")
        print(f"\n  {C.GREEN}60+ Modules | 10,000+ Payloads | 20 WAF Signatures{C.RST}")
        print(f"  {C.GREEN}12-Layer Filter | 100+ Recon Sources | 150 Scanners{C.RST}")
        print(f"\n  {C.GREEN}Quick Start:{C.RST}")
        print(f"  {C.CYAN}python zombie.py -t example.com --full-apocalypse{C.RST}")
        print(f"  {C.CYAN}python zombie.py -t example.com --recon{C.RST}")
        print(f"  {C.CYAN}python zombie.py -u https://target.com/page?q=test --waf{C.RST}")
        print(f"  {C.CYAN}python zombie.py -t example.com --takeover{C.RST}")
        print(f"  {C.CYAN}python zombie.py -u https://target.com --crawler{C.RST}")
        print(f"  {C.CYAN}python zombie.py -t example.com --dorking{C.RST}")
        print(f"\n  {C.GREEN}Advanced:{C.RST}")
        print(f"  {C.CYAN}python zombie.py -t example.com --full-apocalypse --aggressive{C.RST}")
        print(f"  {C.CYAN}python zombie.py -t example.com --stealth safari --region japan{C.RST}")
        print(f"\n  {C.GREEN}Full Help:{C.RST}")
        print(f"  {C.CYAN}python zombie.py --help{C.RST}")
        print(f"\n  {C.DIM}Built with ❤️ for Bug Bounty Hunters{C.RST}")
        print(f"  {C.DIM}\"When false positives die, true bugs rise from the grave.\"{C.RST}")
        print()
        return
    
    # ═══ Initialize Shared Zombie ═══
    zombie = Zombie(
        fingerprint=args.stealth,
        pool_size=args.pool_size,
        region=args.region,
        base_delay=args.delay,
    )
    
    target = args.target or urlparse(args.url).netloc
    
    # ═══ RECON ONLY ═══
    if args.recon and args.target:
        async def run():
            recon = ZombieRecon(
                domain=args.target,
                zombie_instance=zombie,
                output_dir=args.output,
                max_workers=args.workers,
            )
            report = await recon.recon()
            exported = recon.export_report(["json", "txt", "csv"])
            print(f"\n{C.GREEN}{I.CHECK} Recon: {report['statistics']['total_subdomains']} subdomains{C.RST}")
            for fmt, path in exported.items():
                print(f"  {C.GREEN}{I.FILE} {fmt.upper()}: {path}{C.RST}")
        asyncio.run(run())
        return
    
    # ═══ WAF BYPASS ONLY ═══
    if args.waf_bypass and args.url:
        async def run():
            waf = ZombieWAFZero(
                target_url=args.url,
                zombie_instance=zombie,
            )
            report = await waf.execute_full_ghost_penetration(
                param=args.param,
                vuln_type=args.vuln_type,
            )
            out_dir = Path(args.output)
            out_dir.mkdir(parents=True, exist_ok=True)
            ts = datetime.now().strftime("%Y%m%d_%H%M%S")
            path = out_dir / f"waf_report_{ts}.json"
            with open(path, "w") as f:
                json.dump(report, f, default=str, indent=2)
            print(f"\n{C.GREEN}{I.CHECK} WAF Report: {path}{C.RST}")
        asyncio.run(run())
        return
    
    # ═══ TAKEOVER ONLY ═══
    if args.takeover:
        async def run():
            subs = []
            if args.subs_file:
                with open(args.subs_file) as f:
                    subs = [line.strip() for line in f if line.strip()]
            elif args.target:
                recon = ZombieRecon(
                    domain=args.target,
                    zombie_instance=zombie,
                )
                report = await recon.recon()
                subs = list(report.get("subdomains", []))
            
            if subs:
                engine = SubdomainTakeoverEngine(
                    subdomains=subs,
                    zombie_instance=zombie,
                    max_workers=args.workers,
                )
                report = await engine.scan_all()
                print(f"\n{C.GREEN}{I.CHECK} Takeover: {report['total_vulnerable']} vulnerable{C.RST}")
                
                if report['vulnerable_subdomains']:
                    print(f"\n{C.YELLOW}Vulnerable Subdomains:{C.RST}")
                    for v in report['vulnerable_subdomains']:
                        print(f"  {C.RED}{I.FIRE} {v['subdomain']} → {v['service_name']} [{v['impact']}] — {v.get('provider', 'Unknown')}{C.RST}")
            else:
                print(f"{C.RED}{I.CROSS} No subdomains to scan — run recon first{C.RST}")
        asyncio.run(run())
        return
    
    # ═══ DORKING ONLY ═══
    if args.dorking and args.target:
        async def run():
            dorking = ZombieDorking(
                domain=args.target,
                zombie_instance=zombie,
            )
            report = await dorking.execute_dorking()
            summary = report.get('summary', {})
            print(f"\n{C.GREEN}{I.CHECK} Dorking Complete{C.RST}")
            print(f"  Google:     {summary.get('google_results', 0)} results")
            print(f"  GitHub:     {summary.get('github_findings', 0)} findings")
            print(f"  Shodan:     {summary.get('shodan_results', 0)} results")
            print(f"  GitLab:     {summary.get('gitlab_findings', 0)} findings")
            print(f"  Pastebin:   {summary.get('pastebin_leaks', 0)} leaks")
            print(f"  SearchCode: {summary.get('searchcode_findings', 0)} findings")
        asyncio.run(run())
        return
    
    # ═══ CRAWLER ONLY ═══
    if args.crawler and args.url:
        async def run():
            crawler = ZombieCrawler(
                start_url=args.url,
                zombie_instance=zombie,
                max_pages=args.max_pages,
                max_depth=args.max_depth,
                workers=args.workers,
            )
            report = await crawler.crawl()
            stats = report.get('statistics', {})
            print(f"\n{C.GREEN}{I.CHECK} Crawler Complete{C.RST}")
            print(f"  Pages:       {stats.get('pages_crawled', 0)}")
            print(f"  APIs:        {stats.get('api_endpoints', 0)}")
            print(f"  Sensitive:   {stats.get('sensitive_files', 0)}")
            print(f"  Forms:       {stats.get('forms', 0)}")
            print(f"  Params:      {stats.get('unique_params', 0)}")
            print(f"  Findings:    {stats.get('findings', 0)}")
        asyncio.run(run())
        return
    
    # ═══ FULL APOCALYPSE ═══
    if not any([args.recon, args.waf_bypass, args.takeover,
                args.dorking, args.crawler]):
        args.full_apocalypse = True
    
    if args.full_apocalypse:
        async def run():
            trinity = ZombieExploitationTrinity(
                domain=target,
                zombie_instance=zombie,
                output_dir=args.output,
                config={
                    "fingerprint": args.stealth,
                    "pool_size": args.pool_size,
                    "region": args.region,
                    "workers": args.workers,
                    "rate_limit": args.rate_limit,
                    "max_pages": args.max_pages,
                },
            )
            
            target_url = args.url or (f"https://www.{args.target}" if args.target else None)
            
            await trinity.execute_full_apocalypse(
                target_url=target_url,
                param=args.param,
                vuln_type=args.vuln_type,
                subdomains_file=args.subs_file,
                skip_recon=args.skip_recon,
                skip_dorking=args.skip_dorking,
                skip_crawler=args.skip_crawler,
                skip_takeover=args.skip_takeover,
                skip_waf=args.skip_waf,
                skip_fuzzer=args.skip_fuzzer,
                skip_verify=args.skip_verify,
                enable_camouflage=args.camouflage,
                aggressive=args.aggressive,
            )
            
            await trinity.cleanup()
        asyncio.run(run())
        return


