    @staticmethod
    def sample(lst: List[str], n: int) -> List[str]:
        """Get random sample from payload list."""
        if not lst:
            return []
        return random.sample(lst, min(n, len(lst)))
    
    @classmethod
    def get_all_part2(cls) -> Dict[str, List[str]]:
        """Return all Part 2 extended payloads."""
        return {
            "cors": cls.CORS_PAYLOADS,
            "jwt": cls.JWT_PAYLOADS,
            "graphql": cls.GRAPHQL_PAYLOADS,
            "deserialization": cls.DESERIALIZATION_PAYLOADS,
            "file_upload": cls.FILEUPLOAD_PAYLOADS,
            "ldap_xpath": cls.LDAP_XPATH_PAYLOADS,
            "cache_poisoning": cls.CACHE_POISONING_PAYLOADS,
            "http_smuggling": cls.HTTP_SMUGGLING_PAYLOADS,
            "prototype_pollution": cls.PROTOTYPE_POLLUTION_PAYLOADS,
        }
    
    @classmethod
    def get_total_part2_count(cls) -> int:
        """Return total Part 2 payload count."""
        return (
            len(cls.CORS_PAYLOADS) + len(cls.JWT_PAYLOADS) +
            len(cls.GRAPHQL_PAYLOADS) + len(cls.DESERIALIZATION_PAYLOADS) +
            len(cls.FILEUPLOAD_PAYLOADS) + len(cls.LDAP_XPATH_PAYLOADS) +
            len(cls.CACHE_POISONING_PAYLOADS) + len(cls.HTTP_SMUGGLING_PAYLOADS) +
            len(cls.PROTOTYPE_POLLUTION_PAYLOADS)
        )


