def detect_waf_advanced(response: Dict) -> Optional[str]:
    """
    🛡️ Advanced WAF Detection — 30+ WAF Signatures.
    
    Args:
        response: HTTP response dictionary
        
    Returns:
        WAF name if detected, None otherwise
    """
    if not response:
        return None
    
    text = (response.get('text', '') or '').lower()
    headers = {
        k.lower(): str(v).lower()
        for k, v in response.get('headers', {}).items()
    }
    status = response.get('status', 0)
    cookies = str(response.get('cookies', {}))
    
    best_match = None
    best_score = 0.0
    
    for waf_name, sigs in ADVANCED_WAF_DB.items():
        score = 0.0
        matches = []
        
        # Check headers
        sig_headers = sigs.get('headers', {})
        total_header_checks = sum(len(patterns) for patterns in sig_headers.values())
        matched_headers = 0
        
        for header_name, patterns in sig_headers.items():
            actual_value = headers.get(header_name.lower(), "")
            if actual_value:
                for pattern in patterns:
                    if re.search(pattern, str(actual_value), re.IGNORECASE):
                        matched_headers += 1
                        matches.append(f"Header:{header_name}")
                        break
        
        if total_header_checks > 0:
            score += (matched_headers / total_header_checks) * 0.5
        
        # Check cookies
        sig_cookies = sigs.get('cookies', [])
        if sig_cookies:
            cookie_matches = sum(
                1 for pattern in sig_cookies
                if re.search(pattern, cookies, re.IGNORECASE)
            )
            if cookie_matches > 0:
                score += (cookie_matches / len(sig_cookies)) * 0.3
        
        # Check body
        sig_body = sigs.get('body_patterns', [])
        if sig_body:
            body_matches = sum(
                1 for pattern in sig_body
                if re.search(pattern, text, re.IGNORECASE)
            )
            if body_matches > 0:
                score += (body_matches / len(sig_body)) * 0.2
                matches.append(f"Body:{body_matches}")
        
        # Status code
        if status in sigs.get('block_code', []):
            score += 0.05
        
        score *= sigs.get('confidence', 0.7)
        
        if score > best_score:
            best_score = score
            best_match = waf_name
    
    if best_match and best_score >= 0.3:
        return best_match
    
    return None


