# GRAPHQL SCANNER v50 — Advanced GraphQL Security Scanner
# ═══════════════════════════════════════════════════════════════

class GraphQLScanner:
    """
    🔍 GRAPHQL SCANNER v50 — Comprehensive GraphQL Security Analysis.
    
    Features:
    - Introspection query (detect if enabled)
    - Field suggestion attack
    - Batching attack detection
    - Alias-based rate limit bypass
    - Deep recursion DoS detection
    - Circular fragment detection
    - Operation name manipulation
    - Directive overloading
    - Query complexity analysis
    - Persisted query abuse
    - Subscription endpoint discovery
    
    Connected to: ZombieCrawler, FuzzerEngine, Database
    """
    
    GRAPHQL_PATHS: ClassVar[List[str]] = [
        '/graphql', '/gql', '/graphiql', '/graphql/console',
        '/api/graphql', '/api/gql', '/v1/graphql', '/v2/graphql',
        '/query', '/api/query', '/graph', '/playground',
        '/graphql-explorer', '/altair', '/voyager',
    ]
    
    INTROSPECTION_QUERIES: ClassVar[List[str]] = [
        # Full introspection
        '{__schema{types{name,fields{name,type{name,kind,ofType{name,kind}}}}}}',
        '{__schema{queryType{name},mutationType{name},subscriptionType{name}}}',
        '{__schema{types{name,description,fields{name,description,args{name,type{name}},type{name}}}}}',
        '{__type(name:"Query"){name,fields{name,args{name,type{name}},type{name}}}}',
        '{__type(name:"Mutation"){name,fields{name,args{name,type{name}},type{name}}}}',
        # Enumeration
        '{__schema{types{name,enumValues{name}}}}',
        '{__schema{directives{name,description,args{name},locations}}}',
        # Minimal
        '{__schema{types{name}}}',
        '{__typename}',
    ]
    
    def __init__(
        self,
        target_url: str = "",
        zombie_instance: Optional[Zombie] = None,
        db: Optional[Any] = None,
    ):
        """
        Initialize GraphQL Scanner v50.
        
        Args:
            target_url: Target base URL
            zombie_instance: Optional Zombie instance
            db: Optional database instance
        """
        self.target_url = target_url.rstrip('/')
        self._zombie = zombie_instance
        self.db = db
        
        self.graphql_endpoints: List[str] = []
        self.introspection_enabled: bool = False
        self.schema_info: Dict = {}
        self.vulnerabilities: List[Dict] = []
        self.stats = Counter()
    
    async def discover_endpoints(self, session) -> List[str]:
        """Discover GraphQL endpoints on target."""
        endpoints = []
        
        async def check_path(path: str) -> Optional[str]:
            url = f"{self.target_url}{path}"
            try:
                headers = {}
                if self._zombie:
                    headers = self._zombie.get_headers(url)
                
                # Send introspection query
                resp = await session.fetch(
                    url,
                    method="POST",
                    headers={**headers, "Content-Type": "application/json"},
                    json_data={"query": "{__typename}"},
                    timeout=10,
                )
                
                if resp.get('status') == 200:
                    text = (resp.get('text', '') or '')
                    if '__typename' in text or 'data' in text:
                        return url
            except Exception:
                pass
            return None
        
        tasks = [check_path(p) for p in self.GRAPHQL_PATHS]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, str) and result:
                endpoints.append(result)
        
        self.graphql_endpoints = endpoints
        return endpoints
    
    async def test_introspection(self, session, endpoint: str) -> Dict:
        """Test if introspection is enabled."""
        result = {"enabled": False, "types": [], "queries": [], "mutations": []}
        
        try:
            headers = {"Content-Type": "application/json"}
            if self._zombie:
                headers.update(self._zombie.get_headers(endpoint))
            
            for query in self.INTROSPECTION_QUERIES[:3]:
                resp = await session.fetch(
                    endpoint,
                    method="POST",
                    headers=headers,
                    json_data={"query": query},
                    timeout=15,
                )
                
                if resp.get('status') == 200:
                    text = (resp.get('text', '') or '')
                    if '__schema' in text and 'types' in text:
                        result["enabled"] = True
                        try:
                            data = json.loads(text)
                            schema = data.get('data', {}).get('__schema', {})
                            result["types"] = [t.get('name', '') for t in schema.get('types', [])]
                            query_type = schema.get('queryType', {})
                            mutation_type = schema.get('mutationType', {})
                            if query_type:
                                result["queries"] = [query_type.get('name', '')]
                            if mutation_type:
                                result["mutations"] = [mutation_type.get('name', '')]
                        except Exception:
                            pass
                        break
        except Exception:
            pass
        
        return result
    
    async def test_batching(self, session, endpoint: str) -> Dict:
        """Test if query batching is allowed."""
        result = {"batching_enabled": False, "evidence": ""}
        
        try:
            headers = {"Content-Type": "application/json"}
            if self._zombie:
                headers.update(self._zombie.get_headers(endpoint))
            
            # Send batched queries
            batched = [
                {"query": "{__typename}"},
                {"query": "{__typename}"},
                {"query": "{__typename}"},
            ]
            
            resp = await session.fetch(
                endpoint,
                method="POST",
                headers=headers,
                json_data=batched,
                timeout=10,
            )
            
            if resp.get('status') == 200:
                text = (resp.get('text', '') or '')
                if text.count('__typename') >= 2:
                    result["batching_enabled"] = True
                    result["evidence"] = f"Batching returned {text.count('__typename')} responses"
        except Exception:
            pass
        
        return result
    
    async def test_alias_attack(self, session, endpoint: str) -> Dict:
        """Test alias-based resource exhaustion."""
        result = {"vulnerable": False, "evidence": ""}
        
        try:
            headers = {"Content-Type": "application/json"}
            if self._zombie:
                headers.update(self._zombie.get_headers(endpoint))
            
            # Alias attack (100 aliases)
            aliases = " ".join([f"a{i}:__typename" for i in range(100)])
            query = f"{{{aliases}}}"
            
            resp = await session.fetch(
                endpoint,
                method="POST",
                headers=headers,
                json_data={"query": query},
                timeout=15,
            )
            
            if resp.get('status') == 200:
                text = (resp.get('text', '') or '')
                count = text.count('"a')
                if count >= 100:
                    result["vulnerable"] = True
                    result["evidence"] = f"Alias attack returned {count} responses"
        except Exception:
            pass
        
        return result
    
    async def test_depth_attack(self, session, endpoint: str) -> Dict:
        """Test deep recursion query (DoS)."""
        result = {"vulnerable": False, "evidence": ""}
        
        try:
            headers = {"Content-Type": "application/json"}
            if self._zombie:
                headers.update(self._zombie.get_headers(endpoint))
            
            # Deep recursion
            depth = 15
            query = "query{" + "".join([f"q{i}:__typename" + "{" for i in range(depth)]) + "__typename" + "}" * depth + "}"
            
            start = time.time()
            resp = await session.fetch(
                endpoint,
                method="POST",
                headers=headers,
                json_data={"query": query},
                timeout=20,
            )
            elapsed = time.time() - start
            
            if elapsed > 5:
                result["vulnerable"] = True
                result["evidence"] = f"Deep recursion took {elapsed:.1f}s"
        except Exception:
            pass
        
        return result
    
    async def full_scan(self, session) -> Dict:
        """Execute full GraphQL security scan."""
        print(f"\n{C.CYAN}{'═'*60}{C.RST}")
        print(f"{C.CYAN}  {I.SEARCH} GRAPHQL SCANNER v50 — {self.target_url}{C.RST}")
        print(f"{C.CYAN}{'═'*60}{C.RST}")
        
        # Discover endpoints
        endpoints = await self.discover_endpoints(session)
        print(f"  {C.GREEN}├─ Endpoints: {len(endpoints)}{C.RST}")
        
        for endpoint in endpoints:
            print(f"\n  {C.MAGENTA}[SCANNING] {endpoint}{C.RST}")
            
            # Test introspection
            introspection = await self.test_introspection(session, endpoint)
            if introspection["enabled"]:
                self.introspection_enabled = True
                self.schema_info = introspection
                self.vulnerabilities.append({
                    "type": "graphql_introspection",
                    "severity": "HIGH",
                    "endpoint": endpoint,
                    "evidence": f"Introspection enabled — {len(introspection.get('types', []))} types exposed",
                })
                print(f"  {C.RED}  {I.WARN} Introspection ENABLED — {len(introspection.get('types', []))} types{C.RST}")
            
            # Test batching
            batching = await self.test_batching(session, endpoint)
            if batching["batching_enabled"]:
                self.vulnerabilities.append({
                    "type": "graphql_batching",
                    "severity": "MEDIUM",
                    "endpoint": endpoint,
                    "evidence": batching["evidence"],
                })
                print(f"  {C.YELLOW}  {I.WARN} Batching ENABLED{C.RST}")
            
            # Test alias attack
            alias = await self.test_alias_attack(session, endpoint)
            if alias["vulnerable"]:
                self.vulnerabilities.append({
                    "type": "graphql_alias_attack",
                    "severity": "MEDIUM",
                    "endpoint": endpoint,
                    "evidence": alias["evidence"],
                })
                print(f"  {C.YELLOW}  {I.WARN} Alias attack possible{C.RST}")
            
            # Test depth attack
            depth = await self.test_depth_attack(session, endpoint)
            if depth["vulnerable"]:
                self.vulnerabilities.append({
                    "type": "graphql_depth_attack",
                    "severity": "LOW",
                    "endpoint": endpoint,
                    "evidence": depth["evidence"],
                })
                print(f"  {C.YELLOW}  {I.WARN} Deep recursion DoS possible{C.RST}")
        
        return self._build_report()
    
    def _build_report(self) -> Dict:
        """Build GraphQL scan report."""
        return {
            "target": self.target_url,
            "endpoints_found": self.graphql_endpoints,
            "introspection_enabled": self.introspection_enabled,
            "schema_info": self.schema_info,
            "vulnerabilities": self.vulnerabilities,
            "stats": dict(self.stats),
        }


