# WEBSOCKET TESTER v50 — WebSocket Security Analyzer
# ═══════════════════════════════════════════════════════════════

class WebSocketTester:
    """
    🔌 WEBSOCKET TESTER v50 — WebSocket Security Analysis.
    
    Features:
    - WebSocket endpoint discovery
    - Origin header bypass
    - CSWSH (Cross-Site WebSocket Hijacking)
    - Message injection/tampering
    - Authentication bypass via WebSocket
    - Rate limiting test
    - Large payload DoS
    
    Connected to: ZombieCrawler, Database
    """
    
    WS_PATTERNS: ClassVar[List[str]] = [
        r'wss?://[^\s"\'<>]+',
        r'new\s+WebSocket\s*\(\s*["\']([^"\']+)["\']',
        r'socket\.io', r'sockjs',
        r'ws://', r'wss://',
    ]
    
    def __init__(
        self,
        target_url: str = "",
        zombie_instance: Optional[Zombie] = None,
    ):
        """
        Initialize WebSocket Tester v50.
        
        Args:
            target_url: Target base URL
            zombie_instance: Optional Zombie instance
        """
        self.target_url = target_url
        self._zombie = zombie_instance
        self.ws_endpoints: List[str] = []
        self.vulnerabilities: List[Dict] = []
    
    def discover_endpoints(self, html: str, js_code: str) -> List[str]:
        """Discover WebSocket endpoints from HTML/JS."""
        endpoints = []
        
        combined = f"{html} {js_code}"
        
        for pattern in self.WS_PATTERNS:
            for match in re.finditer(pattern, combined, re.IGNORECASE):
                endpoint = match.group(1) if match.lastindex else match.group(0)
                if endpoint.startswith('ws'):
                    endpoints.append(endpoint)
        
        self.ws_endpoints = list(set(endpoints))
        return self.ws_endpoints
    
    async def test_origin_bypass(self, ws_url: str) -> Dict:
        """Test if WebSocket accepts arbitrary origins."""
        result = {"vulnerable": False, "evidence": ""}
        
        try:
            async with aiohttp.ClientSession() as session:
                headers = {"Origin": "http://evil.com"}
                async with session.ws_connect(
                    ws_url,
                    headers=headers,
                    timeout=10,
                    ssl=False,
                ) as ws:
                    result["vulnerable"] = True
                    result["evidence"] = "Connection accepted with arbitrary Origin"
        except Exception:
            pass
        
        return result


