# CACHE POISONING ENGINE v50 — Web Cache Poisoning Detection
# ═══════════════════════════════════════════════════════════════

class CachePoisoningEngine:
    """
    🗄️ CACHE POISONING ENGINE v50 — Web Cache Poisoning Detection.
    
    Features:
    - Host header injection
    - X-Forwarded-Host manipulation
    - X-Forwarded-Scheme poisoning
    - Cache key injection
    - Unkeyed header discovery
    - Query string cache poisoning
    - Fat GET attack
    
    Connected to: SessionManager, Database
    """
    
    POISON_HEADERS: ClassVar[Dict[str, str]] = {
        "X-Forwarded-Host": "evil.com",
        "X-Forwarded-For": "127.0.0.1",
        "X-Forwarded-Scheme": "http",
        "X-Forwarded-Proto": "http",
        "X-Original-URL": "/admin",
        "X-Rewrite-URL": "/admin",
        "X-HTTP-Method-Override": "POST",
        "X-HTTP-Method": "PUT",
        "Forwarded": "host=evil.com",
    }
    
    def __init__(
        self,
        target_url: str = "",
        zombie_instance: Optional[Zombie] = None,
        db: Optional[Any] = None,
    ):
        """
        Initialize Cache Poisoning Engine v50.
        
        Args:
            target_url: Target URL
            zombie_instance: Optional Zombie instance
            db: Optional database instance
        """
        self.target_url = target_url
        self._zombie = zombie_instance
        self.db = db
        self.vulnerabilities: List[Dict] = []
    
    async def test_header_poisoning(self, session, url: str) -> List[Dict]:
        """Test for cache poisoning via HTTP headers."""
        findings = []
        
        for header_name, poison_value in self.POISON_HEADERS.items():
            try:
                headers = {header_name: poison_value}
                if self._zombie:
                    headers.update(self._zombie.get_headers(url))
                
                resp = await session.fetch(url, headers=headers, timeout=10)
                
                if resp.get('status') == 200:
                    text = (resp.get('text', '') or '')
                    
                    # Check if poisoned value reflected
                    if poison_value in text or header_name in text:
                        findings.append({
                            "type": "cache_poisoning_header",
                            "header": header_name,
                            "payload": poison_value,
                            "evidence": f"Header {header_name} reflected in response",
                            "severity": "HIGH",
                        })
            except Exception:
                continue
        
        return findings
    
    async def test_host_poisoning(self, session, url: str) -> List[Dict]:
        """Test for Host header cache poisoning."""
        findings = []
        
        host_payloads = [
            "evil.com",
            f"evil.com{urlparse(url).netloc}",
            f"{urlparse(url).netloc}@evil.com",
        ]
        
        for host in host_payloads:
            try:
                headers = {"Host": host}
                if self._zombie:
                    headers.update(self._zombie.get_headers(url))
                
                resp = await session.fetch(url, headers=headers, timeout=10)
                text = (resp.get('text', '') or '')
                
                if host in text:
                    findings.append({
                        "type": "cache_poisoning_host",
                        "payload": host,
                        "evidence": f"Host header reflected: {host}",
                        "severity": "HIGH",
                    })
            except Exception:
                continue
        
        return findings
    
    async def full_scan(self, session, url: str) -> Dict:
        """Execute full cache poisoning scan."""
        print(f"\n{C.CYAN}{'═'*60}{C.RST}")
        print(f"{C.CYAN}  {I.CLOUD} CACHE POISONING ENGINE v50 — {url}{C.RST}")
        print(f"{C.CYAN}{'═'*60}{C.RST}")
        
        header_findings = await self.test_header_poisoning(session, url)
        host_findings = await self.test_host_poisoning(session, url)
        
        self.vulnerabilities = header_findings + host_findings
        
        for v in self.vulnerabilities:
            print(f"  {C.RED}  {I.WARN} {v['type']}: {v.get('header', v.get('payload', ''))}{C.RST}")
        
        print(f"  {C.GREEN}├─ Total vulnerabilities: {len(self.vulnerabilities)}{C.RST}")
        
        return {
            "target": url,
            "vulnerabilities": self.vulnerabilities,
            "total": len(self.vulnerabilities),
        }


# ═══════════════════════════════════════════════════════════════
# RACE CONDITION TESTER v50
# ═══════════════════════════════════════════════════════════════

class RaceConditionTester:
    """
    🏃 RACE CONDITION TESTER v50 — TOCTOU & Race Detection.
    
    Features:
    - Concurrent request flooding
    - Coupon/limit bypass testing
    - Auth bypass via race
    - File upload race
    - Parameter race
    
    Connected to: SessionManager, Database
    """
    
    def __init__(
        self,
        db: Optional[Any] = None,
        max_concurrent: int = 50,
    ):
        """
        Initialize Race Condition Tester v50.
        
        Args:
            db: Optional database instance
            max_concurrent: Maximum concurrent requests
        """
        self.db = db
        self.max_concurrent = max_concurrent
        self.vulnerabilities: List[Dict] = []
    
    async def test_concurrent_requests(
        self, session, url: str, method: str = "GET",
        data: Dict = None, count: int = 30,
    ) -> Dict:
        """
        Send concurrent requests to test race conditions.
        
        Args:
            session: SessionManager instance
            url: Target URL
            method: HTTP method
            data: Request data
            count: Number of concurrent requests
            
        Returns:
            Test results
        """
        results = []
        errors = 0
        success = 0
        
        async def send_request() -> Dict:
            try:
                resp = await session.fetch(url, method=method, data=data, timeout=10)
                return {"status": resp.get('status', 0), "text": resp.get('text', '')[:200]}
            except Exception as e:
                return {"error": str(e)}
        
        tasks = [send_request() for _ in range(count)]
        responses = await asyncio.gather(*tasks, return_exceptions=True)
        
        for resp in responses:
            if isinstance(resp, dict):
                if resp.get('error'):
                    errors += 1
                elif resp.get('status', 0) >= 500:
                    errors += 1
                else:
                    success += 1
                    results.append(resp)
        
        return {
            "total": count,
            "success": success,
            "errors": errors,
            "error_rate": round(errors / max(count, 1) * 100, 1),
            "sample_responses": results[:5],
        }


