# BURP SUITE EXPORTER v50 — Burp Suite Integration
# ═══════════════════════════════════════════════════════════════

class BurpSuiteExporter:
    """
    🔗 BURP SUITE EXPORTER v50 — Export findings to Burp Suite format.
    
    Features:
    - Export to Burp XML format
    - Export to Burp JSON format
    - Base64 request/response encoding
    - Host/port/SSL mapping
    - Finding severity mapping to Burp confidence
    
    Connected to: ReportGenerator, Database
    """
    
    def __init__(self, output_dir: str = "./zombie_output"):
        self.output_dir = Path(output_dir)
        self.output_dir.mkdir(parents=True, exist_ok=True)
    
    def export_to_burp_xml(self, findings: List[Dict], target: str) -> Path:
        """
        Export findings to Burp Suite XML format.
        
        Args:
            findings: List of findings
            target: Target domain/URL
            
        Returns:
            Path to exported XML file
        """
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        path = self.output_dir / f"burp_export_{target}_{ts}.xml"
        
        xml_content = '<?xml version="1.0" encoding="UTF-8"?>\n'
        xml_content += '<!DOCTYPE items [\n'
        xml_content += '<!ELEMENT items (item*)>\n'
        xml_content += '<!ELEMENT item (time, url, host, port, protocol, method, path, extension, request, status, response, comment?)>\n'
        xml_content += '<!ELEMENT time (#PCDATA)>\n'
        xml_content += '<!ELEMENT url (#PCDATA)>\n'
        xml_content += '<!ELEMENT host (#PCDATA)>\n'
        xml_content += '<!ELEMENT port (#PCDATA)>\n'
        xml_content += '<!ELEMENT protocol (#PCDATA)>\n'
        xml_content += '<!ELEMENT method (#PCDATA)>\n'
        xml_content += '<!ELEMENT path (#PCDATA)>\n'
        xml_content += '<!ELEMENT extension (#PCDATA)>\n'
        xml_content += '<!ELEMENT request (#PCDATA)>\n'
        xml_content += '<!ELEMENT status (#PCDATA)>\n'
        xml_content += '<!ELEMENT response (#PCDATA)>\n'
        xml_content += '<!ELEMENT comment (#PCDATA)>\n'
        xml_content += ']>\n<items>\n'
        
        for finding in findings:
            url = finding.get('url', '')
            parsed = urlparse(url)
            host = parsed.hostname or target
            port = parsed.port or (443 if parsed.scheme == 'https' else 80)
            protocol = parsed.scheme or 'https'
            path = parsed.path or '/'
            
            request_raw = base64.b64encode(
                f"GET {path} HTTP/1.1\nHost: {host}\n\n".encode()
            ).decode()
            
            response_raw = base64.b64encode(
                str(finding.get('evidence', '')).encode()
            ).decode()
            
            comment = f"[{finding.get('severity', 'INFO')}] {finding.get('vuln_type', 'Unknown')} — {finding.get('evidence', '')[:200]}"
            
            xml_content += f"""  <item>
    <time>{finding.get('timestamp', datetime.now().isoformat())}</time>
    <url>{url}</url>
    <host>{host}</host>
    <port>{port}</port>
    <protocol>{protocol}</protocol>
    <method>GET</method>
    <path>{path}</path>
    <extension>{path.split('.')[-1] if '.' in path else 'null'}</extension>
    <request>{request_raw}</request>
    <status>{finding.get('status', 200)}</status>
    <response>{response_raw}</response>
    <comment><![CDATA[{comment}]]></comment>
  </item>\n"""
        
        xml_content += '</items>'
        
        with open(path, 'w', encoding='utf-8') as f:
            f.write(xml_content)
        
        return path


