# DISCORD WEBHOOK NOTIFIER v50
# ═══════════════════════════════════════════════════════════════

class DiscordNotifier:
    """
    💬 DISCORD NOTIFIER v50 — Send scan results to Discord.
    
    Features:
    - Webhook integration
    - Severity-based color coding
    - Embed message formatting
    - Batch notification (findings grouped by severity)
    - Progress updates
    - Error notifications
    - Rate limiting (Discord webhook limits)
    
    Connected to: All modules
    """
    
    SEVERITY_COLORS: ClassVar[Dict[str, int]] = {
        "CRITICAL": 0xFF0000,  # Red
        "HIGH": 0xFF6600,      # Orange
        "MEDIUM": 0xFFAA00,    # Yellow
        "LOW": 0x00AA00,       # Green
        "INFO": 0x0088CC,      # Blue
    }
    
    def __init__(self, webhook_url: str, username: str = "🧟 Zombie v50"):
        """
        Initialize Discord Notifier v50.
        
        Args:
            webhook_url: Discord webhook URL
            username: Bot username
        """
        self.webhook_url = webhook_url
        self.username = username
        self.session = None
    
    async def _send_webhook(self, payload: Dict) -> bool:
        """Send payload to Discord webhook."""
        try:
            async with aiohttp.ClientSession() as session:
                async with session.post(
                    self.webhook_url,
                    json=payload,
                    timeout=aiohttp.ClientTimeout(total=10),
                ) as resp:
                    return resp.status == 204
        except Exception:
            return False
    
    async def send_scan_start(self, target: str, scan_type: str, modules: int = 60) -> bool:
        """Notify scan start."""
        embed = {
            "title": f"🔍 Scan Started — {target}",
            "description": f"**Type:** {scan_type}\n**Modules:** {modules}+\n**Time:** {datetime.now().strftime('%Y-%m-%d %H:%M:%S')} UTC",
            "color": 0x0088CC,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
        
        payload = {
            "username": self.username,
            "embeds": [embed],
        }
        
        return await self._send_webhook(payload)
    
    async def send_findings_batch(self, findings: List[Dict], max_per_message: int = 10) -> int:
        """Send findings to Discord in batches."""
        sent = 0
        
        # Group by severity
        grouped = defaultdict(list)
        for f in findings:
            severity = f.get('severity', 'INFO').upper()
            grouped[severity].append(f)
        
        # Send critical first
        for severity in ["CRITICAL", "HIGH", "MEDIUM", "LOW", "INFO"]:
            batch = grouped.get(severity, [])
            if not batch:
                continue
            
            for i in range(0, len(batch), max_per_message):
                chunk = batch[i:i + max_per_message]
                
                fields = []
                for finding in chunk:
                    vuln_type = finding.get('vuln_type', 'Unknown')
                    url = finding.get('url', 'N/A')[:100]
                    evidence = str(finding.get('evidence', 'N/A'))[:150]
                    
                    fields.append({
                        "name": f"[{severity}] {vuln_type}",
                        "value": f"**URL:** {url}\n**Evidence:** {evidence}",
                        "inline": False,
                    })
                
                embed = {
                    "title": f"{I.severity_icon(severity)} {severity} Findings ({i+1}-{min(i+max_per_message, len(batch))} of {len(batch)})",
                    "color": self.SEVERITY_COLORS.get(severity, 0x0088CC),
                    "fields": fields,
                    "timestamp": datetime.now(timezone.utc).isoformat(),
                }
                
                payload = {
                    "username": self.username,
                    "embeds": [embed],
                }
                
                if await self._send_webhook(payload):
                    sent += len(chunk)
                
                await asyncio.sleep(1)  # Rate limit
        
        return sent
    
    async def send_scan_complete(self, target: str, total_findings: int, duration: float, severity_counts: Dict) -> bool:
        """Notify scan completion."""
        fields = [
            {"name": "🔴 Critical", "value": str(severity_counts.get('CRITICAL', 0)), "inline": True},
            {"name": "🟠 High", "value": str(severity_counts.get('HIGH', 0)), "inline": True},
            {"name": "🟡 Medium", "value": str(severity_counts.get('MEDIUM', 0)), "inline": True},
            {"name": "🟢 Low", "value": str(severity_counts.get('LOW', 0)), "inline": True},
            {"name": "🔵 Info", "value": str(severity_counts.get('INFO', 0)), "inline": True},
            {"name": "⏱️ Duration", "value": f"{duration:.1f}s", "inline": True},
        ]
        
        embed = {
            "title": f"✅ Scan Complete — {target}",
            "description": f"**Total Findings:** {total_findings}",
            "color": 0x00FF00,
            "fields": fields,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
        
        payload = {
            "username": self.username,
            "embeds": [embed],
        }
        
        return await self._send_webhook(payload)


