# SLACK NOTIFIER v50
# ═══════════════════════════════════════════════════════════════

class SlackNotifier:
    """
    💬 SLACK NOTIFIER v50 — Send scan results to Slack.
    
    Connected to: All modules
    """
    
    SEVERITY_EMOJI: ClassVar[Dict[str, str]] = {
        "CRITICAL": ":red_circle:",
        "HIGH": ":orange_circle:",
        "MEDIUM": ":yellow_circle:",
        "LOW": ":green_circle:",
        "INFO": ":blue_circle:",
    }
    
    def __init__(self, webhook_url: str, username: str = "Zombie v50"):
        self.webhook_url = webhook_url
        self.username = username
    
    async def send_message(self, text: str, blocks: List[Dict] = None) -> bool:
        """Send message to Slack."""
        payload = {
            "username": self.username,
            "text": text,
        }
        if blocks:
            payload["blocks"] = blocks
        
        try:
            async with aiohttp.ClientSession() as session:
                async with session.post(
                    self.webhook_url,
                    json=payload,
                    timeout=aiohttp.ClientTimeout(total=10),
                ) as resp:
                    return resp.status == 200
        except Exception:
            return False
    
    async def send_findings_summary(self, target: str, findings: List[Dict]) -> bool:
        """Send findings summary to Slack."""
        severity_counts = Counter(f.get('severity', 'INFO').upper() for f in findings)
        
        blocks = [
            {
                "type": "header",
                "text": {"type": "plain_text", "text": f"🧟 Zombie v50 Scan — {target}"}
            },
            {
                "type": "section",
                "fields": [
                    {"type": "mrkdwn", "text": f"*Total Findings:* {len(findings)}"},
                    {"type": "mrkdwn", "text": f"*Scan Time:* {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}"},
                ]
            },
            {
                "type": "section",
                "fields": [
                    {"type": "mrkdwn", "text": f":red_circle: Critical: {severity_counts.get('CRITICAL', 0)}"},
                    {"type": "mrkdwn", "text": f":orange_circle: High: {severity_counts.get('HIGH', 0)}"},
                    {"type": "mrkdwn", "text": f":yellow_circle: Medium: {severity_counts.get('MEDIUM', 0)}"},
                    {"type": "mrkdwn", "text": f":green_circle: Low: {severity_counts.get('LOW', 0)}"},
                ]
            },
        ]
        
        # Add top critical/high findings
        critical_high = [f for f in findings if f.get('severity', '').upper() in ['CRITICAL', 'HIGH']][:5]
        if critical_high:
            text = "*Top Findings:*\n"
            for f in critical_high:
                emoji = self.SEVERITY_EMOJI.get(f.get('severity', 'INFO').upper(), ':grey_question:')
                text += f"{emoji} [{f.get('severity', 'INFO')}] {f.get('vuln_type', 'Unknown')}: {f.get('url', 'N/A')[:80]}\n"
            
            blocks.append({
                "type": "section",
                "text": {"type": "mrkdwn", "text": text}
            })
        
        return await self.send_message(
            f"Zombie v50 scan complete: {target} — {len(findings)} findings",
            blocks,
        )


# ═══════════════════════════════════════════════════════════════
# ADVANCED CACHE SYSTEM v50 — Multi-Level Caching
# ═══════════════════════════════════════════════════════════════

class AdvancedCache:
    """
    🚀 ADVANCED CACHE SYSTEM v50 — Multi-Level Intelligent Caching.
    
    Features:
    - L1: In-memory LRU cache (fastest)
    - L2: Disk-based cache (persistent)
    - TTL-based expiration per cache level
    - Cache key normalization
    - Compression for large responses
    - Cache warming from previous scans
    - Automatic cache invalidation
    - Cache statistics & hit rate tracking
    - Thread-safe operations
    - Memory pressure-aware eviction
    
    Connected to: SessionManager, All HTTP modules
    """
    
    def __init__(
        self,
        max_memory_entries: int = 10000,
        max_memory_size_mb: int = 500,
        disk_cache_dir: str = "./zombie_cache",
        default_ttl: int = 300,
        enable_compression: bool = True,
    ):
        """
        Initialize Advanced Cache v50.
        
        Args:
            max_memory_entries: Maximum entries in memory cache
            max_memory_size_mb: Maximum memory cache size in MB
            disk_cache_dir: Directory for disk cache
            default_ttl: Default TTL in seconds
            enable_compression: Enable compression for large entries
        """
        self.max_memory_entries = max_memory_entries
        self.max_memory_size = max_memory_size_mb * 1024 * 1024
        self.disk_cache_dir = Path(disk_cache_dir)
        self.disk_cache_dir.mkdir(parents=True, exist_ok=True)
        self.default_ttl = default_ttl
        self.enable_compression = enable_compression
        
        # L1: Memory cache (OrderedDict for LRU)
        self._memory_cache: OrderedDict = OrderedDict()
        self._memory_size: int = 0
        
        # L2: Disk cache
        self._disk_index: Dict[str, float] = {}
        self._load_disk_index()
        
        # Stats
        self._l1_hits: int = 0
        self._l1_misses: int = 0
        self._l2_hits: int = 0
        self._l2_misses: int = 0
        
        # Locks
        self._lock = threading.RLock()
        
        # Background cleanup
        self._cleanup_interval = 300
        self._last_cleanup = time.time()
    
    def _load_disk_index(self) -> None:
        """Load disk cache index."""
        index_file = self.disk_cache_dir / "_index.json"
        if index_file.exists():
            try:
                with open(index_file) as f:
                    self._disk_index = json.load(f)
            except Exception:
                self._disk_index = {}
    
    def _save_disk_index(self) -> None:
        """Save disk cache index."""
        index_file = self.disk_cache_dir / "_index.json"
        try:
            with open(index_file, 'w') as f:
                json.dump(self._disk_index, f)
        except Exception:
            pass
    
    def _normalize_key(self, key: str) -> str:
        """Normalize cache key for consistent lookups."""
        return hashlib.sha256(key.encode()).hexdigest()[:32]
    
    def _compress(self, data: str) -> bytes:
        """Compress string data."""
        if self.enable_compression and len(data) > 1024:
            return zlib.compress(data.encode())
        return data.encode()
    
    def _decompress(self, data: bytes) -> str:
        """Decompress data if needed."""
        try:
            return zlib.decompress(data).decode()
        except Exception:
            return data.decode() if isinstance(data, bytes) else str(data)
    
    def _evict_memory(self, needed_bytes: int = 0) -> None:
        """Evict entries from memory cache based on LRU."""
        while self._memory_size + needed_bytes > self.max_memory_size and self._memory_cache:
            _, (_, size) = self._memory_cache.popitem(last=False)
            self._memory_size = max(0, self._memory_size - size)
        
        while len(self._memory_cache) >= self.max_memory_entries:
            self._memory_cache.popitem(last=False)
    
    def get(self, key: str, ttl: int = None) -> Optional[Any]:
        """Get value from cache (L1 first, then L2)."""
        normalized_key = self._normalize_key(key)
        ttl = ttl or self.default_ttl
        
        # Cleanup periodically
        self._cleanup_if_needed()
        
        with self._lock:
            # L1: Memory cache
            if normalized_key in self._memory_cache:
                entry, size, timestamp = self._memory_cache[normalized_key]
                if time.time() - timestamp < ttl:
                    self._memory_cache.move_to_end(normalized_key)
                    self._l1_hits += 1
                    return json.loads(entry) if isinstance(entry, str) else entry
                else:
                    del self._memory_cache[normalized_key]
                    self._memory_size = max(0, self._memory_size - size)
            
            self._l1_misses += 1
            
            # L2: Disk cache
            disk_path = self.disk_cache_dir / f"{normalized_key}.cache"
            if disk_path.exists() and normalized_key in self._disk_index:
                disk_timestamp = self._disk_index[normalized_key]
                if time.time() - disk_timestamp < ttl:
                    try:
                        with open(disk_path, 'rb') as f:
                            compressed_data = f.read()
                        data = self._decompress(compressed_data)
                        result = json.loads(data)
                        
                        # Promote to L1
                        self._promote_to_memory(normalized_key, result)
                        self._l2_hits += 1
                        return result
                    except Exception:
                        pass
                else:
                    disk_path.unlink(missing_ok=True)
                    del self._disk_index[normalized_key]
            
            self._l2_misses += 1
        
        return None
    
    def set(self, key: str, value: Any, ttl: int = None) -> None:
        """Set value in cache (both L1 and L2)."""
        normalized_key = self._normalize_key(key)
        ttl = ttl or self.default_ttl
        
        with self._lock:
            # Store in L1 (memory)
            self._store_in_memory(normalized_key, value)
            
            # Store in L2 (disk)
            self._store_on_disk(normalized_key, value)
    
    def _store_in_memory(self, normalized_key: str, value: Any) -> None:
        """Store value in memory cache."""
        serialized = json.dumps(value) if not isinstance(value, str) else value
        size = len(serialized)
        
        self._evict_memory(size)
        
        if size <= self.max_memory_size:
            self._memory_cache[normalized_key] = (serialized, size, time.time())
            self._memory_size += size
    
    def _store_on_disk(self, normalized_key: str, value: Any) -> None:
        """Store value on disk cache."""
        disk_path = self.disk_cache_dir / f"{normalized_key}.cache"
        
        try:
            serialized = json.dumps(value) if not isinstance(value, str) else value
            compressed = self._compress(serialized)
            
            with open(disk_path, 'wb') as f:
                f.write(compressed)
            
            self._disk_index[normalized_key] = time.time()
        except Exception:
            pass
    
    def _promote_to_memory(self, normalized_key: str, value: Any) -> None:
        """Promote disk cache entry to memory."""
        self._store_in_memory(normalized_key, value)
    
    def _cleanup_if_needed(self) -> None:
        """Run periodic cleanup."""
        now = time.time()
        if now - self._last_cleanup > self._cleanup_interval:
            self._cleanup_expired()
            self._last_cleanup = now
    
    def _cleanup_expired(self) -> None:
        """Remove expired entries from memory."""
        with self._lock:
            expired_keys = []
            for key, (_, _, timestamp) in self._memory_cache.items():
                if time.time() - timestamp > self.default_ttl:
                    expired_keys.append(key)
            
            for key in expired_keys:
                _, size, _ = self._memory_cache.pop(key)
                self._memory_size = max(0, self._memory_size - size)
    
    def clear(self) -> None:
        """Clear all caches."""
        with self._lock:
            self._memory_cache.clear()
            self._memory_size = 0
            
            for key in list(self._disk_index.keys()):
                disk_path = self.disk_cache_dir / f"{key}.cache"
                disk_path.unlink(missing_ok=True)
            
            self._disk_index.clear()
            self._save_disk_index()
    
    def get_stats(self) -> Dict:
        """Get cache statistics."""
        with self._lock:
            total_l1 = self._l1_hits + self._l1_misses
            total_l2 = self._l2_hits + self._l2_misses
            
            return {
                "l1": {
                    "entries": len(self._memory_cache),
                    "size_bytes": self._memory_size,
                    "size_mb": round(self._memory_size / (1024 * 1024), 2),
                    "hits": self._l1_hits,
                    "misses": self._l1_misses,
                    "hit_rate": round(self._l1_hits / max(total_l1, 1) * 100, 1),
                },
                "l2": {
                    "entries": len(self._disk_index),
                    "hits": self._l2_hits,
                    "misses": self._l2_misses,
                    "hit_rate": round(self._l2_hits / max(total_l2, 1) * 100, 1),
                },
                "total_hit_rate": round(
                    (self._l1_hits + self._l2_hits) / max(total_l1 + total_l2, 1) * 100, 1
                ),
            }
    
    def warm_from_file(self, file_path: str) -> int:
        """Warm cache from previous scan data file."""
        count = 0
        try:
            with open(file_path) as f:
                data = json.load(f)
            
            if isinstance(data, list):
                for item in data:
                    if isinstance(item, dict) and 'url' in item:
                        key = f"response:{item['url']}"
                        self.set(key, item)
                        count += 1
        except Exception:
            pass
        
        return count


# ═══════════════════════════════════════════════════════════════
# CONNECTION POOL MANAGER v50
# ═══════════════════════════════════════════════════════════════

class ConnectionPoolManager:
    """
    🔌 CONNECTION POOL MANAGER v50 — Advanced Connection Pooling.
    
    Features:
    - Per-domain connection pools
    - Dynamic pool sizing based on load
    - Connection health checking
    - Idle connection cleanup
    - Connection reuse optimization
    - DNS cache per domain
    - SSL session cache
    - Connection timeout management
    
    Connected to: SessionManager
    """
    
    def __init__(
        self,
        default_pool_size: int = 50,
        max_pool_size: int = 200,
        idle_timeout: int = 30,
        dns_cache_ttl: int = 300,
        enable_ssl_cache: bool = True,
    ):
        """
        Initialize Connection Pool Manager v50.
        
        Args:
            default_pool_size: Default connections per domain
            max_pool_size: Maximum connections per domain
            idle_timeout: Idle connection timeout in seconds
            dns_cache_ttl: DNS cache TTL in seconds
            enable_ssl_cache: Enable SSL session caching
        """
        self.default_pool_size = default_pool_size
        self.max_pool_size = max_pool_size
        self.idle_timeout = idle_timeout
        self.dns_cache_ttl = dns_cache_ttl
        self.enable_ssl_cache = enable_ssl_cache
        
        self._pools: Dict[str, Dict] = {}
        self._dns_cache: Dict[str, Tuple[List[str], float]] = {}
        self._ssl_contexts: Dict[str, ssl.SSLContext] = {}
        self._lock = asyncio.Lock()
        self._stats = Counter()
    
    async def get_pool_for_domain(self, domain: str) -> aiohttp.TCPConnector:
        """Get or create connection pool for domain."""
        async with self._lock:
            if domain not in self._pools:
                # Determine pool size based on domain frequency
                pool_size = self.default_pool_size
                
                connector = aiohttp.TCPConnector(
                    limit=pool_size,
                    limit_per_host=min(pool_size, 30),
                    ttl_dns_cache=self.dns_cache_ttl,
                    use_dns_cache=True,
                    enable_cleanup_closed=True,
                    force_close=False,
                    keepalive_timeout=self.idle_timeout,
                )
                
                self._pools[domain] = {
                    "connector": connector,
                    "created_at": time.time(),
                    "active_connections": 0,
                    "peak_connections": 0,
                    "total_requests": 0,
                    "last_used": time.time(),
                }
            
            pool = self._pools[domain]
            pool["last_used"] = time.time()
            return pool["connector"]
    
    async def record_request(self, domain: str) -> None:
        """Record a request for pool statistics."""
        async with self._lock:
            if domain in self._pools:
                self._pools[domain]["total_requests"] += 1
    
    async def cleanup_idle_pools(self) -> int:
        """Cleanup idle connection pools."""
        cleaned = 0
        now = time.time()
        
        async with self._lock:
            for domain in list(self._pools.keys()):
                pool = self._pools[domain]
                if now - pool["last_used"] > self.idle_timeout * 2:
                    try:
                        await pool["connector"].close()
                    except Exception:
                        pass
                    del self._pools[domain]
                    cleaned += 1
        
        return cleaned
    
    def get_stats(self) -> Dict:
        """Get connection pool statistics."""
        return {
            "total_pools": len(self._pools),
            "domains": list(self._pools.keys()),
            "total_requests": sum(p["total_requests"] for p in self._pools.values()),
            "dns_cache_entries": len(self._dns_cache),
        }
    
    async def close_all(self) -> None:
        """Close all connection pools."""
        async with self._lock:
            for domain, pool in self._pools.items():
                try:
                    await pool["connector"].close()
                except Exception:
                    pass
            self._pools.clear()


# ═══════════════════════════════════════════════════════════════
# MEMORY MANAGER v50 — Automatic Memory Optimization
# ═══════════════════════════════════════════════════════════════

class MemoryManager:
    """
    💾 MEMORY MANAGER v50 — Automatic Memory Optimization.
    
    Features:
    - Memory usage monitoring
    - Automatic garbage collection
    - Large object tracking
    - Memory pressure detection
    - Cache size adjustment based on memory
    - Worker pool adjustment under pressure
    - Swap prevention
    
    Connected to: All modules
    """
    
    def __init__(
        self,
        max_memory_percent: float = 80.0,
        gc_threshold: float = 70.0,
        cache_reduce_ratio: float = 0.5,
        check_interval: float = 10.0,
    ):
        """
        Initialize Memory Manager v50.
        
        Args:
            max_memory_percent: Maximum memory usage before aggressive cleanup
            gc_threshold: Memory threshold to trigger GC
            cache_reduce_ratio: Ratio to reduce cache by
            check_interval: Memory check interval in seconds
        """
        self.max_memory_percent = max_memory_percent
        self.gc_threshold = gc_threshold
        self.cache_reduce_ratio = cache_reduce_ratio
        self.check_interval = check_interval
        
        self._last_check = time.time()
        self._memory_history: List[float] = []
        self._gc_count: int = 0
        self._cleanup_count: int = 0
        
        if PSUTIL_AVAILABLE:
            self._process = psutil.Process()
        else:
            self._process = None
    
    def get_memory_usage(self) -> Dict:
        """Get current memory usage."""
        if self._process:
            try:
                mem = self._process.memory_info()
                percent = self._process.memory_percent()
                return {
                    "rss_mb": round(mem.rss / (1024 * 1024), 1),
                    "vms_mb": round(mem.vms / (1024 * 1024), 1),
                    "percent": round(percent, 1),
                }
            except Exception:
                pass
        
        return {"rss_mb": 0, "vms_mb": 0, "percent": 0}
    
    async def check_and_optimize(self, force: bool = False) -> Dict:
        """
        Check memory usage and optimize if needed.
        
        Args:
            force: Force optimization regardless of thresholds
            
        Returns:
            Optimization actions taken
        """
        actions = []
        now = time.time()
        
        if not force and now - self._last_check < self.check_interval:
            return {"actions": actions, "memory": self.get_memory_usage()}
        
        self._last_check = now
        mem = self.get_memory_usage()
        self._memory_history.append(mem["percent"])
        
        # Trim history
        if len(self._memory_history) > 100:
            self._memory_history = self._memory_history[-100:]
        
        percent = mem["percent"]
        
        # Trigger GC at threshold
        if percent >= self.gc_threshold or force:
            gc.collect()
            self._gc_count += 1
            actions.append("gc_collected")
        
        # Aggressive cleanup at max threshold
        if percent >= self.max_memory_percent or force:
            # Clear response cache
            response_cache.clear()
            url_cache.clear()
            actions.append("response_cache_cleared")
            
            # Force garbage collection
            for _ in range(3):
                gc.collect()
            
            self._cleanup_count += 1
            actions.append("aggressive_cleanup")
        
        return {
            "actions": actions,
            "memory": self.get_memory_usage(),
            "gc_count": self._gc_count,
            "cleanup_count": self._cleanup_count,
        }
    
    def get_stats(self) -> Dict:
        """Get memory manager statistics."""
        return {
            "current_memory": self.get_memory_usage(),
            "gc_count": self._gc_count,
            "cleanup_count": self._cleanup_count,
            "avg_memory_percent": round(
                sum(self._memory_history) / max(len(self._memory_history), 1), 1
            ) if self._memory_history else 0,
            "peak_memory_percent": max(self._memory_history) if self._memory_history else 0,
        }


# ═══════════════════════════════════════════════════════════════
# ASYNC TASK ORCHESTRATOR v50
# ═══════════════════════════════════════════════════════════════

class AsyncTaskOrchestrator:
    """
    🎯 ASYNC TASK ORCHESTRATOR v50 — Advanced Async Task Management.
    
    Features:
    - Task prioritization
    - Concurrent task limiting
    - Task dependency management
    - Task timeout handling
    - Task retry with backoff
    - Progress tracking
    - Graceful shutdown
    - Task cancellation
    - Result aggregation
    
    Connected to: All async modules
    """
    
    def __init__(
        self,
        max_concurrent: int = 50,
        default_timeout: int = 30,
        max_retries: int = 3,
    ):
        """
        Initialize Async Task Orchestrator v50.
        
        Args:
            max_concurrent: Maximum concurrent tasks
            default_timeout: Default task timeout
            max_retries: Maximum retries per task
        """
        self.max_concurrent = max_concurrent
        self.default_timeout = default_timeout
        self.max_retries = max_retries
        
        self._semaphore = asyncio.Semaphore(max_concurrent)
        self._running_tasks: Set[asyncio.Task] = set()
        self._completed: int = 0
        self._failed: int = 0
        self._lock = asyncio.Lock()
    
    async def run_task(
        self,
        coro: Callable[..., Any],
        *args,
        priority: int = 0,
        timeout: int = None,
        retries: int = None,
        **kwargs,
    ) -> Any:
        """
        Run a single task with concurrency control.
        
        Args:
            coro: Async callable
            *args: Positional arguments
            priority: Task priority (lower = higher priority)
            timeout: Task timeout override
            retries: Retry count override
            **kwargs: Keyword arguments
            
        Returns:
            Task result
            
        Raises:
            Exception: If task fails after all retries
        """
        timeout = timeout or self.default_timeout
        retries = retries if retries is not None else self.max_retries
        
        # Wait for semaphore (with priority-aware waiting)
        async with self._semaphore:
            last_error = None
            
            for attempt in range(retries + 1):
                try:
                    result = await asyncio.wait_for(
                        coro(*args, **kwargs),
                        timeout=timeout,
                    )
                    
                    async with self._lock:
                        self._completed += 1
                    
                    return result
                
                except asyncio.TimeoutError:
                    last_error = asyncio.TimeoutError(f"Task timed out after {timeout}s")
                    if attempt < retries:
                        await asyncio.sleep(2 ** attempt)
                
                except Exception as e:
                    last_error = e
                    if attempt < retries:
                        await asyncio.sleep(2 ** attempt)
            
            async with self._lock:
                self._failed += 1
            
            raise last_error
    
    async def run_batch(
        self,
        tasks: List[Tuple[Callable, tuple, dict]],
        return_exceptions: bool = True,
    ) -> List[Any]:
        """
        Run a batch of tasks concurrently.
        
        Args:
            tasks: List of (coro, args, kwargs) tuples
            return_exceptions: Return exceptions instead of raising
            
        Returns:
            List of results
        """
        async def wrapped_task(coro, args, kwargs):
            try:
                return await self.run_task(coro, *args, **kwargs)
            except Exception as e:
                if return_exceptions:
                    return e
                raise
        
        coros = [wrapped_task(c, a, k) for c, a, k in tasks]
        results = await asyncio.gather(*coros, return_exceptions=return_exceptions)
        return results
    
    async def shutdown(self, timeout: float = 10.0) -> None:
        """Graceful shutdown — cancel all running tasks."""
        for task in self._running_tasks:
            if not task.done():
                task.cancel()
        
        if self._running_tasks:
            await asyncio.wait(self._running_tasks, timeout=timeout)
    
    def get_stats(self) -> Dict:
        """Get orchestrator statistics."""
        return {
            "max_concurrent": self.max_concurrent,
            "completed": self._completed,
            "failed": self._failed,
            "success_rate": round(
                self._completed / max(self._completed + self._failed, 1) * 100, 1
            ),
        }


# ═══════════════════════════════════════════════════════════════
# ADVANCED REPORTING ENGINE v50 — Charts, Graphs, Timeline
# ═══════════════════════════════════════════════════════════════

class AdvancedReportingEngine:
    """
    📊 ADVANCED REPORTING ENGINE v50 — Professional Visualization.
    
    Features:
    - ASCII art charts (severity distribution, timeline)
    - Vulnerability timeline visualization
    - OWASP Top 10 mapping visualization
    - CWE distribution charts
    - Scan progress timeline
    - Executive summary generation
    - Finding correlation matrix
    - Risk score calculation (CVSS-based)
    - Remediation prioritization
    - PDF report generation with charts
    
    Connected to: ReportGenerator, ZombieDatabase
    """
    
    def __init__(self, output_dir: str = "./zombie_reports"):
        self.output_dir = Path(output_dir)
        self.output_dir.mkdir(parents=True, exist_ok=True)
    
    def generate_ascii_chart(
        self, data: Dict[str, int], title: str = "", max_width: int = 50
    ) -> str:
        """
        Generate ASCII bar chart.
        
        Args:
            data: Dict of label → count
            title: Chart title
            max_width: Maximum bar width
            
        Returns:
            ASCII chart string
        """
        if not data:
            return "No data available"
        
        max_value = max(data.values())
        chart = f"\n{'═'*60}\n"
        chart += f"  {title}\n"
        chart += f"{'═'*60}\n"
        
        for label, count in sorted(data.items(), key=lambda x: x[1], reverse=True):
            bar_width = int((count / max(max_value, 1)) * max_width)
            bar = "█" * bar_width
            chart += f"  {label:20s} │ {bar} {count}\n"
        
        chart += f"{'─'*60}\n"
        return chart
    
    def generate_severity_chart(self, findings: List[Dict]) -> str:
        """Generate severity distribution ASCII chart."""
        severity_counts = Counter(f.get("severity", "INFO").upper() for f in findings)
        
        severity_order = ["CRITICAL", "HIGH", "MEDIUM", "LOW", "INFO"]
        severity_colors = {
            "CRITICAL": C.CRITICAL, "HIGH": C.HIGH,
            "MEDIUM": C.MEDIUM, "LOW": C.LOW, "INFO": C.INFO,
        }
        
        chart = f"\n{C.BOLD}{'═'*60}{C.RST}\n"
        chart += f"{C.BOLD}  📊 SEVERITY DISTRIBUTION{C.RST}\n"
        chart += f"{C.BOLD}{'═'*60}{C.RST}\n"
        
        max_count = max(severity_counts.values()) if severity_counts else 1
        
        for sev in severity_order:
            count = severity_counts.get(sev, 0)
            if count > 0:
                bar_width = int((count / max_count) * 40)
                bar = "█" * bar_width
                color = severity_colors.get(sev, C.WHITE)
                chart += f"  {color}{sev:8s}{C.RST} │ {bar} {count}\n"
        
        chart += f"{C.DIM}{'─'*60}{C.RST}\n"
        return chart
    
    def generate_timeline_chart(self, findings: List[Dict]) -> str:
        """
        Generate vulnerability discovery timeline.
        
        Args:
            findings: List of findings with timestamps
            
        Returns:
            ASCII timeline chart
        """
        if not findings:
            return "No findings to generate timeline"
        
        # Group by hour
        timeline = defaultdict(lambda: defaultdict(int))
        
        for f in findings:
            ts = f.get("timestamp", "")
            if ts:
                try:
                    dt = datetime.fromisoformat(str(ts).replace("Z", "+00:00"))
                    hour_key = dt.strftime("%Y-%m-%d %H:00")
                    severity = f.get("severity", "INFO").upper()
                    timeline[hour_key][severity] += 1
                except Exception:
                    pass
        
        if not timeline:
            return "No timestamped findings"
        
        chart = f"\n{C.BOLD}{'═'*60}{C.RST}\n"
        chart += f"{C.BOLD}  📅 VULNERABILITY TIMELINE{C.RST}\n"
        chart += f"{C.BOLD}{'═'*60}{C.RST}\n"
        
        for hour in sorted(timeline.keys()):
            counts = timeline[hour]
            total = sum(counts.values())
            critical = counts.get("CRITICAL", 0)
            high = counts.get("HIGH", 0)
            
            bar = ""
            if critical > 0:
                bar += f"{C.CRITICAL}{'█' * min(critical, 10)}{C.RST}"
            if high > 0:
                bar += f"{C.HIGH}{'█' * min(high, 10)}{C.RST}"
            
            chart += f"  {hour} │ {bar} {total}\n"
        
        chart += f"{C.DIM}{'─'*60}{C.RST}\n"
        return chart
    
    def generate_owasp_chart(self, findings: List[Dict]) -> str:
        """Generate OWASP Top 10 distribution chart."""
        owasp_mapping = {
            "sql": "A03: Injection",
            "sqli": "A03: Injection",
            "xss": "A03: Injection",
            "ssti": "A03: Injection",
            "cmdi": "A03: Injection",
            "lfi": "A01: Broken Access Control",
            "idor": "A01: Broken Access Control",
            "ssrf": "A10: SSRF",
            "xxe": "A05: Security Misconfiguration",
            "jwt": "A07: Auth Failures",
            "oauth": "A07: Auth Failures",
            "csrf": "A01: Broken Access Control",
            "cors": "A05: Security Misconfiguration",
            "open redirect": "A01: Broken Access Control",
            "file upload": "A03: Injection",
            "subdomain takeover": "A06: Vulnerable Components",
            "cloud credential": "A05: Security Misconfiguration",
            "sensitive file": "A05: Security Misconfiguration",
        }
        
        owasp_counts = defaultdict(int)
        for f in findings:
            vt = f.get("vuln_type", "").lower()
            owasp = owasp_mapping.get(vt, "Other")
            owasp_counts[owasp] += 1
        
        return self.generate_ascii_chart(dict(owasp_counts), "OWASP TOP 10 DISTRIBUTION")
    
    def generate_executive_summary(self, findings: List[Dict], target: str, scan_type: str) -> str:
        """
        Generate executive summary for management.
        
        Args:
            findings: List of findings
            target: Target domain
            scan_type: Type of scan
            
        Returns:
            Executive summary string
        """
        severity_counts = Counter(f.get("severity", "INFO").upper() for f in findings)
        vuln_types = Counter(f.get("vuln_type", "Unknown") for f in findings)
        
        summary = f"""
{C.BOLD}{'═'*70}{C.RST}
{C.BOLD}  📋 EXECUTIVE SUMMARY{C.RST}
{C.BOLD}{'═'*70}{C.RST}

  Target:        {target}
  Scan Type:     {scan_type}
  Date:          {datetime.now().strftime('%Y-%m-%d %H:%M:%S')} UTC
  Total Issues:  {len(findings)}

  {C.BOLD}Critical Findings:{C.RST} {severity_counts.get('CRITICAL', 0)}
  {C.BOLD}High Findings:{C.RST}     {severity_counts.get('HIGH', 0)}
  {C.BOLD}Medium Findings:{C.RST}   {severity_counts.get('MEDIUM', 0)}
  {C.BOLD}Low Findings:{C.RST}      {severity_counts.get('LOW', 0)}

  {C.BOLD}Top Vulnerability Types:{C.RST}
"""
        
        for vt, count in vuln_types.most_common(5):
            summary += f"    • {vt}: {count}\n"
        
        # Calculate risk score
        risk_weights = {"CRITICAL": 10, "HIGH": 5, "MEDIUM": 2, "LOW": 1, "INFO": 0}
        total_risk = sum(risk_weights.get(f.get("severity", "INFO").upper(), 0) for f in findings)
        
        if total_risk >= 50:
            risk_level = "CRITICAL"
        elif total_risk >= 25:
            risk_level = "HIGH"
        elif total_risk >= 10:
            risk_level = "MEDIUM"
        else:
            risk_level = "LOW"
        
        summary += f"""
  {C.BOLD}Overall Risk Score:{C.RST} {total_risk} ({risk_level})

  {C.BOLD}Recommendations:{C.RST}
    1. Prioritize critical and high severity findings
    2. Patch all injection vulnerabilities immediately
    3. Implement proper access controls
    4. Review security configurations
    5. Conduct regular security assessments

{C.BOLD}{'═'*70}{C.RST}
"""
        
        return summary
    
    def generate_remediation_plan(self, findings: List[Dict]) -> str:
        """
        Generate prioritized remediation plan.
        
        Args:
            findings: List of findings
            
        Returns:
            Remediation plan string
        """
        plan = f"\n{C.BOLD}{'═'*70}{C.RST}\n"
        plan += f"{C.BOLD}  🔧 REMEDIATION PLAN (Prioritized){C.RST}\n"
        plan += f"{C.BOLD}{'═'*70}{C.RST}\n\n"
        
        # Sort by severity then confidence
        severity_order = {"CRITICAL": 0, "HIGH": 1, "MEDIUM": 2, "LOW": 3, "INFO": 4}
        sorted_findings = sorted(
            findings,
            key=lambda f: (
                severity_order.get(f.get("severity", "INFO").upper(), 99),
                -(f.get("confidence", 0)),
            )
        )
        
        priority = 1
        for f in sorted_findings[:20]:
            severity = f.get("severity", "INFO").upper()
            vuln_type = f.get("vuln_type", "Unknown")
            url = f.get("url", "N/A")[:60]
            
            sev_icon = {"CRITICAL": "🔴", "HIGH": "🟠", "MEDIUM": "🟡", "LOW": "🟢", "INFO": "🔵"}.get(severity, "⚪")
            
            remediation = self._get_remediation(vuln_type)
            
            plan += f"  {priority:2d}. {sev_icon} [{severity}] {vuln_type}\n"
            plan += f"      URL: {url}\n"
            plan += f"      Fix: {remediation}\n\n"
            
            priority += 1
        
        plan += f"{C.DIM}{'═'*70}{C.RST}\n"
        return plan
    
    def _get_remediation(self, vuln_type: str) -> str:
        """Get remediation advice for vulnerability type."""
        vuln_lower = vuln_type.lower()
        
        remediations = {
            "sqli": "Use parameterized queries/prepared statements. Never concatenate user input into SQL.",
            "xss": "Implement proper output encoding (HTML entity encoding). Use CSP headers.",
            "ssti": "Never pass user input directly to template engines. Use sandboxed templates.",
            "lfi": "Use whitelist for file inclusion. Avoid user input in file paths. Use basename().",
            "ssrf": "Implement URL whitelist. Block internal IPs. Disable unnecessary protocols.",
            "cmdi": "Use exec() with array arguments. Avoid shell=True. Use subprocess.run().",
            "xxe": "Disable external entities in XML parser. Use JSON instead of XML where possible.",
            "idor": "Implement proper authorization checks. Use random/unguessable IDs.",
            "csrf": "Implement CSRF tokens. Use SameSite cookies. Check Referer/Origin headers.",
            "cors": "Restrict Access-Control-Allow-Origin to specific domains. Validate Origin header.",
            "jwt": "Use strong secrets. Implement proper algorithm validation. Set expiration times.",
            "open redirect": "Use whitelist for redirect URLs. Use relative paths. Validate target.",
            "file upload": "Validate file types by content, not extension. Store files outside web root.",
            "subdomain takeover": "Remove dangling DNS records. Verify service ownership regularly.",
        }
        
        for key, remediation in remediations.items():
            if key in vuln_lower:
                return remediation
        
        return "Review and apply security best practices for this vulnerability type."
    
    def generate_full_report(
        self, findings: List[Dict], target: str, scan_type: str, zombie_identity: Dict = None
    ) -> str:
        """
        Generate complete advanced report with all visualizations.
        
        Args:
            findings: List of findings
            target: Target domain
            scan_type: Type of scan
            zombie_identity: Zombie identity info
            
        Returns:
            Complete report string
        """
        report = f"""
{C.CYAN}{C.BOLD}{'═'*70}{C.RST}
{C.CYAN}{C.BOLD}  🧟 ZOMBIE ULTIMATE v50.0.0 — FULL REPORT{C.RST}
{C.CYAN}{C.BOLD}  PHANTOM REQUIEM{C.RST}
{C.CYAN}{C.BOLD}{'═'*70}{C.RST}
"""
        
        # Executive Summary
        report += self.generate_executive_summary(findings, target, scan_type)
        
        # Severity Chart
        report += self.generate_severity_chart(findings)
        
        # OWASP Chart
        report += self.generate_owasp_chart(findings)
        
        # Timeline
        report += self.generate_timeline_chart(findings)
        
        # Remediation Plan
        report += self.generate_remediation_plan(findings)
        
        # Detailed Findings
        report += f"\n{C.BOLD}{'═'*70}{C.RST}\n"
        report += f"{C.BOLD}  🔍 DETAILED FINDINGS{C.RST}\n"
        report += f"{C.BOLD}{'═'*70}{C.RST}\n\n"
        
        for i, finding in enumerate(findings):
            report += f"  {C.BOLD}#{i+1} [{finding.get('severity', 'INFO')}] {finding.get('vuln_type', 'Unknown')}{C.RST}\n"
            report += f"  URL:        {finding.get('url', 'N/A')[:80]}\n"
            report += f"  Parameter:  {finding.get('param', 'N/A')}\n"
            report += f"  Confidence: {finding.get('confidence', 0)}%\n"
            report += f"  Evidence:   {str(finding.get('evidence', 'N/A'))[:150]}\n"
            report += f"  {'─'*50}\n\n"
        
        return report
    
    def save_report(self, content: str, target: str, format: str = "txt") -> Path:
        """Save report to file."""
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        target_slug = re.sub(r'[^a-zA-Z0-9]', '_', target)
        filename = f"advanced_report_{target_slug}_{ts}.{format}"
        path = self.output_dir / filename
        
        with open(path, 'w', encoding='utf-8') as f:
            f.write(content)
        
        return path


# ═══════════════════════════════════════════════════════════════
# FINDING CORRELATOR v50 — Advanced Finding Analysis
# ═══════════════════════════════════════════════════════════════

class FindingCorrelator:
    """
    🔗 FINDING CORRELATOR v50 — Advanced Finding Correlation & Analysis.
    
    Features:
    - URL-based correlation
    - Parameter-based correlation
    - Vulnerability type clustering
    - Attack surface mapping
    - Risk heatmap generation
    - Finding deduplication (fuzzy matching)
    - Finding chain detection (vuln A leads to vuln B)
    - Technology-based risk assessment
    
    Connected to: Database, FilterPipeline
    """
    
    def __init__(self):
        """Initialize Finding Correlator v50."""
        self._url_index: Dict[str, List[Dict]] = defaultdict(list)
        self._param_index: Dict[str, List[Dict]] = defaultdict(list)
        self._type_index: Dict[str, List[Dict]] = defaultdict(list)
        self._chains: List[List[Dict]] = []
    
    def index_findings(self, findings: List[Dict]) -> None:
        """Index findings for fast correlation."""
        for f in findings:
            url = f.get('url', '')
            param = f.get('param', '')
            vuln_type = f.get('vuln_type', '')
            
            self._url_index[url].append(f)
            if param:
                self._param_index[param].append(f)
            self._type_index[vuln_type].append(f)
    
    def find_related(self, finding: Dict) -> List[Dict]:
        """Find findings related to a specific finding."""
        related = []
        url = finding.get('url', '')
        param = finding.get('param', '')
        vuln_type = finding.get('vuln_type', '')
        finding_id = finding.get('id', '')
        
        # Find by URL
        for f in self._url_index.get(url, []):
            if f.get('id') != finding_id:
                related.append(f)
        
        # Find by parameter
        if param:
            for f in self._param_index.get(param, []):
                if f.get('id') != finding_id and f not in related:
                    related.append(f)
        
        return related
    
    def detect_chains(self) -> List[List[Dict]]:
        """
        Detect vulnerability chains (A leads to B leads to C).
        
        Example: LFI → Config file read → Database credentials → SQLi
        """
        chains = []
        
        # Chain: LFI → Credential Leak → SQLi
        lfi_findings = self._type_index.get('Local File Inclusion', [])
        lfi_findings.extend(self._type_index.get('Path Traversal', []))
        cred_findings = self._type_index.get('Sensitive File Exposure', [])
        sqli_findings = self._type_index.get('SQL Injection', [])
        
        for lfi in lfi_findings:
            lfi_url = lfi.get('url', '')
            lfi_domain = urlparse(lfi_url).netloc
            
            for cred in cred_findings:
                cred_url = cred.get('url', '')
                cred_domain = urlparse(cred_url).netloc
                
                if lfi_domain == cred_domain:
                    for sqli in sqli_findings:
                        sqli_url = sqli.get('url', '')
                        sqli_domain = urlparse(sqli_url).netloc
                        
                        if cred_domain == sqli_domain:
                            chains.append([lfi, cred, sqli])
        
        # Chain: SSRF → Cloud Metadata → Credential Leak
        ssrf_findings = self._type_index.get('SSRF', [])
        cloud_findings = self._type_index.get('Cloud Credential Leak', [])
        
        for ssrf in ssrf_findings:
            for cloud in cloud_findings:
                chains.append([ssrf, cloud])
        
        self._chains = chains
        return chains
    
    def generate_attack_surface_map(self) -> Dict:
        """Generate attack surface mapping."""
        attack_surface = {
            "total_endpoints": len(self._url_index),
            "vulnerable_endpoints": len([u for u, fs in self._url_index.items() if fs]),
            "total_params": len(self._param_index),
            "vulnerable_params": len([p for p, fs in self._param_index.items() if fs]),
            "vuln_types": dict(Counter(
                f.get('vuln_type', 'Unknown')
                for fs in self._type_index.values()
                for f in fs
            )),
            "chains_detected": len(self._chains),
        }
        
        return attack_surface
    
    def clear(self) -> None:
        """Clear all indices."""
        self._url_index.clear()
        self._param_index.clear()
        self._type_index.clear()
        self._chains.clear()


# ═══════════════════════════════════════════════════════════════
# SCAN SCHEDULER v50 — Automated Periodic Scanning
# ═══════════════════════════════════════════════════════════════

class ScanScheduler:
    """
    ⏰ SCAN SCHEDULER v50 — Automated Periodic Scanning.
    
    Features:
    - Cron-like scheduling
    - Multiple scan profiles
    - Concurrent scan limiting
    - Scan result comparison (delta detection)
    - Notification on new findings
    - Automatic database maintenance
    
    Connected to: ZombieExploitationTrinity, Database
    """
    
    def __init__(self, db: Optional[ZombieDatabase] = None):
        """
        Initialize Scan Scheduler v50.
        
        Args:
            db: Database instance
        """
        self.db = db
        self._scheduled_scans: List[Dict] = []
        self._running = False
    
    def add_schedule(
        self,
        target: str,
        scan_type: str = "full",
        interval_hours: int = 24,
        config: Dict = None,
    ) -> str:
        """
        Add a scheduled scan.
        
        Args:
            target: Target domain
            scan_type: Type of scan
            interval_hours: Interval in hours
            config: Optional scan configuration
            
        Returns:
            Schedule ID
        """
        schedule_id = dhash(f"{target}{time.time()}", 12)
        
        self._scheduled_scans.append({
            "id": schedule_id,
            "target": target,
            "scan_type": scan_type,
            "interval_hours": interval_hours,
            "config": config or {},
            "last_run": None,
            "next_run": datetime.now() + timedelta(hours=interval_hours),
            "run_count": 0,
            "enabled": True,
        })
        
        return schedule_id
    
    async def run_pending_scans(self, trinity_factory: Callable) -> List[Dict]:
        """
        Run all pending scheduled scans.
        
        Args:
            trinity_factory: Function to create ZombieExploitationTrinity instances
            
        Returns:
            List of scan results
        """
        results = []
        now = datetime.now()
        
        for schedule in self._scheduled_scans:
            if not schedule["enabled"]:
                continue
            
            if schedule["next_run"] and schedule["next_run"] <= now:
                print(f"\n{C.CYAN}[SCHEDULER] Running: {schedule['target']} ({schedule['scan_type']}){C.RST}")
                
                try:
                    trinity = trinity_factory(
                        domain=schedule["target"],
                        config=schedule["config"],
                    )
                    
                    result = await trinity.execute_full_apocalypse(
                        target_url=f"https://www.{schedule['target']}",
                    )
                    
                    schedule["last_run"] = now
                    schedule["next_run"] = now + timedelta(hours=schedule["interval_hours"])
                    schedule["run_count"] += 1
                    
                    results.append({
                        "schedule_id": schedule["id"],
                        "target": schedule["target"],
                        "result": result,
                    })
                    
                    await trinity.cleanup()
                
                except Exception as e:
                    print(f"  {C.RED}[SCHEDULER] Error: {e}{C.RST}")
        
        return results
    
    def get_stats(self) -> Dict:
        """Get scheduler statistics."""
        return {
            "scheduled_scans": len(self._scheduled_scans),
            "enabled": sum(1 for s in self._scheduled_scans if s["enabled"]),
            "total_runs": sum(s["run_count"] for s in self._scheduled_scans),
            "next_run": min(
                (s["next_run"] for s in self._scheduled_scans if s["enabled"] and s["next_run"]),
                default=None,
            ),
        }


