# RATE LIMIT DETECTOR v50 — Advanced Rate Limiting Detection
# ═══════════════════════════════════════════════════════════════

class RateLimitDetector:
    """
    🚦 RATE LIMIT DETECTOR v50 — Detect & Bypass Rate Limiting.
    
    Features:
    - Automatic rate limit detection
    - Threshold discovery (requests per window)
    - Window size detection (seconds)
    - Status code tracking (429, 503)
    - Retry-After header parsing
    - Rate limit bypass techniques:
      - IP rotation (via proxies)
      - Header manipulation (X-Forwarded-For, X-Real-IP)
      - Parameter pollution
      - Endpoint switching
      - User-Agent rotation
      - Session token rotation
    - Burst mode detection
    - Per-endpoint vs global rate limit detection
    
    Connected to: SessionManager, Zombie, All HTTP modules
    """
    
    def __init__(
        self,
        zombie_instance: Optional[Zombie] = None,
        proxy_list: Optional[List[str]] = None,
        max_probes: int = 100,
    ):
        """
        Initialize Rate Limit Detector v50.
        
        Args:
            zombie_instance: Optional Zombie instance
            proxy_list: Optional list of proxy URLs
            max_probes: Maximum probe requests
        """
        self._zombie = zombie_instance
        self.proxy_list = proxy_list or []
        self.max_probes = max_probes
        
        self.rate_limits: Dict[str, Dict] = {}
        self.detection_history: List[Dict] = []
        self.stats = Counter()
    
    async def detect_rate_limit(
        self, session, url: str, method: str = "GET"
    ) -> Dict:
        """
        Detect rate limiting on an endpoint.
        
        Args:
            session: SessionManager instance
            url: Target URL
            method: HTTP method
            
        Returns:
            Rate limit detection result
        """
        result = {
            "url": url,
            "rate_limited": False,
            "threshold": None,
            "window_seconds": None,
            "status_codes": [],
            "retry_after": None,
            "bypass_methods": [],
        }
        
        # Phase 1: Rapid fire to detect limit
        statuses = []
        retry_headers = []
        rate_limited_at = None
        
        for i in range(min(self.max_probes, 50)):
            try:
                headers = {}
                if self._zombie:
                    headers = self._zombie.get_headers(url)
                
                resp = await session.fetch(url, method=method, headers=headers, timeout=5)
                status = resp.get('status', 0)
                statuses.append(status)
                
                if status == 429:
                    retry_after = resp.get('headers', {}).get('Retry-After', '')
                    if retry_after:
                        retry_headers.append(retry_after)
                    
                    if rate_limited_at is None:
                        rate_limited_at = i + 1
                
                if status in [429, 503]:
                    result["rate_limited"] = True
                    break
                
                # Small delay between requests
                await asyncio.sleep(0.05)
            
            except Exception:
                break
        
        if rate_limited_at:
            result["threshold"] = rate_limited_at
            result["status_codes"] = statuses
        
        if retry_headers:
            try:
                result["retry_after"] = int(retry_headers[0])
                result["window_seconds"] = result["retry_after"]
            except ValueError:
                pass
        
        # Phase 2: Test bypass methods
        if result["rate_limited"]:
            bypass_methods = await self._test_bypasses(session, url, method)
            result["bypass_methods"] = bypass_methods
        
        self.detection_history.append(result)
        self.rate_limits[url] = result
        
        return result
    
    async def _test_bypasses(
        self, session, url: str, method: str
    ) -> List[str]:
        """Test rate limit bypass techniques."""
        working_bypasses = []
        
        bypass_tests = [
            {
                "name": "X-Forwarded-For",
                "headers": {"X-Forwarded-For": f"127.0.0.{random.randint(1, 255)}"},
            },
            {
                "name": "X-Real-IP",
                "headers": {"X-Real-IP": f"10.0.0.{random.randint(1, 255)}"},
            },
            {
                "name": "User-Agent rotation",
                "headers": {"User-Agent": random_user_agent()},
            },
            {
                "name": "Accept-Encoding vary",
                "headers": {"Accept-Encoding": random.choice(["gzip", "deflate", "br", "identity"])},
            },
        ]
        
        for test in bypass_tests:
            try:
                headers = test["headers"].copy()
                if self._zombie:
                    headers.update(self._zombie.get_headers(url))
                
                resp = await session.fetch(url, method=method, headers=headers, timeout=5)
                
                if resp.get('status') not in [429, 503]:
                    working_bypasses.append(test["name"])
                    self.stats[f"bypass_{test['name']}"] += 1
                
                await asyncio.sleep(1)
            
            except Exception:
                continue
        
        return working_bypasses
    
    def get_stats(self) -> Dict:
        """Get rate limit detector statistics."""
        return {
            "endpoints_tested": len(self.rate_limits),
            "rate_limited_endpoints": sum(
                1 for r in self.rate_limits.values() if r.get("rate_limited")
            ),
            "bypass_stats": dict(self.stats),
            "avg_threshold": int(
                statistics.mean(
                    [r.get("threshold", 0) for r in self.rate_limits.values() if r.get("threshold")]
                )
            ) if self.rate_limits else 0,
        }


