# WAF FINGERPRINTING 2.0 v50 — Behavioral WAF Analysis
# ═══════════════════════════════════════════════════════════════

class WAFFingerprintingV2:
    """
    🛡️ WAF FINGERPRINTING 2.0 v50 — Behavioral WAF Analysis.
    
    Features:
    - Active WAF probing (safe payloads)
    - Response timing analysis
    - Header ordering analysis
    - Cookie behavior analysis
    - Challenge detection (JS, Captcha, reCAPTCHA)
    - WAF version detection
    - Rule update detection
    - Bypass success rate tracking per WAF
    
    Connected to: ZombieWAFZero, Advanced WAF DB
    """
    
    BEHAVIORAL_PROBES: ClassVar[List[Dict]] = [
        {"name": "basic_sqli", "payload": "' OR 1=1--", "type": "sqli", "safe": True},
        {"name": "basic_xss", "payload": "<script>test</script>", "type": "xss", "safe": True},
        {"name": "basic_path", "payload": "../../../etc/passwd", "type": "lfi", "safe": True},
        {"name": "double_encoded", "payload": "%2527%2520OR%25201=1--", "type": "sqli_encoded", "safe": True},
        {"name": "null_byte", "payload": "test.php%00.jpg", "type": "null_byte", "safe": True},
        {"name": "unicode", "payload": "測試", "type": "unicode", "safe": True},
        {"name": "long_string", "payload": "A" * 5000, "type": "buffer", "safe": True},
        {"name": "special_chars", "payload": "!@#$%^&*()_+-=[]{}|;:',.<>?/~`", "type": "special", "safe": True},
    ]
    
    def __init__(self, zombie_instance: Optional[Zombie] = None):
        """
        Initialize WAF Fingerprinting 2.0 v50.
        
        Args:
            zombie_instance: Optional Zombie instance
        """
        self._zombie = zombie_instance
        self.waf_profiles: Dict[str, Dict] = {}
        self.behavioral_data: Dict[str, Dict] = defaultdict(dict)
        self.stats = Counter()
    
    async def fingerprint_behavioral(self, session, url: str, param: str = "q") -> Dict:
        """
        Perform behavioral WAF fingerprinting.
        
        Args:
            session: SessionManager instance
            url: Target URL
            param: Parameter to test
            
        Returns:
            WAF behavioral profile
        """
        profile = {
            "url": url,
            "waf_detected": None,
            "waf_confidence": 0.0,
            "response_patterns": {},
            "challenge_type": None,
            "block_behaviors": [],
            "bypass_hints": [],
        }
        
        # Phase 1: Send safe probes and analyze responses
        baseline_resp = await session.fetch(url, timeout=10)
        baseline_time = baseline_resp.get('elapsed', 0)
        baseline_size = len(baseline_resp.get('text', ''))
        baseline_headers = baseline_resp.get('headers', {})
        
        for probe in self.BEHAVIORAL_PROBES:
            test_url = inject_payload(url, param, probe["payload"])
            
            try:
                resp = await session.fetch(test_url, timeout=10)
                status = resp.get('status', 0)
                resp_time = resp.get('elapsed', 0)
                resp_size = len(resp.get('text', ''))
                resp_text = (resp.get('text', '') or '').lower()
                
                # Analyze response
                behavior = {
                    "probe": probe["name"],
                    "status": status,
                    "blocked": status in [403, 406, 429, 501, 502, 503],
                    "time_diff_ms": round((resp_time - baseline_time) * 1000, 1),
                    "size_diff": resp_size - baseline_size,
                }
                
                # Detect challenge type
                if "captcha" in resp_text or "recaptcha" in resp_text:
                    profile["challenge_type"] = "captcha"
                    behavior["challenge"] = "captcha"
                elif "cf-challenge" in resp_text or "jschal" in resp_text:
                    profile["challenge_type"] = "js_challenge"
                    behavior["challenge"] = "js_challenge"
                elif "attention required" in resp_text:
                    profile["challenge_type"] = "browser_check"
                    behavior["challenge"] = "browser_check"
                
                if behavior["blocked"]:
                    profile["block_behaviors"].append(behavior)
                
                profile["response_patterns"][probe["name"]] = behavior
                
                await asyncio.sleep(0.3)
            
            except Exception:
                continue
        
        # Phase 2: Match against WAF database
        waf_result = detect_waf_advanced(baseline_resp)
        if waf_result:
            profile["waf_detected"] = waf_result
            profile["waf_confidence"] = 0.8
            
            # Get bypass hints from WAF DB
            waf_info = ADVANCED_WAF_DB.get(waf_result, {})
            profile["bypass_hints"] = waf_info.get("bypass_hints", [])
        
        self.waf_profiles[url] = profile
        return profile
    
    def get_bypass_recommendations(self, waf_name: str) -> List[str]:
        """Get bypass recommendations for a specific WAF."""
        waf_info = ADVANCED_WAF_DB.get(waf_name, {})
        return waf_info.get("bypass_hints", [])
    
    def get_stats(self) -> Dict:
        """Get WAF fingerprinting statistics."""
        return {
            "profiles_generated": len(self.waf_profiles),
            "wafs_detected": Counter(
                p.get("waf_detected", "Unknown")
                for p in self.waf_profiles.values()
            ),
            "challenge_types": Counter(
                p.get("challenge_type", "none")
                for p in self.waf_profiles.values()
            ),
        }


