# API SECURITY SCANNER v50 — REST/GraphQL/gRPC Security
# ═══════════════════════════════════════════════════════════════

class APISecurityScanner:
    """
    🔒 API SECURITY SCANNER v50 — Comprehensive API Security Testing.
    
    Features:
    - REST API security testing
    - GraphQL security testing
    - gRPC endpoint discovery
    - Authentication testing (JWT, OAuth, API Key)
    - Authorization testing (IDOR, privilege escalation)
    - Rate limiting detection
    - Input validation testing
    - Mass assignment detection
    - API version enumeration
    - Deprecated endpoint detection
    - Sensitive data exposure in responses
    - API documentation discovery
    
    Connected to: GraphQLScanner, JWTToolkit, OAuthFlowHijacker
    """
    
    API_PATTERNS: ClassVar[List[str]] = [
        '/api/', '/api/v1/', '/api/v2/', '/api/v3/',
        '/rest/', '/rest/v1/', '/rest/v2/',
        '/graphql', '/gql',
        '/swagger', '/swagger-ui', '/api-docs',
        '/openapi.json', '/swagger.json',
        '/.well-known/', '/.well-known/openid-configuration',
    ]
    
    SENSITIVE_DATA_PATTERNS: ClassVar[List[str]] = [
        r'(?i)"password"\s*:\s*"[^"]+"',
        r'(?i)"secret"\s*:\s*"[^"]+"',
        r'(?i)"token"\s*:\s*"[^"]+"',
        r'(?i)"api_key"\s*:\s*"[^"]+"',
        r'(?i)"access_key"\s*:\s*"[^"]+"',
        r'(?i)"private_key"\s*:\s*"[^"]+"',
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z]{2,}\b',
        r'\b\d{3}-\d{2}-\d{4}\b',  # SSN
        r'\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14})\b',  # Credit Card
    ]
    
    def __init__(
        self,
        target_url: str = "",
        zombie_instance: Optional[Zombie] = None,
        db: Optional[Any] = None,
    ):
        """
        Initialize API Security Scanner v50.
        
        Args:
            target_url: Target base URL
            zombie_instance: Optional Zombie instance
            db: Optional database instance
        """
        self.target_url = target_url.rstrip('/')
        self._zombie = zombie_instance
        self.db = db
        
        self.api_endpoints: List[str] = []
        self.vulnerabilities: List[Dict] = []
        self.stats = Counter()
    
    async def discover_endpoints(self, session) -> List[str]:
        """Discover API endpoints."""
        endpoints = []
        
        async def check(path: str) -> Optional[str]:
            url = f"{self.target_url}{path}"
            try:
                headers = {}
                if self._zombie:
                    headers = self._zombie.get_headers(url)
                
                resp = await session.fetch(url, headers=headers, timeout=10)
                
                if resp.get('status') in [200, 401, 403]:
                    content_type = resp.get('content_type', '').lower()
                    text = (resp.get('text', '') or '').lower()
                    
                    if any(t in content_type for t in ['json', 'xml', 'html']) or \
                       any(k in text for k in ['api', 'swagger', 'openapi', 'graphql', 'endpoint']):
                        return url
            except Exception:
                pass
            return None
        
        tasks = [check(p) for p in self.API_PATTERNS]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        
        for result in results:
            if isinstance(result, str) and result:
                endpoints.append(result)
        
        self.api_endpoints = endpoints
        return endpoints
    
    async def test_auth_required(self, session, endpoint: str) -> Dict:
        """Test if authentication is properly required."""
        result = {"auth_required": True, "evidence": ""}
        
        try:
            # Try without auth
            resp = await session.fetch(endpoint, timeout=10)
            
            if resp.get('status') in [200, 201, 202]:
                text = (resp.get('text', '') or '')
                if len(text) > 100:
                    result["auth_required"] = False
                    result["evidence"] = f"Endpoint accessible without auth — returned {len(text)} bytes"
        except Exception:
            pass
        
        return result
    
    async def test_sensitive_data_exposure(self, session, endpoint: str) -> Dict:
        """Test for sensitive data in API responses."""
        result = {"sensitive_data_found": False, "matches": []}
        
        try:
            headers = {}
            if self._zombie:
                headers = self._zombie.get_headers(endpoint)
            
            resp = await session.fetch(endpoint, headers=headers, timeout=10)
            text = (resp.get('text', '') or '')
            
            for pattern in self.SENSITIVE_DATA_PATTERNS:
                for match in re.finditer(pattern, text):
                    matched = match.group(0)
                    if len(matched) > 10:
                        result["sensitive_data_found"] = True
                        result["matches"].append({
                            "pattern": pattern,
                            "sample": matched[:50],
                        })
        except Exception:
            pass
        
        return result
    
    async def test_mass_assignment(self, session, endpoint: str) -> Dict:
        """Test for mass assignment vulnerability."""
        result = {"vulnerable": False, "evidence": ""}
        
        # Test with extra fields
        mass_assignment_payloads = [
            {"isAdmin": True, "role": "admin", "email": "test@test.com"},
            {"admin": True, "superuser": True, "permissions": ["*"]},
            {"plan": "enterprise", "is_trial": False, "balance": 999999},
        ]
        
        for payload in mass_assignment_payloads:
            try:
                headers = {"Content-Type": "application/json"}
                if self._zombie:
                    headers.update(self._zombie.get_headers(endpoint))
                
                resp = await session.fetch(
                    endpoint,
                    method="POST",
                    headers=headers,
                    json_data=payload,
                    timeout=10,
                )
                
                if resp.get('status') in [200, 201, 202]:
                    text = (resp.get('text', '') or '').lower()
                    if any(k.lower() in text for k in payload.keys()):
                        result["vulnerable"] = True
                        result["evidence"] = f"Extra fields accepted: {list(payload.keys())}"
                        break
            except Exception:
                continue
        
        return result
    
    async def full_scan(self, session) -> Dict:
        """Execute full API security scan."""
        print(f"\n{C.CYAN}{'═'*60}{C.RST}")
        print(f"{C.CYAN}  {I.SHIELD} API SECURITY SCANNER v50 — {self.target_url}{C.RST}")
        print(f"{C.CYAN}{'═'*60}{C.RST}")
        
        # Discover endpoints
        endpoints = await self.discover_endpoints(session)
        print(f"  {C.GREEN}├─ Endpoints: {len(endpoints)}{C.RST}")
        
        for endpoint in endpoints:
            print(f"\n  {C.MAGENTA}[SCANNING] {endpoint}{C.RST}")
            
            # Test auth required
            auth = await self.test_auth_required(session, endpoint)
            if not auth["auth_required"]:
                self.vulnerabilities.append({
                    "type": "api_missing_auth",
                    "severity": "HIGH",
                    "endpoint": endpoint,
                    "evidence": auth["evidence"],
                })
                print(f"  {C.RED}  {I.WARN} No auth required!{C.RST}")
            
            # Test sensitive data
            sensitive = await self.test_sensitive_data_exposure(session, endpoint)
            if sensitive["sensitive_data_found"]:
                self.vulnerabilities.append({
                    "type": "api_sensitive_data",
                    "severity": "CRITICAL",
                    "endpoint": endpoint,
                    "evidence": f"Found {len(sensitive['matches'])} sensitive patterns",
                })
                print(f"  {C.RED}  {I.WARN} Sensitive data exposed! ({len(sensitive['matches'])} matches){C.RST}")
            
            # Test mass assignment
            mass = await self.test_mass_assignment(session, endpoint)
            if mass["vulnerable"]:
                self.vulnerabilities.append({
                    "type": "api_mass_assignment",
                    "severity": "HIGH",
                    "endpoint": endpoint,
                    "evidence": mass["evidence"],
                })
                print(f"  {C.YELLOW}  {I.WARN} Mass assignment possible!{C.RST}")
        
        return self._build_report()
    
    def _build_report(self) -> Dict:
        """Build API security report."""
        return {
            "target": self.target_url,
            "endpoints_found": self.api_endpoints,
            "vulnerabilities": self.vulnerabilities,
            "stats": dict(self.stats),
        }


# ═══════════════════════════════════════════════════════════════
# DOCKER SCANNER v50 — Container Security Analysis
# ═══════════════════════════════════════════════════════════════

class DockerScanner:
    """
    🐳 DOCKER SCANNER v50 — Container Security Analysis.
    
    Features:
    - Docker socket exposure detection
    - Docker Registry vulnerability scan
    - Container escape detection
    - Privileged container detection
    - Mounted socket detection
    - Environment variable leak
    - Image vulnerability scanning (Trivy integration)
    - Kubernetes API exposure
    - Helm/Tiller exposure
    - Container runtime security
    
    Connected to: CloudMetadataExfiltrator, Database
    """
    
    DOCKER_ENDPOINTS: ClassVar[List[str]] = [
        '/var/run/docker.sock',
        '/run/docker.sock',
        '/var/run/docker.sock:',
        '/containers/json',
        '/info',
        '/version',
        '/images/json',
        '/networks',
        '/volumes',
    ]
    
    K8S_ENDPOINTS: ClassVar[List[str]] = [
        'https://kubernetes.default.svc/',
        'https://kubernetes.default.svc/api/v1/',
        'https://kubernetes.default.svc/api/v1/namespaces/',
        'https://kubernetes.default.svc/api/v1/secrets/',
        'https://kubernetes.default.svc/api/v1/pods/',
        '/api/v1/namespaces/default/secrets/',
        '/api/v1/namespaces/kube-system/secrets/',
        '/version',
        '/healthz',
        '/metrics',
    ]
    
    def __init__(
        self,
        target_url: str = "",
        zombie_instance: Optional[Zombie] = None,
        db: Optional[Any] = None,
    ):
        """
        Initialize Docker Scanner v50.
        
        Args:
            target_url: Target base URL
            zombie_instance: Optional Zombie instance
            db: Optional database instance
        """
        self.target_url = target_url
        self._zombie = zombie_instance
        self.db = db
        
        self.docker_exposed: bool = False
        self.k8s_exposed: bool = False
        self.container_vulns: List[Dict] = []
        self.stats = Counter()
    
    async def test_docker_socket(self, session) -> Dict:
        """Test if Docker socket is exposed."""
        result = {"exposed": False, "endpoints": [], "evidence": ""}
        
        docker_urls = [
            "http://localhost:2375",
            "http://127.0.0.1:2375",
            "http://localhost:2376",
            "http://unix:/var/run/docker.sock:",
        ]
        
        for base_url in docker_urls:
            for endpoint in self.DOCKER_ENDPOINTS[:5]:
                url = f"{base_url}{endpoint}" if base_url.endswith(':') else f"{base_url}{endpoint}"
                
                try:
                    headers = {}
                    if self._zombie:
                        headers = self._zombie.get_headers(url)
                    
                    resp = await session.fetch(url, headers=headers, timeout=5)
                    
                    if resp.get('status') == 200:
                        text = (resp.get('text', '') or '').lower()
                        
                        if any(k in text for k in ['docker', 'containers', 'version', 'apiversion']):
                            result["exposed"] = True
                            result["endpoints"].append(url)
                            result["evidence"] = text[:200]
                            self.docker_exposed = True
                            self.stats["docker_exposed"] += 1
                except Exception:
                    continue
        
        return result
    
    async def test_k8s_api(self, session) -> Dict:
        """Test if Kubernetes API is exposed."""
        result = {"exposed": False, "endpoints": [], "evidence": ""}
        
        k8s_urls = [
            "https://kubernetes.default.svc",
            "https://localhost:6443",
            "https://127.0.0.1:6443",
            "https://10.0.0.1:6443",
        ]
        
        for base_url in k8s_urls:
            for endpoint in self.K8S_ENDPOINTS[:5]:
                url = f"{base_url}{endpoint}"
                
                try:
                    headers = {}
                    if self._zombie:
                        headers = self._zombie.get_headers(url)
                    
                    resp = await session.fetch(url, headers=headers, timeout=5, verify_ssl=False)
                    
                    if resp.get('status') in [200, 401, 403]:
                        text = (resp.get('text', '') or '').lower()
                        
                        if any(k in text for k in ['kubernetes', 'kube', 'apiVersion', 'metadata']):
                            result["exposed"] = True
                            result["endpoints"].append(url)
                            result["evidence"] = text[:200]
                            self.k8s_exposed = True
                            self.stats["k8s_exposed"] += 1
                except Exception:
                    continue
        
        return result
    
    async def test_container_escape(self, session) -> Dict:
        """Test for container escape possibilities."""
        result = {"vulnerable": False, "vectors": []}
        
        escape_vectors = [
            {
                "name": "privileged_container",
                "check": lambda: self._check_privileged(session),
                "severity": "CRITICAL",
            },
            {
                "name": "docker_socket_mount",
                "check": lambda: self._check_socket_mount(session),
                "severity": "CRITICAL",
            },
            {
                "name": "cgroup_escape",
                "check": lambda: self._check_cgroup_escape(session),
                "severity": "HIGH",
            },
            {
                "name": "capabilities_escape",
                "check": lambda: self._check_capabilities(session),
                "severity": "HIGH",
            },
        ]
        
        for vector in escape_vectors:
            try:
                vuln = await vector["check"]()
                if vuln:
                    result["vulnerable"] = True
                    result["vectors"].append({
                        "name": vector["name"],
                        "severity": vector["severity"],
                        "evidence": vuln,
                    })
            except Exception:
                continue
        
        return result
    
    async def _check_privileged(self, session) -> Optional[str]:
        """Check if running in privileged container."""
        try:
            # Check /proc/1/cgroup for container indicators
            resp = await session.fetch("file:///proc/1/cgroup", timeout=5)
            text = (resp.get('text', '') or '')
            
            if 'docker' in text or 'kubepods' in text:
                # Check for privileged flags
                resp2 = await session.fetch("file:///proc/1/status", timeout=5)
                status_text = (resp2.get('text', '') or '')
                
                if 'CapEff:' in status_text:
                    cap_eff = status_text.split('CapEff:')[1].split('\n')[0].strip()
                    if cap_eff == '0000003fffffffff':
                        return f"Privileged container detected — CapEff: {cap_eff}"
        except Exception:
            pass
        
        return None
    
    async def _check_socket_mount(self, session) -> Optional[str]:
        """Check if Docker socket is mounted."""
        try:
            resp = await session.fetch("file:///proc/1/mountinfo", timeout=5)
            text = (resp.get('text', '') or '')
            
            if 'docker.sock' in text:
                return "Docker socket mounted in container"
        except Exception:
            pass
        
        return None
    
    async def _check_cgroup_escape(self, session) -> Optional[str]:
        """Check for cgroup escape possibility."""
        try:
            resp = await session.fetch("file:///proc/1/cgroup", timeout=5)
            text = (resp.get('text', '') or '')
            
            if 'docker' in text:
                return "Running in Docker container — cgroup escape possible"
        except Exception:
            pass
        
        return None
    
    async def _check_capabilities(self, session) -> Optional[str]:
        """Check for dangerous capabilities."""
        try:
            resp = await session.fetch("file:///proc/1/status", timeout=5)
            text = (resp.get('text', '') or '')
            
            dangerous_caps = ['cap_sys_admin', 'cap_sys_ptrace', 'cap_sys_module', 'cap_net_admin']
            
            if 'CapEff:' in text:
                cap_eff = text.split('CapEff:')[1].split('\n')[0].strip()
                # Check if any dangerous capability is set
                cap_int = int(cap_eff, 16)
                
                # SYS_ADMIN = bit 21, SYS_PTRACE = bit 19, etc.
                if cap_int & (1 << 21):  # SYS_ADMIN
                    return "CAP_SYS_ADMIN enabled — full system administration"
                if cap_int & (1 << 19):  # SYS_PTRACE
                    return "CAP_SYS_PTRACE enabled — can trace processes"
        except Exception:
            pass
        
        return None
    
    async def full_scan(self, session) -> Dict:
        """Execute full container security scan."""
        print(f"\n{C.CYAN}{'═'*60}{C.RST}")
        print(f"{C.CYAN}  🐳 DOCKER SCANNER v50 — {self.target_url}{C.RST}")
        print(f"{C.CYAN}{'═'*60}{C.RST}")
        
        # Test Docker socket
        docker_result = await self.test_docker_socket(session)
        if docker_result["exposed"]:
            self.container_vulns.append({
                "type": "docker_socket_exposed",
                "severity": "CRITICAL",
                "evidence": docker_result["evidence"],
                "endpoints": docker_result["endpoints"],
            })
            print(f"  {C.RED}  {I.SKULL} Docker socket EXPOSED!{C.RST}")
        
        # Test K8s API
        k8s_result = await self.test_k8s_api(session)
        if k8s_result["exposed"]:
            self.container_vulns.append({
                "type": "kubernetes_api_exposed",
                "severity": "CRITICAL",
                "evidence": k8s_result["evidence"],
                "endpoints": k8s_result["endpoints"],
            })
            print(f"  {C.RED}  {I.SKULL} Kubernetes API EXPOSED!{C.RST}")
        
        # Test container escape
        escape_result = await self.test_container_escape(session)
        if escape_result["vulnerable"]:
            self.container_vulns.extend([
                {
                    "type": f"container_escape_{v['name']}",
                    "severity": v["severity"],
                    "evidence": v["evidence"],
                }
                for v in escape_result["vectors"]
            ])
            print(f"  {C.RED}  {I.WARN} Container escape possible! ({len(escape_result['vectors'])} vectors){C.RST}")
        
        print(f"  {C.GREEN}├─ Total vulns: {len(self.container_vulns)}{C.RST}")
        
        return self._build_report()
    
    def _build_report(self) -> Dict:
        """Build container scan report."""
        return {
            "target": self.target_url,
            "docker_exposed": self.docker_exposed,
            "k8s_exposed": self.k8s_exposed,
            "vulnerabilities": self.container_vulns,
            "stats": dict(self.stats),
        }


