# PERFORMANCE BENCHMARK v50
# ═══════════════════════════════════════════════════════════════

class PerformanceBenchmark:
    """
    ⚡ PERFORMANCE BENCHMARK v50 — Measure and optimize performance.
    
    Features:
    - Request throughput measurement
    - Memory usage tracking
    - CPU utilization tracking
    - Response time percentiles
    - Concurrency scaling test
    - Payload generation speed
    - Database query performance
    - Cache effectiveness measurement
    
    Connected to: All modules (benchmarking)
    """
    
    def __init__(self):
        self.benchmark_results: List[Dict] = []
        self._memory_manager = MemoryManager()
    
    async def benchmark_requests(
        self, session, url: str, count: int = 100, concurrency: int = 10
    ) -> Dict:
        """Benchmark HTTP request throughput."""
        results = []
        errors = 0
        
        sem = asyncio.Semaphore(concurrency)
        
        async def make_request() -> float:
            async with sem:
                start = time.time()
                try:
                    await session.fetch(url, timeout=10)
                    return time.time() - start
                except Exception:
                    return 0
        
        start = time.time()
        tasks = [make_request() for _ in range(count)]
        times = await asyncio.gather(*tasks)
        total_time = time.time() - start
        
        valid_times = [t for t in times if t > 0]
        
        result = {
            "total_requests": count,
            "concurrency": concurrency,
            "total_time": round(total_time, 2),
            "requests_per_second": round(count / max(total_time, 0.001), 1),
            "avg_response_time_ms": round(sum(valid_times) / max(len(valid_times), 1) * 1000, 1),
            "min_response_time_ms": round(min(valid_times) * 1000, 1) if valid_times else 0,
            "max_response_time_ms": round(max(valid_times) * 1000, 1) if valid_times else 0,
            "errors": count - len(valid_times),
        }
        
        self.benchmark_results.append(result)
        return result
    
    async def benchmark_payload_generation(self, count: int = 1000) -> Dict:
        """Benchmark payload generation speed."""
        start = time.time()
        
        payloads = []
        for _ in range(count):
            payloads.append(random.choice(Payloads.SQLI))
        
        elapsed = time.time() - start
        
        result = {
            "payloads_generated": count,
            "total_time": round(elapsed, 3),
            "payloads_per_second": round(count / max(elapsed, 0.001), 1),
        }
        
        self.benchmark_results.append(result)
        return result
    
    async def benchmark_memory(self) -> Dict:
        """Benchmark memory usage."""
        mem = self._memory_manager.get_memory_usage()
        
        result = {
            "rss_mb": mem["rss_mb"],
            "vms_mb": mem["vms_mb"],
            "percent": mem["percent"],
        }
        
        self.benchmark_results.append(result)
        return result
    
    def generate_report(self) -> str:
        """Generate benchmark report."""
        report = f"""
{C.BOLD}{'═'*60}{C.RST}
{C.BOLD}  ⚡ PERFORMANCE BENCHMARK REPORT{C.RST}
{C.BOLD}{'═'*60}{C.RST}
"""
        
        for i, result in enumerate(self.benchmark_results):
            report += f"\n  Benchmark #{i+1}:\n"
            for key, value in result.items():
                report += f"    {key}: {value}\n"
        
        return report


