# MODULE HEALTH CHECKER v50
# ═══════════════════════════════════════════════════════════════

class ModuleHealthChecker:
    """
    💓 MODULE HEALTH CHECKER v50 — Module Health Monitoring.
    
    Features:
    - Module health status
    - Dependency health
    - Resource availability check
    - Network connectivity test
    - Database health check
    - Memory pressure check
    - Module restart capability
    - Health dashboard
    
    Connected to: ALL modules
    """
    
    def __init__(self, integration_layer: GlobalIntegrationLayer = None):
        self._integration = integration_layer
        self._health_checks: Dict[str, Callable] = {}
        self._health_history: List[Dict] = []
    
    def register_check(self, name: str, check_func: Callable) -> None:
        """Register a health check."""
        self._health_checks[name] = check_func
    
    async def check_module(self, module_name: str, module_instance: Any) -> Dict:
        """Check health of a specific module."""
        result = {
            "module": module_name,
            "status": "unknown",
            "checks": {},
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
        
        # Check if module exists
        if module_instance is None:
            result["status"] = "not_initialized"
            return result
        
        # Run registered checks
        all_healthy = True
        
        for check_name, check_func in self._health_checks.items():
            try:
                check_result = await check_func(module_instance) if asyncio.iscoroutinefunction(check_func) else check_func(module_instance)
                result["checks"][check_name] = check_result
                
                if not check_result.get("healthy", True):
                    all_healthy = False
            except Exception as e:
                result["checks"][check_name] = {"healthy": False, "error": str(e)}
                all_healthy = False
        
        result["status"] = "healthy" if all_healthy else "degraded"
        self._health_history.append(result)
        
        return result
    
    async def check_all(self, modules: Dict[str, Any]) -> Dict:
        """Check health of all modules."""
        results = {}
        healthy_count = 0
        degraded_count = 0
        
        for name, instance in modules.items():
            result = await self.check_module(name, instance)
            results[name] = result
            
            if result["status"] == "healthy":
                healthy_count += 1
            else:
                degraded_count += 1
        
        return {
            "total": len(modules),
            "healthy": healthy_count,
            "degraded": degraded_count,
            "modules": results,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }
    
    def get_health_history(self) -> List[Dict]:
        """Get health check history."""
        return self._health_history[-20:]


