def setup_environment() -> Dict:
    """Setup global environment for Zombie v50."""
    result = {
        "python_version": sys.version,
        "platform": platform.platform(),
        "cpu_count": _os_module.cpu_count(),
        "event_loop": "uvloop" if UVLOOP_AVAILABLE and uvloop else "asyncio",
        "json_library": "orjson" if ORJSON_AVAILABLE else "json",
        "dns_library": "dnspython" if DNS_AVAILABLE else "socket",
        "html_parser": "lxml" if LXML_AVAILABLE else ("bs4" if BS4_AVAILABLE else "re"),
        "rich_available": RICH_AVAILABLE,
        "crypto_available": CRYPTO_AVAILABLE,
        "psutil_available": PSUTIL_AVAILABLE,
        "aiohttp_available": AIOHTTP_AVAILABLE,
        "tldextract_available": TLDEXTRACT_AVAILABLE,
    }
    
    # Set up event loop policy for Windows
    if platform.system() == "Windows":
        asyncio.set_event_loop_policy(asyncio.WindowsSelectorEventLoopPolicy())
    
    return result


def create_default_instances(config: ZombieConfig = None) -> Dict[str, Any]:
    """Create default instances of core modules."""
    if config is None:
        config = ZombieConfig()
    
    zombie = Zombie(
        fingerprint=config.fingerprint,
        pool_size=config.pool_size,
        region=config.region,
        base_delay=config.base_delay,
    )
    
    db = ZombieDatabase(config.db_path)
    
    circuit_breaker = CircuitBreaker(
        name="main",
        failure_threshold=config.failure_threshold,
        recovery_timeout=config.recovery_timeout,
    )
    
    rate_limiter = TokenBucket(
        rate=config.rate_limit,
        burst=config.burst_size,
        name="main",
    )
    
    metrics = MetricsCollector()
    
    return {
        "zombie": zombie,
        "database": db,
        "circuit_breaker": circuit_breaker,
        "rate_limiter": rate_limiter,
        "metrics": metrics,
    }


