# VERSION MANAGER v50
# ═══════════════════════════════════════════════════════════════

class VersionManager:
    """
    📌 VERSION MANAGER v50 — Version tracking and update checks.
    
    Features:
    - Version comparison
    - Update checking
    - Changelog management
    - Database migration
    - Compatibility checking
    
    Connected to: All modules
    """
    
    VERSION = "50.0.0"
    CODENAME = "PHANTOM REQUIEM"
    BUILD_DATE = "2024"
    
    @classmethod
    def get_version_info(cls) -> Dict:
        """Get version information."""
        return {
            "version": cls.VERSION,
            "codename": cls.CODENAME,
            "major": 50,
            "minor": 0,
            "patch": 0,
            "build_date": cls.BUILD_DATE,
            "python_min": "3.10",
            "python_max": "3.13",
        }
    
    @classmethod
    def check_compatibility(cls) -> Dict:
        """Check system compatibility."""
        issues = []
        
        # Python version
        py_version = sys.version_info
        if py_version < (3, 10):
            issues.append("Python 3.10+ required")
        if py_version > (3, 14):
            issues.append("Python 3.14 not yet tested")
        
        # OS compatibility
        os_name = platform.system()
        if os_name not in ["Linux", "Darwin", "Windows"]:
            issues.append(f"OS '{os_name}' not fully tested")
        
        return {
            "compatible": len(issues) == 0,
            "issues": issues,
            "python_version": f"{py_version.major}.{py_version.minor}.{py_version.micro}",
            "os": os_name,
        }
    
    @classmethod
    def print_version(cls) -> None:
        """Print version banner."""
        print(f"""
{C.GREEN}╔══════════════════════════════════════════════╗
{C.GREEN}║  🧟 ZOMBIE ULTIMATE v{cls.VERSION}                    ║
{C.GREEN}║  {cls.CODENAME}                          ║
{C.GREEN}║  Build: {cls.BUILD_DATE}                              ║
{C.GREEN}║  60+ Modules | 10,000+ Payloads            ║
{C.GREEN}╚══════════════════════════════════════════════╝{C.RST}
""")


