# ASYNC OPTIMIZER v50 — Event Loop & Coroutine Optimization
# ═══════════════════════════════════════════════════════════════

class AsyncOptimizer:
    """
    ⚡ ASYNC OPTIMIZER v50 — Event Loop & Coroutine Optimization.
    
    Features:
    - Event loop policy optimization
    - Coroutine scheduling optimization
    - Task group management
    - Memory-efficient task creation
    - Timeout management
    - Cancellation handling
    - Resource cleanup
    
    Connected to: All async modules
    """
    
    def __init__(self):
        self._task_groups: List[asyncio.TaskGroup] = []
        self._active_tasks: Set[asyncio.Task] = set()
        self._optimization_stats = Counter()
    
    async def gather_with_timeout(
        self, coros: List[Coroutine], timeout: float = 30.0,
        return_exceptions: bool = True,
    ) -> List[Any]:
        """
        Gather coroutines with overall timeout.
        
        Args:
            coros: List of coroutines
            timeout: Overall timeout in seconds
            return_exceptions: Return exceptions instead of raising
            
        Returns:
            List of results
        """
        try:
            return await asyncio.wait_for(
                asyncio.gather(*coros, return_exceptions=return_exceptions),
                timeout=timeout,
            )
        except asyncio.TimeoutError:
            self._optimization_stats["timeouts"] += 1
            if return_exceptions:
                return [asyncio.TimeoutError(f"Task timed out after {timeout}s")] * len(coros)
            raise
    
    async def run_with_semaphore(
        self, coro: Callable, *args,
        semaphore: asyncio.Semaphore = None,
        **kwargs,
    ) -> Any:
        """
        Run coroutine with semaphore control.
        
        Args:
            coro: Async callable
            *args: Positional arguments
            semaphore: Optional semaphore
            **kwargs: Keyword arguments
            
        Returns:
            Coroutine result
        """
        if semaphore:
            async with semaphore:
                return await coro(*args, **kwargs)
        return await coro(*args, **kwargs)
    
    async def batch_execute(
        self, items: List[Any], handler: Callable,
        concurrency: int = 10, timeout_per_item: float = 30.0,
    ) -> List[Dict]:
        """
        Execute handler on items in batches.
        
        Args:
            items: List of items to process
            handler: Async handler function
            concurrency: Max concurrent executions
            timeout_per_item: Timeout per item
            
        Returns:
            List of result dicts
        """
        results = []
        sem = asyncio.Semaphore(concurrency)
        
        async def process_item(item: Any) -> Dict:
            async with sem:
                try:
                    result = await asyncio.wait_for(
                        handler(item),
                        timeout=timeout_per_item,
                    )
                    return {"item": item, "result": result, "error": None}
                except Exception as e:
                    return {"item": item, "result": None, "error": str(e)}
        
        tasks = [process_item(item) for item in items]
        results = await asyncio.gather(*tasks)
        
        return results
    
    def get_stats(self) -> Dict:
        """Get optimizer statistics."""
        return {
            "active_tasks": len(self._active_tasks),
            "timeouts": self._optimization_stats.get("timeouts", 0),
        }


# ═══════════════════════════════════════════════════════════════
# RESOURCE CLEANER v50 — Automatic Resource Cleanup
# ═══════════════════════════════════════════════════════════════

class ResourceCleaner:
    """
    🧹 RESOURCE CLEANER v50 — Automatic Resource Cleanup.
    
    Features:
    - File handle cleanup
    - Socket cleanup
    - Database connection cleanup
    - Cache cleanup
    - Temporary file cleanup
    - Memory cleanup
    - Async resource cleanup
    
    Connected to: All modules
    """
    
    def __init__(self):
        self._cleanup_handlers: List[Callable] = []
        self._temp_files: List[Path] = []
        self._cleanup_stats = Counter()
    
    def register_handler(self, handler: Callable) -> None:
        """Register a cleanup handler."""
        self._cleanup_handlers.append(handler)
    
    def register_temp_file(self, path: Path) -> None:
        """Register a temporary file for cleanup."""
        self._temp_files.append(path)
    
    async def cleanup_all(self) -> Dict:
        """
        Run all cleanup handlers.
        
        Returns:
            Cleanup statistics
        """
        results = {"handlers_run": 0, "files_removed": 0, "errors": 0}
        
        # Run cleanup handlers
        for handler in self._cleanup_handlers:
            try:
                if asyncio.iscoroutinefunction(handler):
                    await handler()
                else:
                    handler()
                results["handlers_run"] += 1
            except Exception as e:
                results["errors"] += 1
                log.warning(f"Cleanup handler error: {e}")
        
        # Remove temp files
        for path in self._temp_files:
            try:
                if path.exists():
                    path.unlink()
                    results["files_removed"] += 1
            except Exception:
                pass
        
        # Force garbage collection
        gc.collect()
        
        # Clear global caches
        response_cache.clear()
        dns_cache.clear()
        url_cache.clear()
        
        self._cleanup_stats["total_cleanups"] += 1
        self._cleanup_stats["last_cleanup_time"] = time.time()
        
        return results
    
    def get_stats(self) -> Dict:
        """Get cleaner statistics."""
        return {
            "handlers_registered": len(self._cleanup_handlers),
            "temp_files_tracked": len(self._temp_files),
            "total_cleanups": self._cleanup_stats.get("total_cleanups", 0),
        }


# ═══════════════════════════════════════════════════════════════
# SIGNAL HANDLER v50 — Graceful Shutdown
# ═══════════════════════════════════════════════════════════════

class SignalHandler:
    """
    🛑 SIGNAL HANDLER v50 — Graceful Shutdown Management.
    
    Features:
    - SIGINT (Ctrl+C) handling
    - SIGTERM handling
    - Graceful shutdown sequence
    - Pending task completion
    - Resource cleanup on exit
    - State persistence on exit
    - Progress save on interrupt
    
    Connected to: All modules
    """
    
    def __init__(self):
        self._shutdown_hooks: List[Callable] = []
        self._shutting_down = False
        self._shutdown_event = asyncio.Event()
        self._original_handlers = {}
    
    def register_shutdown_hook(self, hook: Callable) -> None:
        """Register a shutdown hook."""
        self._shutdown_hooks.append(hook)
    
    @property
    def is_shutting_down(self) -> bool:
        """Check if shutdown is in progress."""
        return self._shutting_down
    
    async def wait_for_shutdown(self) -> None:
        """Wait for shutdown signal."""
        await self._shutdown_event.wait()
    
    def trigger_shutdown(self) -> None:
        """Trigger graceful shutdown."""
        if not self._shutting_down:
            self._shutting_down = True
            self._shutdown_event.set()
    
    def setup_handlers(self) -> None:
        """Setup signal handlers."""
        loop = asyncio.get_event_loop()
        
        def handle_signal(sig, frame):
            print(f"\n{C.YELLOW}{I.WARN} Received signal {sig}. Shutting down gracefully...{C.RST}")
            self.trigger_shutdown()
        
        for sig in [signal.SIGINT, signal.SIGTERM]:
            try:
                self._original_handlers[sig] = signal.getsignal(sig)
                signal.signal(sig, handle_signal)
            except Exception:
                pass
    
    def restore_handlers(self) -> None:
        """Restore original signal handlers."""
        for sig, handler in self._original_handlers.items():
            try:
                signal.signal(sig, handler)
            except Exception:
                pass
    
    async def execute_shutdown(self, db: Any = None, session: Any = None) -> None:
        """
        Execute graceful shutdown sequence.
        
        Args:
            db: Optional database instance
            session: Optional session manager
        """
        print(f"\n{C.CYAN}  {I.HOURGLASS} Executing graceful shutdown...{C.RST}")
        
        # Run shutdown hooks
        for hook in self._shutdown_hooks:
            try:
                if asyncio.iscoroutinefunction(hook):
                    await hook()
                else:
                    hook()
            except Exception as e:
                log.error(f"Shutdown hook error: {e}")
        
        # Close session
        if session:
            try:
                await session.close()
                print(f"  {C.GREEN}{I.CHECK} Session closed{C.RST}")
            except Exception as e:
                print(f"  {C.YELLOW}{I.WARN} Session close error: {e}{C.RST}")
        
        # Vacuum database
        if db:
            try:
                db.vacuum()
                db.close()
                print(f"  {C.GREEN}{I.CHECK} Database closed{C.RST}")
            except Exception as e:
                print(f"  {C.YELLOW}{I.WARN} Database close error: {e}{C.RST}")
        
        # Final cleanup
        memory_cleanup()
        print(f"  {C.GREEN}{I.CHECK} Memory cleaned up{C.RST}")
        print(f"\n{C.GREEN}  {I.CHECK} Shutdown complete. Goodbye!{C.RST}\n")


