# LOGGING ENHANCER v50 — Advanced Logging Features
# ═══════════════════════════════════════════════════════════════

class LoggingEnhancer:
    """
    📝 LOGGING ENHANCER v50 — Advanced Logging Features.
    
    Features:
    - Structured logging (JSON format)
    - Log level dynamic adjustment
    - Per-module log levels
    - Log sampling (reduce noise)
    - Log aggregation
    - Performance logging
    - Audit logging
    
    Connected to: All modules
    """
    
    def __init__(self):
        self._module_log_levels: Dict[str, int] = {}
        self._log_samples: Dict[str, int] = defaultdict(int)
        self._sample_rates: Dict[str, float] = {}
        self._json_formatter = logging.Formatter(
            '{"timestamp":"%(asctime)s","level":"%(levelname)s","module":"%(name)s","message":"%(message)s"}',
            datefmt='%Y-%m-%dT%H:%M:%S',
        )
    
    def set_module_level(self, module: str, level: str) -> None:
        """Set log level for specific module."""
        self._module_log_levels[module] = getattr(logging, level.upper(), logging.INFO)
        logging.getLogger(module).setLevel(self._module_log_levels[module])
    
    def set_sample_rate(self, module: str, rate: float) -> None:
        """Set log sampling rate for module (0.0-1.0)."""
        self._sample_rates[module] = max(0.0, min(1.0, rate))
    
    def should_log(self, module: str, level: int) -> bool:
        """Check if message should be logged based on sampling."""
        if module in self._sample_rates:
            self._log_samples[module] += 1
            if random.random() > self._sample_rates[module]:
                return False
        return True
    
    def enable_json_logging(self) -> None:
        """Enable JSON structured logging."""
        for handler in logging.getLogger('zombie').handlers:
            if isinstance(handler, logging.FileHandler):
                handler.setFormatter(self._json_formatter)
    
    def get_stats(self) -> Dict:
        """Get logging statistics."""
        return {
            "module_levels": {k: logging.getLevelName(v) for k, v in self._module_log_levels.items()},
            "sample_rates": dict(self._sample_rates),
        }


